import { useState, useRef, useEffect } from 'react';
import { M, mc } from '../../theme/buildM';
import { ST } from '../../theme/styles';
import { hexAlpha } from '../../theme/colorUtils';
import { ls } from '../../utils/storage';
import { useApp } from '../../context/AppContext';
import { Card, FilledBtn, TonalBtn, Input, Skel } from '../ui';
function PortfolioHealthScore({ portfolio }) {
  if (!portfolio || portfolio.length < 2) return null;
  const total = portfolio.reduce((s, p) => s + p.invested, 0);
  const topPct = Math.max(...portfolio.map((p) => (p.invested / total) * 100));
  const concScore = topPct > 50 ? 35 : topPct > 35 ? 65 : 100;
  const divScore = Math.min((portfolio.length / 8) * 100, 100);
  const overall = Math.round((concScore + divScore) / 2);
  const grade =
    overall >= 85
      ? "A"
      : overall >= 70
        ? "B"
        : overall >= 55
          ? "C"
          : overall >= 40
            ? "D"
            : "F";
  const gc =
    overall >= 85
      ? M.gain
      : overall >= 70
        ? hexAlpha(M.gain, 0.7)
        : overall >= 55
          ? M.gold
          : M.loss;
  return (
    <Card style={{ padding: 18 }}>
      <div
        style={{
          display: "flex",
          alignItems: "center",
          justifyContent: "space-between",
          marginBottom: 14,
        }}
      >
        <div style={{ fontSize: 13, fontWeight: 800, color: M.txt }}>
          {"🏥 Portfolio Health"}
        </div>
        <div
          style={{
            width: 42,
            height: 42,
            borderRadius: "50%",
            background: hexAlpha(gc, 0.14),
            border: "2px solid " + gc,
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            fontSize: 18,
            fontWeight: 900,
            color: gc,
          }}
        >
          {grade}
        </div>
      </div>
      {[
        [
          "Concentration",
          concScore,
          topPct > 35
            ? "Top holding: " + topPct.toFixed(0) + "%"
            : "Positions well spread",
        ],
        ["Diversification", divScore, portfolio.length + " positions"],
      ].map(([l, s, note]) => (
        <div key={l} style={{ marginBottom: 12 }}>
          <div
            style={{
              display: "flex",
              justifyContent: "space-between",
              marginBottom: 5,
            }}
          >
            <span style={{ fontSize: 12, color: hexAlpha(M.txt, 0.6) }}>
              {l}
            </span>
            <span
              style={{
                fontSize: 12,
                fontWeight: 700,
                color: s >= 70 ? M.gain : s >= 50 ? M.gold : M.loss,
              }}
            >
              {s + "/100"}
            </span>
          </div>
          <div
            style={{
              height: 5,
              borderRadius: M.rFull,
              background: hexAlpha(M.txt, 0.08),
              overflow: "hidden",
            }}
          >
            <div
              style={{
                height: "100%",
                width: s + "%",
                borderRadius: M.rFull,
                transition: "width .4s",
                background:
                  s >= 70
                    ? hexAlpha(M.gain, 0.8)
                    : s >= 50
                      ? hexAlpha(M.gold, 0.8)
                      : hexAlpha(M.loss, 0.8),
              }}
            />
          </div>
          <div
            style={{ fontSize: 10, color: hexAlpha(M.txt, 0.32), marginTop: 3 }}
          >
            {note}
          </div>
        </div>
      ))}
    </Card>
  );
}

// ─── Paper Trading ────────────────────────────────────────────────────────────
export default PortfolioHealthScore;
