import { useState, useRef, useEffect } from 'react';
import { M, mc } from '../../theme/buildM';
import { ST } from '../../theme/styles';
import { hexAlpha } from '../../theme/colorUtils';
import { ls } from '../../utils/storage';
import { useApp } from '../../context/AppContext';
import { Card, FilledBtn, TonalBtn, Input, Skel } from '../ui';
function LearnVisual({ v }) {
  if (!v) return null;
  if (v.type === "bar") {
    const vals = v.bars.map((b) => Math.abs(b.v)),
      max = Math.max(...vals);
    const isNeg = v.negative;
    return (
      <div
        style={{
          background: hexAlpha(M.txt, 0.04),
          backdropFilter: "blur(36px) saturate(160%)",
          WebkitBackdropFilter: "blur(36px) saturate(160%)",
          boxShadow: "inset 0 1px 0 " + hexAlpha(M.txt, 0.08),
          border: "1px solid " + hexAlpha(M.txt, 0.07),
          borderRadius: M.r16,
          padding: "14px 16px",
        }}
      >
        <div
          style={{
            fontSize: 10,
            color: hexAlpha(M.txt, 0.35),
            fontWeight: 700,
            textTransform: "uppercase",
            letterSpacing: 1,
            marginBottom: 12,
          }}
        >
          {v.label}
        </div>
        <div
          style={{
            display: "flex",
            gap: 8,
            alignItems: "flex-end",
            height: 72,
          }}
        >
          {v.bars.map((b, i) => (
            <div
              key={i}
              style={{
                flex: 1,
                display: "flex",
                flexDirection: "column",
                alignItems: "center",
                gap: 4,
              }}
            >
              <div
                style={{
                  fontSize: 9,
                  color: isNeg ? (b.v < 0 ? M.loss : M.gain) : mc(v.colorKey),
                  fontWeight: 700,
                  fontFamily: "monospace",
                }}
              >
                {isNeg && b.v > 0 ? "+" : ""}
                {b.v}
                {isNeg ? "%" : ""}
              </div>
              <div
                style={{
                  backdropFilter: "blur(36px) saturate(160%)",
                  WebkitBackdropFilter: "blur(36px) saturate(160%)",
                  boxShadow: "inset 0 1px 0 " + hexAlpha(M.txt, 0.1),
                  width: "100%",
                  background: isNeg
                    ? b.v < 0
                      ? M.loss
                      : M.gain
                    : mc(v.colorKey),
                  borderRadius: "4px 4px 2px 2px",
                  opacity: 0.8,
                  height: `${(Math.abs(b.v) / max) * 54 + 8}px`,
                  minHeight: 8,
                }}
              />
              <div
                style={{
                  fontSize: 8,
                  color: hexAlpha(M.txt, 0.35),
                  textAlign: "center",
                  lineHeight: 1.2,
                  whiteSpace: "pre",
                }}
              >
                {b.l}
              </div>
            </div>
          ))}
        </div>
      </div>
    );
  }
  if (v.type === "compare") {
    const max = Math.max(...v.items.map((i) => i.v));
    return (
      <div
        style={{
          background: hexAlpha(M.txt, 0.04),
          backdropFilter: "blur(36px) saturate(160%)",
          WebkitBackdropFilter: "blur(36px) saturate(160%)",
          boxShadow: "inset 0 1px 0 " + hexAlpha(M.txt, 0.08),
          border: "1px solid " + hexAlpha(M.txt, 0.07),
          borderRadius: M.r16,
          padding: "14px 16px",
        }}
      >
        <div
          style={{
            fontSize: 10,
            color: hexAlpha(M.txt, 0.35),
            fontWeight: 700,
            textTransform: "uppercase",
            letterSpacing: 1,
            marginBottom: 10,
          }}
        >
          {v.label}
        </div>
        {v.items.map((item, i) => (
          <div key={i} style={{ marginBottom: 8 }}>
            <div
              style={{
                display: "flex",
                justifyContent: "space-between",
                marginBottom: 4,
              }}
            >
              <span
                style={{
                  fontSize: 11,
                  color: hexAlpha(M.txt, 0.65),
                  whiteSpace: "pre",
                }}
              >
                {item.l}
              </span>
              <span
                style={{
                  fontSize: 11,
                  color: mc(v.colorKey),
                  fontFamily: "monospace",
                  fontWeight: 700,
                }}
              >
                {item.v}
              </span>
            </div>
            <div
              style={{
                backdropFilter: "blur(36px) saturate(160%)",
                WebkitBackdropFilter: "blur(36px) saturate(160%)",
                boxShadow: "inset 0 1px 0 " + hexAlpha(M.txt, 0.1),
                height: 5,
                background: hexAlpha(M.txt, 0.06),
                borderRadius: M.rFull,
              }}
            >
              <div
                style={{
                  backdropFilter: "blur(36px) saturate(160%)",
                  WebkitBackdropFilter: "blur(36px) saturate(160%)",
                  boxShadow: "inset 0 1px 0 " + hexAlpha(M.txt, 0.1),
                  height: "100%",
                  width: `${(item.v / max) * 100}%`,
                  background: mc(v.colorKey),
                  borderRadius: M.rFull,
                  opacity: 0.75,
                }}
              />
            </div>
          </div>
        ))}
      </div>
    );
  }
  if (v.type === "pie") {
    let angle = -Math.PI / 2;
    const total = v.slices.reduce((s, sl) => s + sl.v, 0);
    const paths = v.slices.map((sl) => {
      const frac = sl.v / total,
        a = frac * Math.PI * 2;
      const x1 = 50 + 42 * Math.cos(angle),
        y1 = 50 + 42 * Math.sin(angle);
      angle += a;
      const x2 = 50 + 42 * Math.cos(angle),
        y2 = 50 + 42 * Math.sin(angle);
      return {
        ...sl,
        d: `M50 50 L${x1} ${y1} A42 42 0 ${a > Math.PI ? 1 : 0} 1 ${x2} ${y2}Z`,
      };
    });
    return (
      <div
        style={{
          background: hexAlpha(M.txt, 0.04),
          backdropFilter: "blur(36px) saturate(160%)",
          WebkitBackdropFilter: "blur(36px) saturate(160%)",
          boxShadow: "inset 0 1px 0 " + hexAlpha(M.txt, 0.08),
          border: "1px solid " + hexAlpha(M.txt, 0.07),
          borderRadius: M.r16,
          padding: "14px 16px",
          display: "flex",
          gap: 14,
          alignItems: "center",
        }}
      >
        <svg
          width="90"
          height="90"
          viewBox="0 0 100 100"
          style={{ flexShrink: 0 }}
        >
          {paths.map((p, i) => (
            <path key={i} d={p.d} fill={p.c} opacity="0.85" />
          ))}
          <circle cx="50" cy="50" r="22" fill={hexAlpha(M.bg, 0.9)} />
        </svg>
        <div style={{ flex: 1 }}>
          <div
            style={{
              fontSize: 10,
              color: hexAlpha(M.txt, 0.35),
              fontWeight: 700,
              textTransform: "uppercase",
              letterSpacing: 1,
              marginBottom: 8,
            }}
          >
            {v.label}
          </div>
          {v.slices.map((sl, i) => (
            <div
              key={i}
              style={{
                display: "flex",
                alignItems: "center",
                gap: 6,
                marginBottom: 3,
                fontSize: 11,
              }}
            >
              <div
                style={{
                  backdropFilter: "blur(36px) saturate(160%)",
                  WebkitBackdropFilter: "blur(36px) saturate(160%)",
                  boxShadow: "inset 0 1px 0 " + hexAlpha(M.txt, 0.1),
                  width: 7,
                  height: 7,
                  borderRadius: "50%",
                  background: sl.c,
                  flexShrink: 0,
                }}
              />
              <span style={{ color: hexAlpha(M.txt, 0.65), flex: 1 }}>
                {sl.l}
              </span>
              <span
                style={{
                  color: sl.c,
                  fontFamily: "monospace",
                  fontWeight: 700,
                }}
              >
                {sl.v}%
              </span>
            </div>
          ))}
        </div>
      </div>
    );
  }
  if (v.type === "gauge") {
    const pct = (v.value || 50) / 100,
      r = 38,
      cx = 56,
      cy = 52;
    const x2 = cx + r * Math.cos(Math.PI + pct * Math.PI),
      y2 = cy + r * Math.sin(Math.PI + pct * Math.PI);
    const large = pct > 0.5 ? 1 : 0;
    return (
      <div
        style={{
          background: hexAlpha(M.txt, 0.04),
          backdropFilter: "blur(36px) saturate(160%)",
          WebkitBackdropFilter: "blur(36px) saturate(160%)",
          boxShadow: "inset 0 1px 0 " + hexAlpha(M.txt, 0.08),
          border: "1px solid " + hexAlpha(M.txt, 0.07),
          borderRadius: M.r16,
          padding: "14px 16px",
          textAlign: "center",
        }}
      >
        <div
          style={{
            fontSize: 10,
            color: hexAlpha(M.txt, 0.35),
            fontWeight: 700,
            textTransform: "uppercase",
            letterSpacing: 1,
            marginBottom: 6,
          }}
        >
          {v.label}
        </div>
        <svg
          width="112"
          height="68"
          viewBox="0 0 112 68"
          style={{ display: "block", margin: "0 auto" }}
        >
          <path
            d={`M${cx - r} ${cy} A${r} ${r} 0 0 1 ${cx + r} ${cy}`}
            fill="none"
            stroke={hexAlpha(M.txt, 0.08)}
            strokeWidth="8"
            strokeLinecap="round"
          />
          <path
            d={`M${cx - r} ${cy} A${r} ${r} 0 ${large} 1 ${x2} ${y2}`}
            fill="none"
            stroke={mc(v.colorKey) || M.gold}
            strokeWidth="8"
            strokeLinecap="round"
          />
          <text
            x={cx}
            y={cy - 5}
            textAnchor="middle"
            fill={M.txt}
            fontSize="17"
            fontWeight="900"
            fontFamily="monospace"
          >
            {v.value}
          </text>
          <text
            x={cx}
            y={cy + 8}
            textAnchor="middle"
            fill={hexAlpha(M.txt, 0.3)}
            fontSize="7"
          >
            /100
          </text>
          <text
            x={cx - r}
            y={cy + 16}
            textAnchor="middle"
            fill={hexAlpha(M.txt, 0.3)}
            fontSize="6"
          >
            {v.lo}
          </text>
          <text
            x={cx + r}
            y={cy + 16}
            textAnchor="middle"
            fill={hexAlpha(M.txt, 0.3)}
            fontSize="6"
          >
            {v.hi}
          </text>
        </svg>
      </div>
    );
  }
  if (v.type === "scatter") {
    const xs = v.points.map((p) => p.x),
      ys = v.points.map((p) => p.y);
    const minX = Math.min(...xs) - 5,
      maxX = Math.max(...xs) + 10;
    const minY = Math.min(...ys) - 5,
      maxY = Math.max(...ys) + 10;
    const px = (x) => 6 + ((x - minX) / (maxX - minX)) * 88;
    const py = (y) => 74 - ((y - minY) / (maxY - minY)) * 64;
    return (
      <div
        style={{
          background: hexAlpha(M.txt, 0.04),
          backdropFilter: "blur(36px) saturate(160%)",
          WebkitBackdropFilter: "blur(36px) saturate(160%)",
          boxShadow: "inset 0 1px 0 " + hexAlpha(M.txt, 0.08),
          border: "1px solid " + hexAlpha(M.txt, 0.07),
          borderRadius: M.r16,
          padding: "14px 16px",
        }}
      >
        <div
          style={{
            fontSize: 10,
            color: hexAlpha(M.txt, 0.35),
            fontWeight: 700,
            textTransform: "uppercase",
            letterSpacing: 1,
            marginBottom: 4,
          }}
        >
          {v.label}
        </div>
        <svg width="100%" height="90" viewBox="0 0 100 80">
          {v.points.map((p, i) => (
            <g key={i}>
              <circle
                cx={px(p.x)}
                cy={py(p.y)}
                r="2.8"
                fill={mc(v.colorKey) || M.pri}
                opacity="0.85"
              />
              <text
                x={px(p.x)}
                y={py(p.y) - 4}
                textAnchor="middle"
                fill={hexAlpha(M.txt, 0.5)}
                fontSize="3.5"
              >
                {p.l}
              </text>
            </g>
          ))}
          <text
            x="50"
            y="79"
            textAnchor="middle"
            fill={hexAlpha(M.txt, 0.22)}
            fontSize="4"
          >
            ← Risk →
          </text>
        </svg>
      </div>
    );
  }
  if (v.type === "steps") {
    return (
      <div
        style={{
          background: hexAlpha(M.txt, 0.04),
          backdropFilter: "blur(36px) saturate(160%)",
          WebkitBackdropFilter: "blur(36px) saturate(160%)",
          boxShadow: "inset 0 1px 0 " + hexAlpha(M.txt, 0.08),
          border: "1px solid " + hexAlpha(M.txt, 0.07),
          borderRadius: M.r16,
          padding: "14px 16px",
        }}
      >
        <div
          style={{
            fontSize: 10,
            color: hexAlpha(M.txt, 0.35),
            fontWeight: 700,
            textTransform: "uppercase",
            letterSpacing: 1,
            marginBottom: 12,
          }}
        >
          {v.label}
        </div>
        {v.steps.map((step, i) => (
          <div
            key={i}
            style={{ display: "flex", gap: 10, alignItems: "flex-start" }}
          >
            <div
              style={{
                display: "flex",
                flexDirection: "column",
                alignItems: "center",
                flexShrink: 0,
              }}
            >
              <div
                style={{
                  width: 22,
                  height: 22,
                  borderRadius: "50%",
                  background: hexAlpha(M.pri, 0.15),
                  backdropFilter: "blur(36px) saturate(160%)",
                  WebkitBackdropFilter: "blur(36px) saturate(160%)",
                  boxShadow: "inset 0 1px 0 " + hexAlpha(M.txt, 0.08),
                  border: "1.5px solid " + M.pri,
                  display: "flex",
                  alignItems: "center",
                  justifyContent: "center",
                  fontSize: 10,
                  fontWeight: 800,
                  color: M.pri,
                }}
              >
                {i + 1}
              </div>
              {i < v.steps.length - 1 && (
                <div
                  style={{
                    backdropFilter: "blur(36px) saturate(160%)",
                    WebkitBackdropFilter: "blur(36px) saturate(160%)",
                    boxShadow: "inset 0 1px 0 " + hexAlpha(M.txt, 0.1),
                    width: 2,
                    height: 12,
                    background: hexAlpha(M.txt, 0.08),
                    borderRadius: 2,
                  }}
                />
              )}
            </div>
            <div
              style={{
                fontSize: 12,
                color: hexAlpha(M.txt, 0.68),
                paddingTop: 3,
                paddingBottom: i < v.steps.length - 1 ? 12 : 0,
                lineHeight: 1.45,
              }}
            >
              {step}
            </div>
          </div>
        ))}
      </div>
    );
  }
  if (v.type === "payoff") {
    return (
      <div
        style={{
          background: hexAlpha(M.txt, 0.04),
          backdropFilter: "blur(36px) saturate(160%)",
          WebkitBackdropFilter: "blur(36px) saturate(160%)",
          boxShadow: "inset 0 1px 0 " + hexAlpha(M.txt, 0.08),
          border: "1px solid " + hexAlpha(M.txt, 0.07),
          borderRadius: M.r16,
          padding: "14px 16px",
        }}
      >
        <div
          style={{
            fontSize: 10,
            color: hexAlpha(M.txt, 0.35),
            fontWeight: 700,
            textTransform: "uppercase",
            letterSpacing: 1,
            marginBottom: 6,
          }}
        >
          {v.label}
        </div>
        <svg width="100%" height="72" viewBox="0 0 200 72">
          <line
            x1="0"
            y1="52"
            x2="200"
            y2="52"
            stroke={hexAlpha(M.txt, 0.1)}
            strokeWidth="1"
          />
          <line
            x1="90"
            y1="4"
            x2="90"
            y2="68"
            stroke={hexAlpha(M.txt, 0.1)}
            strokeWidth="1"
            strokeDasharray="3,3"
          />
          <polyline
            points="0,52 90,52 200,4"
            fill="none"
            stroke={mc(v.colorKey) || M.gain}
            strokeWidth="2.5"
            strokeLinecap="round"
            strokeLinejoin="round"
          />
          <circle cx="90" cy="52" r="3" fill={mc(v.colorKey) || M.gain} />
          <text
            x="86"
            y="66"
            textAnchor="middle"
            fill={hexAlpha(M.txt, 0.35)}
            fontSize="8"
          >
            Strike
          </text>
          <text x="8" y="48" fill={hexAlpha(M.txt, 0.3)} fontSize="7">
            Loss = premium
          </text>
          <text x="142" y="18" fill={mc(v.colorKey) || M.gain} fontSize="7">
            Profit ↑ unlimited
          </text>
        </svg>
      </div>
    );
  }
  if (v.type === "candle") {
    return (
      <div
        style={{
          background: hexAlpha(M.txt, 0.04),
          backdropFilter: "blur(36px) saturate(160%)",
          WebkitBackdropFilter: "blur(36px) saturate(160%)",
          boxShadow: "inset 0 1px 0 " + hexAlpha(M.txt, 0.08),
          border: "1px solid " + hexAlpha(M.txt, 0.07),
          borderRadius: M.r16,
          padding: "14px 16px",
        }}
      >
        <div
          style={{
            fontSize: 10,
            color: hexAlpha(M.txt, 0.35),
            fontWeight: 700,
            textTransform: "uppercase",
            letterSpacing: 1,
            marginBottom: 6,
          }}
        >
          {v.label}
        </div>
        <svg width="100%" height="68" viewBox="0 0 200 68">
          {[
            [25, 20, 52, 14, 56],
            [50, 28, 46, 20, 42],
            [75, 20, 48, 14, 50],
            [100, 25, 38, 12, 40],
            [125, 14, 34, 8, 36],
            [150, 10, 30, 4, 32],
            [175, 8, 25, 3, 27],
          ].map(([x, o, c, l, h], i) => (
            <g key={i}>
              <line
                x1={x}
                y1={l}
                x2={x}
                y2={h}
                stroke={o > c ? M.err : M.gain}
                strokeWidth="1.5"
              />
              <rect
                x={x - 5}
                y={Math.min(o, c)}
                width="10"
                height={Math.max(Math.abs(o - c), 1)}
                fill={o > c ? M.err : M.gain}
                rx="1"
              />
            </g>
          ))}
          <text
            x="100"
            y="66"
            textAnchor="middle"
            fill={hexAlpha(M.txt, 0.25)}
            fontSize="5"
          >
            Example price chart — green=up, red=down candles
          </text>
        </svg>
      </div>
    );
  }
  return null;
}

