// ─── Yahoo Finance stock data — no AI needed ─────────────────────
async function fetchYahooStockData(sym) {
  const url = `https://query1.finance.yahoo.com/v8/finance/chart/${encodeURIComponent(sym)}?interval=1d&range=5d`;
  const proxies = [
    `https://corsproxy.io/?${encodeURIComponent(url)}`,
    `https://api.allorigins.win/get?url=${encodeURIComponent(url)}`,
  ];
  for (const proxy of proxies) {
    try {
      const ctrl1 = new AbortController();
      const t1 = setTimeout(() => ctrl1.abort(), 7000);
      const r = await fetch(proxy, { signal: ctrl1.signal });
      clearTimeout(t1);
      if (!r.ok) continue;
      const raw = await r.json();
      const d =
        typeof raw.contents === "string" ? JSON.parse(raw.contents) : raw;
      const res = d?.chart?.result?.[0];
      if (!res) continue;
      const meta = res.meta;
      const prev =
        meta.chartPreviousClose ||
        meta.previousClose ||
        meta.regularMarketPreviousClose;
      const price = meta.regularMarketPrice ?? meta.price ?? 0;
      const changeP = prev && price ? ((price - prev) / prev) * 100 : 0;
      const change = prev && price ? price - prev : 0;
      // 52-week range
      const high52 = meta.fiftyTwoWeekHigh ?? meta.regularMarketDayHigh ?? null;
      const low52 = meta.fiftyTwoWeekLow ?? meta.regularMarketDayLow ?? null;
      // Mini chart points from close prices
      const closes = res.indicators?.quote?.[0]?.close?.filter(Boolean) ?? [];
      const chartPoints =
        closes.length > 1
          ? closes.map((c) => ((c - closes[0]) / closes[0]) * 100)
          : null;
      return {
        symbol: sym.toUpperCase(),
        name: meta.longName || meta.shortName || sym.toUpperCase(),
        price,
        change,
        changeP,
        high52,
        low52,
        marketCap: meta.marketCap ? formatMarketCap(meta.marketCap) : null,
        currency: meta.currency || "USD",
        exchange: meta.exchangeName || null,
        chartPoints,
        source: "yahoo",
      };
    } catch {
      continue;
    }
  }
  return null;
}

function formatMarketCap(n) {
  if (!n) return "N/A";
  if (n >= 1e12) return `$${(n / 1e12).toFixed(2)}T`;
  if (n >= 1e9) return `$${(n / 1e9).toFixed(1)}B`;
  if (n >= 1e6) return `$${(n / 1e6).toFixed(0)}M`;
  return `$${n.toLocaleString()}`;
}
async function fetchLivePrice(sym) {
  const url = `https://query1.finance.yahoo.com/v8/finance/chart/${encodeURIComponent(sym)}?interval=1d&range=1d`;
  const proxies = [
    `https://corsproxy.io/?${encodeURIComponent(url)}`,
    `https://api.allorigins.win/get?url=${encodeURIComponent(url)}`,
  ];
  for (const proxy of proxies) {
    try {
      const ctrl2 = new AbortController();
      const t2 = setTimeout(() => ctrl2.abort(), 6000);
      const r = await fetch(proxy, { signal: ctrl2.signal });
      clearTimeout(t2);
      if (!r.ok) continue;
      const raw = await r.json();
      // allorigins wraps in .contents; corsproxy.io returns direct
      const d =
        typeof raw.contents === "string" ? JSON.parse(raw.contents) : raw;
      const meta = d?.chart?.result?.[0]?.meta;
      if (!meta) continue;
      const prev =
        meta.chartPreviousClose ||
        meta.previousClose ||
        meta.regularMarketPreviousClose;
      const price = meta.regularMarketPrice ?? meta.price;
      if (!price) continue;
      const changeP = prev && price ? ((price - prev) / prev) * 100 : 0;
      return { sym, price, changeP };
    } catch {
      continue;
    }
  }
  return null;
}
export { fetchYahooStockData, formatMarketCap, fetchLivePrice };
