import { useState, useRef } from 'react';
import { M, mc } from '../../theme/buildM';
import { ST } from '../../theme/styles';
import { hexAlpha } from '../../theme/colorUtils';
function ObolLogo({ size = 34 }) {
  const [loaded, setLoaded] = useState(false);
  const [errored, setErrored] = useState(false);
  const idRef = useRef(`obl_${++_logoIdCounter}`);
  const id = idRef.current;
  const r = size / 2;
  const radius = size * 0.29;
  return (
    <div
      style={{
        backdropFilter: "blur(36px) saturate(160%)",
        WebkitBackdropFilter: "blur(36px) saturate(160%)",
        width: size,
        height: size,
        borderRadius: radius,
        overflow: "hidden",
        flexShrink: 0,
        boxShadow: "0 2px 12px " + hexAlpha(M.pri, 0.55),
        position: "relative",
        background: hexAlpha(M.pri, 0.15),
      }}
    >
      {/* SVG always rendered as base layer */}
      <svg
        viewBox={"0 0 " + size + " " + size}
        width={size}
        height={size}
        xmlns="http://www.w3.org/2000/svg"
        style={{ position: "absolute", inset: 0 }}
      >
        <defs>
          <radialGradient id={`${id}a`} cx="40%" cy="35%" r="65%">
            <stop offset="0%" stopColor={M.pri} />
            <stop offset="100%" stopColor={M.priCont} />
          </radialGradient>
        </defs>
        <circle cx={r} cy={r} r={r} fill={`url(#${id}a)`} />
        <circle
          cx={r}
          cy={r}
          r={r - 1}
          fill="none"
          stroke={M.gold}
          strokeWidth="0.9"
          strokeOpacity="0.8"
        />
        <text
          x="50%"
          y="57%"
          textAnchor="middle"
          dominantBaseline="middle"
          fill={M.gold}
          fontSize={size * 0.44}
          fontWeight="900"
          fontFamily="Georgia,serif"
        >
          o
        </text>
      </svg>
      {/* Image layered on top — hides when errored */}
      {!errored && (
        <img
          src="https://raw.githubusercontent.com/obol-mapp/obol-mapp.github.io/main/logo.png"
          alt=""
          onLoad={() => setLoaded(true)}
          onError={() => setErrored(true)}
          style={{
            position: "absolute",
            inset: 0,
            width: "100%",
            height: "100%",
            objectFit: "cover",
            opacity: loaded ? 1 : 0,
            transition: "opacity .3s",
          }}
        />
      )}
    </div>
  );
}

// ─── Shared UI Components ─────────────────────────────────────────
export default ObolLogo;
