import { useState, useRef, useEffect } from 'react';
import { M, mc } from '../theme/buildM';
import { ST } from '../theme/styles';
import { hexAlpha } from '../theme/colorUtils';
import { ls } from '../utils/storage';
import { useApp } from '../context/AppContext';
import { useSettings } from '../context/SettingsContext';
import { Card, FilledBtn, TonalBtn, Input, Skel } from '../components/ui';
import { ErrorCard, NoAIBanner } from '../components/ui';
import ObolLogo from '../components/ui/ObolLogo';
import { callAI, hasAIConfigured } from '../api/ai';
import {
  INVESTOR_LEVELS,XP_PER_TOPIC,XP_PER_QUIZ_PASS,XP_STREAK_BONUS,
  DEFAULT_XP,getLevel,xpToNext,SNAPSHOT_TIPS,
} from '../data/levels';
import { LEARN_CATS,LEARN_TOPICS,GUIDED_BEGINNER,GUIDED_ADVANCED,DEFAULT_LEARN_PROGRESS } from '../data/learn';
import LearnVisual from '../components/learn/LearnVisual';
import { XpToast, LevelBadge } from '../components/learn/XpBadges';
import { DailyChallenge, TopicQuiz, FlashcardScreen } from '../components/learn/LearnActivities';
import { CongratsModal, GuidedProgressCard } from '../components/learn/LearnProgress';
import LearnSheet from '../components/learn/LearnSheet';
import StockScreener from './StockScreener';

function LearnScreen({ advanced, onSetAdvanced, xpData, onXpEarned }) {
  const [sheet, setSheet] = useState(null);
  const [learnSub, setLearnSub] = useState("topics");
  const [quizTopic, setQuizTopic] = useState(null);
  const [progress, setProgress] = useState(() =>
    ls.get("siq_learn_progress", DEFAULT_LEARN_PROGRESS),
  );

  const saveProgress = (next) => {
    setProgress(next);
    ls.set("siq_learn_progress", next);
  };

  const markComplete = (key) => {
    if (!progress.completed.includes(key) && onXpEarned)
      onXpEarned(XP_PER_TOPIC, "Topic Read");
    const next = {
      ...progress,
      completed: [...new Set([...progress.completed, key])],
    };
    // Check if a phase just completed
    const beginnerDone = GUIDED_BEGINNER.every((k) =>
      next.completed.includes(k),
    );
    const advancedDone = GUIDED_ADVANCED.every((k) =>
      next.completed.includes(k),
    );

    if (next.phase === "advanced" && advancedDone && !progress.congrats) {
      next.congrats = "advanced";
    } else if (
      next.phase === "beginner" &&
      beginnerDone &&
      !progress.congrats
    ) {
      next.congrats = "beginner";
    }
    saveProgress(next);
  };

  const handleAdvance = () => {
    const next = {
      ...progress,
      phase: "advanced",
      congrats: null,
      pinned: true,
    };
    saveProgress(next);
    if (onSetAdvanced) onSetAdvanced(true);
  };

  const handleStayBeginner = () => {
    saveProgress({ ...progress, congrats: null, pinned: false });
  };

  const handleAdvancedCongratsRestart = () => {
    saveProgress({ ...DEFAULT_LEARN_PROGRESS, congrats: null });
    if (onSetAdvanced) onSetAdvanced(false);
  };

  const handleAdvancedCongratsDismiss = () => {
    saveProgress({ ...progress, congrats: null, pinned: false });
  };

  const handleRestartAll = () => {
    saveProgress({ ...DEFAULT_LEARN_PROGRESS, congrats: null });
    if (onSetAdvanced) onSetAdvanced(false);
  };

  const handleRestartAdvanced = () => {
    const next = {
      ...progress,
      phase: "advanced",
      pinned: true,
      congrats: null,
      completed: progress.completed.filter((k) => GUIDED_BEGINNER.includes(k)),
    };
    saveProgress(next);
  };

  const handleSkip = () => {
    // Skip current topic by marking it complete without opening sheet
    const path =
      progress.phase === "advanced" ? GUIDED_ADVANCED : GUIDED_BEGINNER;
    const next = path.find((k) => !progress.completed.includes(k));
    if (next) markComplete(next);
  };

  const isGuided = progress.phase !== "done";
  const isPinned = progress.pinned && isGuided;
  const isBottom = !progress.pinned || !isGuided;
  const phaseComplete =
    progress.phase === "beginner"
      ? GUIDED_BEGINNER.every((k) => progress.completed.includes(k))
      : GUIDED_ADVANCED.every((k) => progress.completed.includes(k));
  const allComplete = [...GUIDED_BEGINNER, ...GUIDED_ADVANCED].every((k) =>
    progress.completed.includes(k),
  );

  const orderedCats = advanced
    ? [
        LEARN_CATS.find((c) => c.key === "advanced"),
        ...LEARN_CATS.filter((c) => c.key !== "advanced"),
      ]
    : LEARN_CATS;

  const topicsForCat = (catKey) => LEARN_TOPICS.filter((t) => t.cat === catKey);
  const catColor = (cat) => cat.color || mc(cat.colorKey || "pri");

  const progressCard = (
    <GuidedProgressCard
      progress={progress}
      pinned={isPinned}
      onContinue={(topic) => setSheet(topic)}
      onSkip={handleSkip}
    />
  );

  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 0 }}>
      {/* Congrats modal */}
      {progress.congrats && (
        <CongratsModal
          phase={progress.congrats}
          onAdvance={handleAdvance}
          onStay={handleStayBeginner}
          onRestart={handleAdvancedCongratsRestart}
          onDismiss={handleAdvancedCongratsDismiss}
        />
      )}

      <div style={{ display: "flex", gap: 8, marginBottom: 14 }}>
        {[
          ["topics", "📚 Topics"],
          ["flashcards", "🃏 Flashcards"],
        ].map(([id, lbl]) => (
          <button
            key={id}
            onClick={() => setLearnSub(id)}
            style={ST.subTabBtn(learnSub === id)}
          >
            {lbl}
          </button>
        ))}
      </div>

      {learnSub === "flashcards" ? (
        <FlashcardScreen onXpEarned={onXpEarned || (() => {})} />
      ) : (
        <>
          <DailyChallenge
            xpData={xpData || DEFAULT_XP}
            onXpEarned={onXpEarned || (() => {})}
            onUpdateXp={(patch) => {
              const cur = ls.get("siq_xp", DEFAULT_XP);
              ls.set("siq_xp", { ...cur, ...patch });
            }}
          />

          {/* Header */}
          <div style={{ padding: "0 0 12px" }}>
            <Card
              style={{
                padding: 14,
                background: hexAlpha(M.pri, 0.1),
                border: "1px solid " + hexAlpha(M.pri, 0.2),
              }}
            >
              <div
                style={{
                  fontSize: 12,
                  color: M.pri,
                  fontWeight: 800,
                  marginBottom: 3,
                }}
              >
                🎓 Learning Center
              </div>
              <div style={{ fontSize: 12, color: hexAlpha(M.txt, 0.55) }}>
                {LEARN_TOPICS.length} topics · tap any card to read · track your
                progress
              </div>
            </Card>
          </div>

          {/* Pinned guided card — locked to top */}
          {isPinned && !phaseComplete && (
            <div style={{ padding: "0 0 16px" }}>{progressCard}</div>
          )}

          {/* All categories + topic grid */}
          {orderedCats.filter(Boolean).map((cat) => {
            const topics = topicsForCat(cat.key);
            if (topics.length === 0) return null;
            const cc = catColor(cat);
            return (
              <div key={cat.key} style={{ marginBottom: 28 }}>
                <div
                  style={{
                    display: "flex",
                    alignItems: "center",
                    gap: 8,
                    marginBottom: 12,
                    paddingLeft: 2,
                  }}
                >
                  <div
                    style={{
                      width: 3,
                      height: 18,
                      borderRadius: 2,
                      background: cc,
                      flexShrink: 0,
                    }}
                  />
                  <div style={{ fontSize: 13, fontWeight: 800, color: cc }}>
                    {cat.label}
                  </div>
                  <div style={{ fontSize: 11, color: hexAlpha(M.txt, 0.35) }}>
                    ({topics.length})
                  </div>
                </div>
                <div
                  style={{
                    display: "grid",
                    gridTemplateColumns: "1fr 1fr",
                    gap: 10,
                  }}
                >
                  {topics.map((t) => {
                    const isDone = progress.completed.includes(t.key);
                    return (
                      <button
                        key={t.key}
                        onClick={() => setSheet(t)}
                        style={{
                          ...ST.card,
                          background: isDone
                            ? hexAlpha(M.pri, 0.09)
                            : hexAlpha(M.bg, 0.55),
                          border:
                            "1px solid " +
                            (isDone
                              ? hexAlpha(M.pri, 0.28)
                              : hexAlpha(M.txt, 0.1)),
                          borderRadius: M.r20,
                          padding: "14px 12px",
                          cursor: "pointer",
                          fontFamily: "inherit",
                          textAlign: "left",
                          display: "flex",
                          flexDirection: "column",
                          gap: 8,
                          transition: "all .15s",
                          minHeight: 96,
                          boxSizing: "border-box",
                          position: "relative",
                        }}
                        onTouchStart={(e) => {
                          e.currentTarget.style.background = hexAlpha(
                            M.pri,
                            0.14,
                          );
                          e.currentTarget.style.borderColor = hexAlpha(
                            M.pri,
                            0.4,
                          );
                          e.currentTarget.style.transform = "scale(0.96)";
                        }}
                        onTouchEnd={(e) => {
                          e.currentTarget.style.background = isDone
                            ? hexAlpha(M.pri, 0.09)
                            : hexAlpha(M.bg, 0.55);
                          e.currentTarget.style.borderColor = isDone
                            ? hexAlpha(M.pri, 0.28)
                            : hexAlpha(M.txt, 0.1);
                          e.currentTarget.style.transform = "scale(1)";
                        }}
                      >
                        {/* Completed checkmark badge */}
                        {isDone && (
                          <div
                            style={{
                              position: "absolute",
                              top: 8,
                              right: 8,
                              width: 18,
                              height: 18,
                              borderRadius: "50%",
                              background: hexAlpha(M.pri, 0.85),
                              display: "flex",
                              alignItems: "center",
                              justifyContent: "center",
                              fontSize: 10,
                              color: M.onPri,
                              fontWeight: 900,
                            }}
                          >
                            ✓
                          </div>
                        )}
                        <div
                          style={{
                            display: "flex",
                            alignItems: "center",
                            gap: 8,
                          }}
                        >
                          <span style={{ fontSize: 22 }}>{t.icon}</span>
                          <div
                            style={{
                              width: 6,
                              height: 6,
                              borderRadius: "50%",
                              background: isDone
                                ? hexAlpha(M.pri, 0.6)
                                : catColor(cat),
                              flexShrink: 0,
                            }}
                          />
                        </div>
                        <div
                          style={{
                            fontSize: 12,
                            fontWeight: 700,
                            color: isDone ? hexAlpha(M.txt, 0.65) : M.txt,
                            lineHeight: 1.35,
                          }}
                        >
                          {t.title}
                        </div>
                      </button>
                    );
                  })}
                </div>
              </div>
            );
          })}

          {/* Bottom progress card — shown when pinned=false or phase=done */}
          {(!isPinned || phaseComplete) && (
            <div style={{ padding: "16px 0 8px" }}>
              {progressCard}
              <div style={{ display: "flex", gap: 10, marginTop: 10 }}>
                {allComplete ? (
                  <FilledBtn
                    label="Restart All Guided Training 🔄"
                    onClick={handleRestartAll}
                    full
                  />
                ) : progress.phase === "advanced" && !allComplete ? (
                  <>
                    <FilledBtn
                      label="Continue Advanced 🚀"
                      onClick={() =>
                        saveProgress({ ...progress, pinned: true })
                      }
                      full
                    />
                    <button
                      onClick={handleRestartAll}
                      style={{
                        ...ST.chip,
                        cursor: "pointer",
                        padding: "12px 14px",
                        whiteSpace: "nowrap",
                        background: hexAlpha(M.txt, 0.06),
                        border: "1px solid " + hexAlpha(M.txt, 0.12),
                        fontSize: 12,
                        color: hexAlpha(M.txt, 0.5),
                        fontFamily: "inherit",
                        borderRadius: M.r12,
                      }}
                    >
                      Restart
                    </button>
                  </>
                ) : (
                  <>
                    <FilledBtn
                      label="Continue to Advanced 🚀"
                      onClick={handleAdvance}
                      full
                    />
                    <button
                      onClick={handleRestartAll}
                      style={{
                        ...ST.chip,
                        cursor: "pointer",
                        padding: "12px 14px",
                        whiteSpace: "nowrap",
                        background: hexAlpha(M.txt, 0.06),
                        border: "1px solid " + hexAlpha(M.txt, 0.12),
                        fontSize: 12,
                        color: hexAlpha(M.txt, 0.5),
                        fontFamily: "inherit",
                        borderRadius: M.r12,
                      }}
                    >
                      Restart
                    </button>
                  </>
                )}
              </div>
            </div>
          )}
        </>
      )}

      {sheet && (
        <LearnSheet
          topic={sheet}
          onClose={() => {
            setSheet(null);
            if (sheet && TOPIC_QUIZ[sheet.key]) setQuizTopic(sheet.key);
          }}
          onComplete={markComplete}
        />
      )}
      {quizTopic && (
        <TopicQuiz
          topicKey={quizTopic}
          onPass={() => {
            if (onXpEarned) onXpEarned(XP_PER_QUIZ_PASS, "Quiz Pass");
          }}
          onDismiss={() => setQuizTopic(null)}
        />
      )}
    </div>
  );
}

function MarketsScreen({ advanced, initialSub }) {
  const { activeStock } = useApp();
  // Read from sessionStorage on mount; sessionStorage resets when app closes
  const [sub, setSub] = useState(() => {
    // If navigate() explicitly requested a sub-tab, use it
    if (initialSub) return initialSub;
    // Otherwise restore last used during this session
    return sessionStorage.getItem("siq_markets_sub") || "sentiment";
  });
  const prevInitialSub = useRef(initialSub);

  const switchSub = (s) => {
    setSub(s);
    try {
      sessionStorage.setItem("siq_markets_sub", s);
    } catch {}
  };

  // If navigate() fires a NEW initialSub (not just the same one from mount), honor it
  useEffect(() => {
    if (initialSub && initialSub !== prevInitialSub.current) {
      prevInitialSub.current = initialSub;
      switchSub(initialSub);
    }
  }, [initialSub]);

  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
      <div style={{ display: "flex", gap: 8 }}>
        {[
          ["🎯", "sentiment", "Sentiment"],
          ["🔮", "simulator", "Simulator"],
          ["🔍", "screener", "Screener"],
        ].map(([icon, id, label]) => (
          <button
            key={id}
            onClick={() => switchSub(id)}
            style={ST.subTabBtn(sub === id)}
          >
            <span>{icon}</span>
            {label}
          </button>
        ))}
      </div>
      {sub === "sentiment" && <SentimentScreen advanced={advanced} />}
      {sub === "simulator" && <SimulatorScreen advanced={advanced} />}
      {sub === "screener" && <StockScreener />}
    </div>
  );
}

