import { useApp } from '../context/AppContext';
import Spark from '../components/ui/Spark';
import { M, mc } from '../theme/buildM';
import { ST } from '../theme/styles';
import { hexAlpha } from '../theme/colorUtils';
// ─── Ticker mention detector — renders tappable stock chips in text
function MessageWithTickers({ content }) {
  const { navigate } = useApp();
  // Match 2-5 uppercase letters that look like tickers (not common words)
  const SKIP = new Set([
    "I",
    "A",
    "AI",
    "IT",
    "US",
    "UK",
    "OR",
    "IF",
    "IN",
    "ON",
    "AT",
    "TO",
    "BE",
    "IS",
    "BY",
    "AN",
    "AS",
    "UP",
    "DO",
    "GO",
    "MY",
    "SO",
    "NO",
    "OK",
    "TV",
    "PM",
    "AM",
    "PE",
    "EV",
    "VC",
    "IPO",
    "ETF",
    "IRA",
    "GDP",
    "CPI",
    "SEC",
    "FED",
  ]);
  const parts = content.split(/(\b[A-Z]{2,5}\b)/g);
  return (
    <span style={{ whiteSpace: "pre-wrap" }}>
      {parts.map((p, i) => {
        if (i % 2 === 1 && !SKIP.has(p)) {
          return (
            <button
              key={i}
              onClick={() => navigate("analyze", p)}
              style={{
                background: hexAlpha(M.pri, 0.18),
                backdropFilter: "blur(36px) saturate(160%)",
                WebkitBackdropFilter: "blur(36px) saturate(160%)",
                boxShadow: "inset 0 1px 0 " + hexAlpha(M.txt, 0.08),
                border: "1px solid " + hexAlpha(M.pri, 0.3),
                borderRadius: "6px",
                padding: "1px 7px",
                color: M.pri,
                fontFamily: "'JetBrains Mono',monospace",
                fontSize: "0.9em",
                fontWeight: 700,
                cursor: "pointer",
                display: "inline",
                lineHeight: "inherit",
                marginInline: 2,
              }}
            >
              {p} ↗
            </button>
          );
        }
        return <span key={i}>{p}</span>;
      })}
    </span>
  );
}
export default MessageWithTickers;
