import { useState, useRef, useEffect } from 'react';
import { M, mc } from '../../theme/buildM';
import { ST } from '../../theme/styles';
import { hexAlpha } from '../../theme/colorUtils';
import { ls } from '../../utils/storage';
import { useApp } from '../../context/AppContext';
import { Card, FilledBtn, TonalBtn, Input, Skel } from '../ui';
function ManualPortfolioEntry({ onAdd }) {
  const [sym, setSym] = useState("");
  const [price, setPrice] = useState("");
  const [shares, setShares] = useState("");
  const [msg, setMsg] = useState("");

  const add = () => {
    if (!sym.trim() || !price || !shares) return;
    const p = parseFloat(price),
      s = parseFloat(shares);
    if (isNaN(p) || isNaN(s)) return;
    onAdd({
      symbol: sym.toUpperCase(),
      name: sym.toUpperCase(),
      price: p,
      shares: s.toFixed(4),
      invested: p * s,
    });
    setSym("");
    setPrice("");
    setShares("");
    setMsg(`✓ ${sym.toUpperCase()} added`);
    setTimeout(() => setMsg(""), 2500);
  };

  return (
    <Card
      style={{
        padding: 20,
        border: "1px solid " + hexAlpha(M.gold, 0.25),
        background: hexAlpha(M.gold, 0.15),
        backdropFilter: "blur(36px) saturate(160%)",
        WebkitBackdropFilter: "blur(36px) saturate(160%)",
        boxShadow: "inset 0 1px 0 " + hexAlpha(M.txt, 0.08),
      }}
    >
      <div
        style={{
          fontSize: 12,
          color: M.gold,
          fontWeight: 700,
          marginBottom: 12,
          textTransform: "uppercase",
          letterSpacing: 1,
        }}
      >
        🔬 Manual Entry (Advanced)
      </div>
      <div style={{ display: "flex", flexDirection: "column", gap: 10 }}>
        <input
          value={sym}
          onChange={(e) => setSym(e.target.value.toUpperCase())}
          placeholder="Ticker (e.g. AAPL)"
          style={{
            width: "100%",
            background: hexAlpha(M.txt, 0.08),
            backdropFilter: "blur(36px) saturate(160%)",
            WebkitBackdropFilter: "blur(36px) saturate(160%)",
            boxShadow: "inset 0 1px 0 " + hexAlpha(M.txt, 0.08),
            border: "1px solid " + hexAlpha(M.txt, 0.14),
            borderRadius: M.r12,
            padding: "11px 14px",
            color: M.txt,
            fontSize: 14,
            outline: "none",
            fontFamily: "'JetBrains Mono',monospace",
            boxSizing: "border-box",
          }}
        />
        <input
          type="number"
          value={price}
          onChange={(e) => setPrice(e.target.value)}
          placeholder="Price per share ($)"
          style={{
            width: "100%",
            background: hexAlpha(M.txt, 0.08),
            backdropFilter: "blur(36px) saturate(160%)",
            WebkitBackdropFilter: "blur(36px) saturate(160%)",
            boxShadow: "inset 0 1px 0 " + hexAlpha(M.txt, 0.08),
            border: "1px solid " + hexAlpha(M.txt, 0.14),
            borderRadius: M.r12,
            padding: "11px 14px",
            color: M.txt,
            fontSize: 14,
            outline: "none",
            fontFamily: "inherit",
            boxSizing: "border-box",
          }}
        />
        <input
          type="number"
          value={shares}
          onChange={(e) => setShares(e.target.value)}
          placeholder="Number of shares"
          style={{
            width: "100%",
            background: hexAlpha(M.txt, 0.08),
            backdropFilter: "blur(36px) saturate(160%)",
            WebkitBackdropFilter: "blur(36px) saturate(160%)",
            boxShadow: "inset 0 1px 0 " + hexAlpha(M.txt, 0.08),
            border: "1px solid " + hexAlpha(M.txt, 0.14),
            borderRadius: M.r12,
            padding: "11px 14px",
            color: M.txt,
            fontSize: 14,
            outline: "none",
            fontFamily: "inherit",
            boxSizing: "border-box",
          }}
        />
        {price &&
          shares &&
          !isNaN(parseFloat(price)) &&
          !isNaN(parseFloat(shares)) && (
            <div style={{ fontSize: 12, color: hexAlpha(M.txt, 0.45) }}>
              Total: ${(parseFloat(price) * parseFloat(shares)).toFixed(2)}
            </div>
          )}
        <button
          onClick={add}
          style={{
            ...ST.btnFilled,
            background: hexAlpha(M.gold, 0.85),
            color: M.bg,
            padding: "13px",
            fontWeight: 800,
            fontSize: 14,
          }}
        >
          + Add to Portfolio
        </button>
        {msg && (
          <div style={{ color: M.gain, fontSize: 13, fontWeight: 700 }}>
            {msg}
          </div>
        )}
      </div>
    </Card>
  );
}

// ─── Portfolio Screen ─────────────────────────────────────────────
export default ManualPortfolioEntry;
