import { hexToRgb, blendHex, getLuminance } from './colorUtils';
// ─── Material You / Monet ────────────────────────────────────────
// Reads from window.AndroidMonet (JavascriptInterface set by MainActivity).
// No module-level caching — always reads fresh so the first real render
// after mount gets actual Monet values.

const MONET_DEFAULTS = {
  pri: "#A78BFA",
  priCont: "#2D1F5E",
  onPri: "#0C0420",
  sec: "#C4B5FD",
  secCont: "#3B2878",
  ter: "#86EFAC",
  terCont: "#14532D",
  surf: "#0A0C12",
  surfVar: "#1E2333",
  outline: "#3A2D5A",
  onSurf: "#EDE9FE",
  err: "#FCA5A5",
  errCont: "#4C1515",
};

const MONET_KEYS = {
  pri: "--md-sys-color-primary",
  priCont: "--md-sys-color-primary-container",
  onPri: "--md-sys-color-on-primary",
  sec: "--md-sys-color-secondary",
  secCont: "--md-sys-color-secondary-container",
  ter: "--md-sys-color-tertiary",
  terCont: "--md-sys-color-tertiary-container",
  surf: "--md-sys-color-surface",
  surfVar: "--md-sys-color-surface-variant",
  outline: "--md-sys-color-outline",
  onSurf: "--md-sys-color-on-surface",
  err: "--md-sys-color-error",
  errCont: "--md-sys-color-error-container",
};

function readAndroidColors() {
  // Called after React mounts — bridge is guaranteed available by then
  if (typeof window === "undefined" || !window.AndroidMonet) return null;
  try {
    const raw = window.AndroidMonet.getColors();
    const parsed = JSON.parse(raw);
    // Map CSS var names back to our short keys
    const result = {};
    for (const [key, cssVar] of Object.entries(MONET_KEYS)) {
      if (parsed[cssVar]) result[key] = parsed[cssVar];
    }
    return Object.keys(result).length > 0 ? result : null;
  } catch (e) {
    return null;
  }
}
// ─── Theme Builder ───────────────────────────────────────────────
function buildM(overrides) {
  const o = overrides || {};
  const d = MONET_DEFAULTS;
  const surf = o.surf || d.surf;
  const surfVar = o.surfVar || d.surfVar;
  const pri = o.pri || d.pri;
  const outline = o.outline || d.outline;
  const onSurf = o.onSurf || d.onSurf;
  const ter = o.ter || d.ter;
  const terCont = o.terCont || d.terCont;
  const err = o.err || d.err;
  const errCont = o.errCont || d.errCont;
  const isDark = getLuminance(surf) < 0.5;
  const bg = surf;
  const s1 = blendHex(surf, pri, 0.05);
  const s2 = blendHex(surf, pri, 0.09);
  const s3 = surfVar;
  const s4 = blendHex(surf, pri, 0.17);
  const outlineDim = blendHex(surf, outline, 0.4);
  const txt = onSurf;
  const txtMid = blendHex(surf, onSurf, 0.6);
  const txtDim = blendHex(surf, onSurf, 0.35);
  const gain = ter;
  const gainCont = terCont;
  const gold = o.gold || "M.gold"; // brand gold — no Monet mapping
  const goldCont = blendHex(surf, gold, isDark ? 0.2 : 0.15);
  return {
    bg,
    s1,
    s2,
    s3,
    s4,
    outline,
    outlineDim,
    pri,
    priCont: o.priCont || d.priCont,
    onPri: o.onPri || d.onPri,
    sec: o.sec || d.sec,
    secCont: o.secCont || d.secCont,
    ter,
    terCont,
    gold,
    goldCont,
    gain,
    gainCont,
    loss: err,
    lossCont: errCont,
    err,
    errCont,
    txt,
    txtMid,
    txtDim,
    r8: "8px",
    r12: "12px",
    r16: "16px",
    r20: "20px",
    r24: "24px",
    r28: "28px",
    rFull: "999px",
  };
}

// Start with defaults — App() replaces this after mount with real Monet values
let M = buildM(null);
export { MONET_DEFAULTS, MONET_KEYS, readAndroidColors, buildM };
