import { useState, useRef, useEffect } from 'react';
import { M, mc } from '../theme/buildM';
import { ST } from '../theme/styles';
import { hexAlpha } from '../theme/colorUtils';
import { ls } from '../utils/storage';
import { useApp } from '../context/AppContext';
import { useSettings } from '../context/SettingsContext';
import { Card, FilledBtn, TonalBtn, Input, Skel } from '../components/ui';
import { ErrorCard, NoAIBanner } from '../components/ui';
import ObolLogo from '../components/ui/ObolLogo';
import { callAI, hasAIConfigured } from '../api/ai';
import { resolveSymbol } from '../data/stocks';
import CrossTabBar from '../components/CrossTabBar';
import MessageWithTickers from '../components/MessageWithTickers';
// ─── Advisor Screen (pinned input) ────────────────────────────────
function AdvisorScreen({ risk, advanced, layout }) {
  const settings = useSettings();
  const { activeStock, navigate } = useApp();
  const profileKey = `siq_chat_${settings?.profile?.email || "guest"}`;
  const [msgs, setMsgs] = useState(() =>
    ls.get(profileKey, [
      {
        role: "assistant",
        content:
          `Hey! 👋 I'm your AI investing advisor.\n\n${risk ? `You're a **${risk.label}** investor — I'll tailor every answer.\n\n` : ""}` +
          `Ask me anything — I'll keep it ${advanced ? "detailed" : "simple and beginner-friendly"}.`,
      },
    ]),
  );
  const [input, setInput] = useState("");
  const [loading, setLoading] = useState(false);
  const [lastErr, setLastErr] = useState(null);
  const bottomRef = useRef(null);
  const prevStock = useRef(null);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: "smooth" });
  }, [msgs]);
  useEffect(() => {
    ls.set(profileKey, msgs.slice(-40));
  }, [msgs]);

  // When activeStock changes, inject a context nudge ONLY if not already discussed recently
  useEffect(() => {
    if (!activeStock) {
      prevStock.current = null;
      return;
    }
    if (activeStock === prevStock.current) return;
    prevStock.current = activeStock;
    // Check last 6 messages — if they already mention this stock, skip
    setMsgs((p) => {
      const recent = p
        .slice(-6)
        .map((m) => m.content || "")
        .join(" ");
      if (recent.includes(activeStock)) return p; // already in context
      return [
        ...p,
        {
          role: "assistant",
          content: `📊 I see you've been looking at **${activeStock}**. Want me to break it down, compare it with similar stocks, or explain what the current signals mean for you?`,
        },
      ];
    });
  }, [activeStock]);

  const send = async (overrideText) => {
    const text = overrideText || input;
    if (!text.trim() || loading) return;
    const msg = { role: "user", content: text };
    setMsgs((p) => [...p, msg]);
    setInput("");
    setLoading(true);
    setLastErr(null);
    const stockCtx = activeStock
      ? ` The user is currently researching ${activeStock}.`
      : "";
    const sys = `You are a friendly investment advisor.${stockCtx} ${risk ? `Investor: ${risk.label} (${risk.adj}).` : ""} ${advanced ? "Detailed analytical answers with specific data." : "Plain English. No jargon. Beginner analogies."} Always briefly mention risks. Write stock tickers in UPPERCASE (e.g. AAPL, TSLA) so they are detectable.`;
    try {
      const resp = await callAI(
        [...msgs, msg].map((m) => ({ role: m.role, content: m.content })),
        sys,
        settings,
      );
      setMsgs((p) => [...p, { role: "assistant", content: resp }]);
    } catch (e) {
      setLastErr(e);
      setMsgs((p) => [...p, { role: "assistant", content: "__error__" }]);
    }
    setLoading(false);
  };

  // ── Predetermined answer tree — 5 levels deep, no AI needed ──────
  // chipLevel tracks which layer we are on: 0 = root, 1-4 = follow-ups
  const [chipLevel, setChipLevel] = useState(0);
  const [chipPath, setChipPath] = useState([]); // breadcrumb of selected topics

  const PRED_TREE_BEGINNER = {
    root: [
      "How do I start investing?",
      "What is a stock?",
      "What is diversification?",
      "How much risk should I take?",
      "What is dollar-cost averaging?",
    ],
    "How do I start investing?": {
      answer:
        "The simplest path: 1) Build a 3-month emergency fund first. 2) Open a stocks & shares ISA or brokerage account. 3) Buy an S&P 500 index fund (like VUSA or CSPX) every month. 4) Reinvest dividends. 5) Don't check it daily — think in years, not days.",
      followups: [
        "What is an index fund?",
        "How much should I invest each month?",
        "What broker should I use?",
        "When should I sell?",
        "What is an ISA?",
      ],
    },
    "What is an index fund?": {
      answer:
        "An index fund is like a shopping basket that automatically holds a tiny slice of hundreds of companies. When you buy one share of an S&P 500 index fund, you instantly own a tiny piece of Apple, Microsoft, Google, Amazon, and 496 other companies.\n\nBecause it's spread across so many companies, one company failing barely affects you.",
      followups: [
        "What's the difference between ETF and index fund?",
        "Which index fund is best for beginners?",
        "Do index funds pay dividends?",
        "How does an index fund grow?",
      ],
    },
    "What is a stock?": {
      answer:
        "A stock is a tiny ownership slice of a company. If Apple is worth $3 trillion and has 15 billion shares, each share is worth about $200 and represents 1/15,000,000,000th of the company.\n\nIf Apple grows and becomes worth more, your slice is worth more too.",
      followups: [
        "How do stocks make money?",
        "What is a dividend?",
        "Why do stock prices change?",
        "What is market cap?",
      ],
    },
    "What is diversification?": {
      answer:
        "Diversification means not putting all your money in one place. If you own 20 different stocks across 5 sectors and one company collapses, you've only lost 5% of your portfolio.\n\nThe goal: when some investments fall, others stay steady or rise.",
      followups: [
        "How many stocks do I need?",
        "What sectors should I invest in?",
        "What is a balanced portfolio?",
        "Should I own international stocks?",
      ],
    },
    "How much risk should I take?": {
      answer:
        "It depends on two things:\n\n1. Time horizon: Money you won't need for 10+ years can take more risk — markets always recover eventually.\n2. Personality: If you'd panic and sell during a 30% crash, you need a lower-risk portfolio.\n\nRule of thumb: Put 'years until retirement ÷ 100' into bonds, the rest in stocks.",
      followups: [
        "What is a low-risk investment?",
        "What is a high-risk investment?",
        "How do bonds reduce risk?",
        "What happened in the 2008 crash?",
      ],
    },
    "What is dollar-cost averaging?": {
      answer:
        "Dollar-cost averaging (DCA) means investing a fixed amount every month regardless of what the market is doing.\n\nIn January: market is high → you buy fewer shares.\nIn March: market crashes → you buy more shares cheaply.\n\nOver time, your average cost stays lower than if you tried to 'time' the market.",
      followups: [
        "How often should I invest?",
        "Should I invest a lump sum or monthly?",
        "Does DCA work in a bear market?",
        "What is a bear market?",
      ],
    },
    "What is a dividend?": {
      answer:
        "A dividend is a cash payment a company makes to shareholders from its profits — like interest from a savings account, but from a real business.\n\nExample: If you own 100 Apple shares and Apple pays a $1 dividend per share, you receive $100 in cash. You can spend it or buy more shares.",
      followups: [
        "Which stocks pay the best dividends?",
        "What is dividend yield?",
        "Are dividends taxed?",
        "What is a DRIP?",
      ],
    },
    "What is a low-risk investment?": {
      answer:
        "Low-risk investments sacrifice growth for safety:\n\n• Government bonds: Lend money to governments. Very safe, modest returns.\n• Index funds: Spread across hundreds of companies. Low risk for long-term investors.\n• Dividend stocks: Stable companies that pay regular cash.\n• Savings accounts: Guaranteed return but often below inflation.",
      followups: [
        "What are government bonds?",
        "What is inflation risk?",
        "What is a defensive stock?",
      ],
    },
  };

  const PRED_TREE_ADVANCED = {
    root: [
      "Screen for undervalued stocks",
      "Explain options flow signals",
      "Sector rotation timing",
      "Macro regime identification",
      "Risk-adjusted return metrics",
    ],
    "Screen for undervalued stocks": {
      answer:
        "A systematic screen for undervalued stocks:\n\n1. P/E < sector average AND P/E < 5-year own average\n2. Price-to-Book < 1.5 (paying less than asset value)\n3. Free Cash Flow yield > 5% (company generates real cash)\n4. ROE > 15% (efficient capital use)\n5. Debt/Equity < 1.0 (not over-leveraged)\n6. Earnings growth > 0% last 3 years\n\nTools: Finviz screener, Simply Wall St, Macrotrends.",
      followups: [
        "What is free cash flow yield?",
        "Explain Price-to-Book ratio",
        "How do I read the Finviz screener?",
        "What is ROE and why does it matter?",
        "Graham Number explained",
      ],
    },
    "Explain options flow signals": {
      answer:
        "Options flow analysis tracks where large, often institutional, money is moving:\n\n• Unusual call buying (far OTM, short dated) = bullish conviction\n• Large put purchases before earnings = hedging or bearish bet\n• Put/Call ratio > 1.0 = fear dominant; < 0.7 = greed dominant\n• GEX (Gamma Exposure) > 0 = dealers buy dips (stabilising); < 0 = dealers sell dips (volatile)\n\nTrack via: Unusual Whales, Market Chameleon, Barchart.",
      followups: [
        "What is gamma squeeze?",
        "Explain IV crush after earnings",
        "What is open interest?",
        "How to read the options chain?",
        "What is a covered call strategy?",
      ],
    },
    "Sector rotation timing": {
      answer:
        "Sector rotation follows the economic cycle:\n\nExpansion: Tech, Consumer Discretionary, Industrials outperform.\nPeak: Energy, Materials, Commodities outperform.\nContraction: Healthcare, Consumer Staples, Utilities outperform.\nRecovery: Financials, Real Estate, Tech begin to outperform again.\n\nSignals to watch: ISM PMI, yield curve slope, Fed language.",
      followups: [
        "How do I identify the current economic phase?",
        "What ETFs cover each sector?",
        "Explain the yield curve",
        "What is the ISM PMI?",
        "Defensive vs cyclical stocks",
      ],
    },
    "Macro regime identification": {
      answer:
        "Macro regimes drive asset class returns more than individual stock picking:\n\n• Risk-on (low rates, strong growth): Equities, HY bonds, EM outperform.\n• Risk-off (recession fears, high rates): Treasuries, gold, USD outperform.\n• Stagflation (high inflation + low growth): Commodities, TIPS, energy stocks.\n• Goldilocks (moderate growth + falling inflation): Tech, growth stocks thrive.\n\nKey indicators: Fed Funds rate direction, CPI trend, yield curve, credit spreads.",
      followups: [
        "How do I track credit spreads?",
        "Explain TIPS vs regular bonds",
        "What moves gold prices?",
        "How does USD strength affect stocks?",
        "Ray Dalio All-Weather portfolio",
      ],
    },
    "Risk-adjusted return metrics": {
      answer:
        "Raw returns are meaningless without risk context:\n\n• Sharpe Ratio = (Return - Risk Free Rate) / StdDev. Above 1.0 is good; above 2.0 excellent.\n• Sortino Ratio = same but only penalises downside volatility. More useful for investors who dislike drawdowns.\n• Max Drawdown = worst peak-to-trough loss. A 50% drawdown requires 100% gain to recover.\n• Calmar Ratio = Annual Return / Max Drawdown. Higher is better.\n\nGoal: maximize return per unit of risk, not raw return.",
      followups: [
        "How do I calculate Sharpe ratio?",
        "Explain portfolio standard deviation",
        "What is beta vs standard deviation?",
        "How hedge funds measure risk?",
        "Kelly Criterion for position sizing",
      ],
    },
    "What is free cash flow yield?": {
      answer:
        "FCF Yield = Free Cash Flow / Market Cap × 100%\n\nFree cash flow is the real cash a business generates after all expenses and capital investment. Unlike earnings, it's very hard to fake.\n\nFCF Yield > 5% = potentially undervalued relative to cash generation.\nFCF Yield < 2% = market pricing in high growth expectations.\n\nBuffett calls FCF the 'owner's earnings' — the most honest measure of a business's value.",
      followups: [
        "How do I find FCF on financial statements?",
        "FCF vs earnings — what's the difference?",
        "What is owner earnings?",
      ],
    },
    "What is gamma squeeze?": {
      answer:
        "A gamma squeeze happens when market makers (who sold call options) must buy the underlying stock to hedge their position as it rises — which pushes the price higher, forcing them to buy more, creating a feedback loop.\n\nClassic example: GameStop (GME) Jan 2021. Retail traders bought far OTM calls. Market makers hedged by buying GME shares. Price exploded.\n\nGamma squeeze conditions: High short interest + high call OI + low float stock.",
      followups: [
        "What is a short squeeze?",
        "Explain delta hedging",
        "What is implied volatility?",
      ],
    },
  };

  const tree = advanced ? PRED_TREE_ADVANCED : PRED_TREE_BEGINNER;

  const handlePredChip = (text) => {
    const node = tree[text];
    if (node) {
      // Has a predefined answer — show it as AI message without API call
      setMsgs((p) => [
        ...p,
        { role: "user", content: text },
        { role: "assistant", content: node.answer, isPredefined: true },
      ]);
      setChipPath((p) => [...p, text]);
      setChipLevel((l) => l + 1);
    } else {
      // No predefined answer — route to AI
      send(text);
      setChipLevel(0);
      setChipPath([]);
    }
  };

  // Build current chip list from tree
  const lastPredChip = chipPath[chipPath.length - 1];
  const predFollowups =
    lastPredChip && tree[lastPredChip]?.followups
      ? tree[lastPredChip].followups
      : [];
  const rootChips = tree.root || [];

  // Stock-specific chips when a stock is active
  const stockChips = activeStock
    ? [`Is ${activeStock} a good buy?`, `Risks of ${activeStock}?`]
    : [];

  // Chip display: if we have predefined followups, show those + 1 general; else show root + stock chips
  const QUICK =
    chipLevel > 0 && predFollowups.length > 0
      ? [
          ...predFollowups.slice(0, 4),
          ...(activeStock ? [`More on ${activeStock}`] : []),
          "Start over",
        ]
      : [...stockChips, ...rootChips.slice(0, activeStock ? 2 : 4)];

  const handleChip = (q) => {
    if (q === "Start over") {
      setChipLevel(0);
      setChipPath([]);
      return;
    }
    if (q.startsWith("More on ")) {
      send(q);
      return;
    }
    handlePredChip(q);
  };

  return (
    <div
      style={{
        display: "flex",
        flexDirection: "column",
        height: "100%",
        overflow: "hidden",
      }}
    >
      {/* Active stock context banner */}
      {activeStock && (
        <div
          style={{
            flexShrink: 0,
            margin: "10px 16px 0",
            background: hexAlpha(M.pri, 0.1),
            backdropFilter: "blur(16px)",
            border: "1px solid " + hexAlpha(M.pri, 0.2),
            borderRadius: M.r16,
            padding: "10px 14px",
            display: "flex",
            alignItems: "center",
            gap: 10,
          }}
        >
          <span style={{ fontSize: 12, color: M.pri, fontWeight: 700 }}>
            📊 {activeStock}
          </span>
          <span style={{ fontSize: 12, color: M.txtMid, flex: 1 }}>
            Advisor knows your research
          </span>
          <button
            onClick={() => navigate("analyze", activeStock)}
            style={{
              ...ST.btnGhost,
              background: "transparent",
              backdropFilter: "blur(36px) saturate(160%)",
              WebkitBackdropFilter: "blur(36px) saturate(160%)",
              boxShadow: "inset 0 1px 0 " + hexAlpha(M.txt, 0.08),
              border: "1px solid " + hexAlpha(M.pri, 0.25),
              color: M.pri,
              borderRadius: M.rFull,
              padding: "3px 10px",
              fontSize: 11,
              cursor: "pointer",
              fontFamily: "inherit",
              fontWeight: 700,
            }}
          >
            View →
          </button>
        </div>
      )}

      {/* Messages */}
      <div
        style={{
          flex: 1,
          overflowY: "auto",
          display: "flex",
          flexDirection: "column",
          gap: 14,
          padding: "12px 16px 8px",
        }}
      >
        {msgs.map((m, i) => (
          <div
            key={i}
            style={{
              display: "flex",
              justifyContent: m.role === "user" ? "flex-end" : "flex-start",
            }}
          >
            {m.content === "__error__" ? (
              <div style={{ maxWidth: "90%", width: "100%" }}>
                <ErrorCard
                  error={lastErr}
                  onRetry={() => {
                    setMsgs((p) => p.slice(0, -2));
                  }}
                  onOpenSettings={() => {}}
                />
              </div>
            ) : (
              <div
                style={{
                  maxWidth: "82%",
                  background:
                    m.role === "user"
                      ? hexAlpha(M.pri, 0.14)
                      : hexAlpha(M.txt, 0.06),
                  backdropFilter: "blur(20px)",
                  WebkitBackdropFilter: "blur(20px)",
                  color: m.role === "user" ? M.pri : M.txt,
                  borderRadius:
                    m.role === "user"
                      ? `${M.r20} ${M.r20} ${M.r8} ${M.r20}`
                      : `${M.r20} ${M.r20} ${M.r20} ${M.r8}`,
                  padding: "14px 16px",
                  fontSize: 14,
                  lineHeight: 1.75,
                  border:
                    m.role === "user"
                      ? "1px solid " + hexAlpha(M.pri, 0.22)
                      : "1px solid " + hexAlpha(M.txt, 0.09),
                  boxShadow:
                    m.role === "user"
                      ? "inset 0 1px 0 " + hexAlpha(M.pri, 0.15)
                      : "inset 0 1px 0 " + hexAlpha(M.txt, 0.08),
                }}
              >
                {m.role === "assistant" && (
                  <div
                    style={{
                      fontSize: 10,
                      color: hexAlpha(M.txt, 0.35),
                      marginBottom: 6,
                      fontWeight: 700,
                      textTransform: "uppercase",
                      letterSpacing: 1,
                    }}
                  >
                    🤖 AI ADVISOR
                  </div>
                )}
                {m.role === "assistant" ? (
                  <MessageWithTickers content={m.content} />
                ) : (
                  <span style={{ whiteSpace: "pre-wrap" }}>{m.content}</span>
                )}
              </div>
            )}
          </div>
        ))}
        {loading && (
          <div style={{ display: "flex" }}>
            <div
              style={{
                background: hexAlpha(M.txt, 0.06),
                backdropFilter: "blur(20px)",
                border: "1px solid " + hexAlpha(M.txt, 0.09),
                boxShadow: "inset 0 1px 0 " + hexAlpha(M.txt, 0.08),
                borderRadius: `${M.r20} ${M.r20} ${M.r20} ${M.r8}`,
                padding: "14px 18px",
              }}
            >
              <div style={{ display: "flex", gap: 5 }}>
                {[0, 1, 2].map((i) => (
                  <div
                    key={i}
                    style={{
                      width: 7,
                      height: 7,
                      borderRadius: "50%",
                      background: hexAlpha(M.pri, 0.18),
                      animation: "bounce 0.9s infinite",
                      animationDelay: `${i * 0.2}s`,
                    }}
                  />
                ))}
              </div>
            </div>
          </div>
        )}
        <div ref={bottomRef} />
      </div>

      {/* Pinned input */}
      <div
        style={{
          flexShrink: 0,
          padding: "10px 16px 20px",
          background: `linear-gradient(to top,${hexAlpha(M.bg, 0.96)} 60%,transparent)`,
          backdropFilter: "blur(36px) saturate(160%)",
          WebkitBackdropFilter: "blur(36px) saturate(160%)",
        }}
      >
        <div
          style={{
            display: "flex",
            gap: 7,
            overflowX: "auto",
            paddingBottom: 10,
          }}
        >
          {QUICK.map((q) => (
            <button
              key={q}
              onClick={() => handleChip(q)}
              style={{
                ...ST.chip,
                boxShadow: "none",
                background: hexAlpha(M.txt, 0.07),
                color: hexAlpha(M.txt, 0.6),
                border: "1px solid " + hexAlpha(M.txt, 0.12),
                borderRadius: M.rFull,
                padding: "7px 14px",
                fontSize: 12,
                fontWeight: 500,
                cursor: "pointer",
                fontFamily: "inherit",
                whiteSpace: "nowrap",
                flexShrink: 0,
              }}
            >
              {q}
            </button>
          ))}
        </div>
        <div style={{ display: "flex", gap: 10, alignItems: "center" }}>
          <input
            value={input}
            onChange={(e) => setInput(e.target.value)}
            onKeyDown={(e) => e.key === "Enter" && send()}
            placeholder="Ask anything…"
            style={{
              ...ST.input,
              flex: 1,
              minWidth: 0,
              borderRadius: M.r20,
              padding: "13px 18px",
              fontSize: 15,
              outline: "none",
            }}
          />
          <button
            onClick={() => send()}
            disabled={loading}
            style={{
              ...ST.btnFilled,
              width: 48,
              height: 48,
              borderRadius: "50%",
              padding: 0,
              boxSizing: "border-box",
              background: loading
                ? hexAlpha(M.txt, 0.07)
                : hexAlpha(M.pri, 0.88),
              color: loading ? hexAlpha(M.txt, 0.3) : M.onPri,
              border: loading
                ? "1px solid " + hexAlpha(M.txt, 0.1)
                : "1px solid " + hexAlpha(M.pri, 0.45),
              cursor: loading ? "not-allowed" : "pointer",
              display: "flex",
              alignItems: "center",
              justifyContent: "center",
              flexShrink: 0,
              boxShadow: loading
                ? "none"
                : "0 4px 20px " + hexAlpha(M.pri, 0.35),
            }}
          >
            {loading ? (
              <div
                style={{
                  width: 18,
                  height: 18,
                  borderRadius: "50%",
                  border: "2px solid " + M.txtDim,
                  borderTopColor: "transparent",
                  animation: "spin .7s linear infinite",
                }}
              />
            ) : (
              <SendIcon
                size={20}
                color={loading ? hexAlpha(M.txt, 0.3) : M.onPri}
              />
            )}
          </button>
        </div>
      </div>
    </div>
  );
}
export default AdvisorScreen;
