import { useState, useRef, useEffect } from 'react';
import { M, mc } from '../../theme/buildM';
import { ST } from '../../theme/styles';
import { hexAlpha } from '../../theme/colorUtils';
import { ls } from '../../utils/storage';
import { useApp } from '../../context/AppContext';
import { Card, FilledBtn, TonalBtn, Input, Skel } from '../ui';
import { PAPER_PRICES } from '../../data/levels';
function PaperTradingScreen({ onXpEarned }) {
  const [paper, setPaper] = useState(() => ls.get("siq_paper", PAPER_DEFAULT));
  const [ticker, setTicker] = useState("");
  const [qty, setQty] = useState("10");
  const [mode, setMode] = useState("buy");
  const [msg, setMsg] = useState(null);
  const save = (p) => {
    setPaper(p);
    ls.set("siq_paper", p);
  };
  const price = (t) => PAPER_PRICES[t.toUpperCase().trim()] || null;
  const execute = () => {
    const t = ticker.toUpperCase().trim();
    const q = parseInt(qty) || 0;
    const p = price(t);
    if (!p) return setMsg({ ok: false, text: "Unknown ticker " + t });
    if (q <= 0) return setMsg({ ok: false, text: "Enter a valid quantity" });
    const cost = +(p * q).toFixed(2);
    if (mode === "buy") {
      if (cost > paper.cash)
        return setMsg({
          ok: false,
          text:
            "Need $" +
            cost +
            " — only $" +
            paper.cash.toFixed(0) +
            " available",
        });
      const h = paper.holdings;
      const prev = h[t] || { shares: 0, avgCost: p };
      const ns = prev.shares + q;
      const na = +((prev.avgCost * prev.shares + cost) / ns).toFixed(2);
      const next = {
        ...paper,
        cash: +(paper.cash - cost).toFixed(2),
        holdings: { ...h, [t]: { shares: ns, avgCost: na } },
        trades: [
          { t, q, p, mode: "buy", date: new Date().toLocaleDateString() },
          ...paper.trades.slice(0, 49),
        ],
      };
      save(next);
      setMsg({ ok: true, text: "Bought " + q + " " + t + " @ $" + p });
      if (onXpEarned) onXpEarned(20, "Paper Trade");
    } else {
      const h = paper.holdings[t];
      if (!h || h.shares < q)
        return setMsg({
          ok: false,
          text: "Only " + (h ? h.shares : 0) + " shares of " + t + " held",
        });
      const remaining = h.shares - q;
      const newH = { ...paper.holdings };
      if (remaining === 0) delete newH[t];
      else newH[t] = { ...h, shares: remaining };
      const next = {
        ...paper,
        cash: +(paper.cash + cost).toFixed(2),
        holdings: newH,
        trades: [
          { t, q, p, mode: "sell", date: new Date().toLocaleDateString() },
          ...paper.trades.slice(0, 49),
        ],
      };
      save(next);
      setMsg({ ok: true, text: "Sold " + q + " " + t + " @ $" + p });
    }
    setTicker("");
    setQty("10");
  };
  const portValue = Object.entries(paper.holdings).reduce(
    (s, [t, h]) => s + (price(t) || 0) * h.shares,
    0,
  );
  const pnl = +(paper.cash + portValue - 10000).toFixed(2);
  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
      <div
        style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr", gap: 8 }}
      >
        {[
          ["Cash", "$" + paper.cash.toFixed(0), M.txt],
          ["Portfolio", "$" + portValue.toFixed(0), M.pri],
          ["P&L", (pnl >= 0 ? "+" : "") + pnl, pnl >= 0 ? M.gain : M.loss],
        ].map(([l, v, c]) => (
          <Card key={l} style={{ padding: "12px 10px", textAlign: "center" }}>
            <div
              style={{
                fontSize: 10,
                color: hexAlpha(M.txt, 0.38),
                fontWeight: 700,
                marginBottom: 4,
              }}
            >
              {l}
            </div>
            <div
              style={{
                fontSize: 14,
                fontWeight: 900,
                color: c,
                fontFamily: "monospace",
              }}
            >
              {v}
            </div>
          </Card>
        ))}
      </div>
      <Card style={{ padding: 18 }}>
        <div style={{ display: "flex", gap: 8, marginBottom: 14 }}>
          {["buy", "sell"].map((m) => (
            <button
              key={m}
              onClick={() => setMode(m)}
              style={{
                flex: 1,
                padding: "10px 0",
                borderRadius: M.r12,
                cursor: "pointer",
                fontFamily: "inherit",
                fontSize: 13,
                fontWeight: 700,
                border:
                  "1px solid " +
                  (mode === m
                    ? hexAlpha(m === "buy" ? M.gain : M.loss, 0.35)
                    : hexAlpha(M.txt, 0.1)),
                background:
                  mode === m
                    ? hexAlpha(m === "buy" ? M.gain : M.loss, 0.12)
                    : "transparent",
                color:
                  mode === m
                    ? m === "buy"
                      ? M.gain
                      : M.loss
                    : hexAlpha(M.txt, 0.4),
              }}
            >
              {m === "buy" ? "🟢 Buy" : "🔴 Sell"}
            </button>
          ))}
        </div>
        <div style={{ display: "flex", gap: 8, marginBottom: 8 }}>
          <input
            value={ticker}
            onChange={(e) => setTicker(e.target.value.toUpperCase())}
            placeholder="AAPL"
            style={{
              ...ST.input,
              flex: 2,
              padding: "10px 12px",
              outline: "none",
              fontSize: 14,
              fontFamily: "monospace",
              fontWeight: 700,
              borderRadius: M.r12,
              border: "1px solid " + hexAlpha(M.txt, 0.12),
            }}
          />
          <input
            value={qty}
            onChange={(e) => setQty(e.target.value.replace(/[^0-9]/g, ""))}
            placeholder="Qty"
            style={{
              ...ST.input,
              flex: 1,
              padding: "10px 12px",
              outline: "none",
              fontSize: 14,
              fontFamily: "monospace",
              fontWeight: 700,
              borderRadius: M.r12,
              border: "1px solid " + hexAlpha(M.txt, 0.12),
            }}
          />
        </div>
        {ticker && price(ticker) && (
          <div
            style={{
              fontSize: 11,
              color: hexAlpha(M.txt, 0.45),
              marginBottom: 8,
            }}
          >
            {"Simulated price: $" +
              price(ticker) +
              " · Total: $" +
              (price(ticker) * (parseInt(qty) || 0)).toFixed(0)}
          </div>
        )}
        {msg && (
          <div
            style={{
              fontSize: 12,
              fontWeight: 700,
              color: msg.ok ? M.gain : M.loss,
              marginBottom: 10,
            }}
          >
            {msg.text}
          </div>
        )}
        <FilledBtn
          label={mode === "buy" ? "Execute Buy" : "Execute Sell"}
          onClick={execute}
          full
          icon={mode === "buy" ? "🟢" : "🔴"}
        />
      </Card>
      {Object.entries(paper.holdings).length > 0 && (
        <Card style={{ padding: 18 }}>
          <div
            style={{
              fontSize: 12,
              fontWeight: 800,
              color: M.txt,
              marginBottom: 12,
            }}
          >
            {"📊 Holdings"}
          </div>
          {Object.entries(paper.holdings).map(([t, h]) => {
            const cp = price(t) || 0;
            const val = cp * h.shares;
            const gl = (cp - h.avgCost) * h.shares;
            return (
              <div
                key={t}
                style={{
                  display: "flex",
                  alignItems: "center",
                  gap: 10,
                  marginBottom: 10,
                  paddingBottom: 10,
                  borderBottom: "1px solid " + hexAlpha(M.txt, 0.06),
                }}
              >
                <span
                  style={{
                    fontFamily: "monospace",
                    fontWeight: 800,
                    color: M.txt,
                    fontSize: 14,
                    minWidth: 48,
                  }}
                >
                  {t}
                </span>
                <div style={{ flex: 1 }}>
                  <div style={{ fontSize: 11, color: hexAlpha(M.txt, 0.45) }}>
                    {h.shares + " shares · avg $" + h.avgCost}
                  </div>
                </div>
                <div style={{ textAlign: "right" }}>
                  <div
                    style={{
                      fontSize: 13,
                      fontWeight: 700,
                      color: M.txt,
                      fontFamily: "monospace",
                    }}
                  >
                    {"$" + val.toFixed(0)}
                  </div>
                  <div
                    style={{
                      fontSize: 11,
                      color: gl >= 0 ? M.gain : M.loss,
                      fontFamily: "monospace",
                    }}
                  >
                    {(gl >= 0 ? "+" : "") + gl.toFixed(0)}
                  </div>
                </div>
              </div>
            );
          })}
        </Card>
      )}
      <button
        onClick={() => {
          save(PAPER_DEFAULT);
          setMsg({ ok: true, text: "Portfolio reset to $10,000 cash" });
        }}
        style={{
          background: "transparent",
          border: "1px solid " + hexAlpha(M.loss, 0.22),
          borderRadius: M.r12,
          padding: "10px 0",
          cursor: "pointer",
          fontSize: 12,
          color: hexAlpha(M.loss, 0.55),
          fontFamily: "inherit",
        }}
      >
        Reset Paper Portfolio
      </button>
    </div>
  );
}

// ─── Investor Journal ──────────────────────────────────────────────────────────
export default PaperTradingScreen;
