import { useState, useRef, useEffect } from 'react';
import { M, mc } from '../theme/buildM';
import { ST } from '../theme/styles';
import { hexAlpha } from '../theme/colorUtils';
import { ls } from '../utils/storage';
import { useApp } from '../context/AppContext';
import { useSettings } from '../context/SettingsContext';
import { Card, FilledBtn, TonalBtn, Input, Skel } from '../components/ui';
import { ErrorCard, NoAIBanner } from '../components/ui';
import ObolLogo from '../components/ui/ObolLogo';
import { callAI, hasAIConfigured } from '../api/ai';
import { fetchYahooStockData, fetchLivePrice } from '../api/yahoo';
import { resolveSymbol, STOCK_CATS } from '../data/stocks';
import CrossTabBar from '../components/CrossTabBar';
import MessageWithTickers from '../components/MessageWithTickers';
import StockSheet from '../components/StockSheet';
import TickerBanner, { TickerToast } from '../components/TickerBanner';
import QuizScreen from './QuizScreen';

function AnalyzeScreen({ risk, advanced, triggerSym, onTriggerConsumed }) {
  const settings = useSettings();
  const { setActiveStock } = useApp();
  const [rawInput, setRawInput] = useState(""); // what user typed
  const [result, setResult] = useState(() => ls.get("siq_lastAnalysis", null));
  const [loading, setLoading] = useState(false);
  const [step, setStep] = useState("");
  const [err, setErr] = useState("");
  const [amount, setAmount] = useState("");
  const [addMsg, setAddMsg] = useState("");
  // showCats: true = show browser, false = show result / loading
  const [showCats, setShowCats] = useState(!ls.get("siq_lastAnalysis", null));
  const [activeCat, setActiveCat] = useState(0);
  const [aiExpanded, setAiExpanded] = useState(false);
  const [aiLoading, setAiLoading] = useState(false);
  const [aiStep, setAiStep] = useState("");
  const [aiErr, setAiErr] = useState("");

  const getPortfolio = () => ls.get("siq_portfolio", []);
  const savePortfolio = (p) => ls.set("siq_portfolio", p);

  const doAnalyze = async (inputVal) => {
    const sym = resolveSymbol(inputVal || rawInput);
    if (!sym.trim()) return;
    setRawInput(sym);
    setLoading(true);
    setResult(null);
    setErr("");
    setShowCats(false);
    setAiExpanded(false);
    try {
      setStep("📡 Fetching live market data…");
      const yahoo = await fetchYahooStockData(sym);
      if (!yahoo)
        throw new Error(
          `Could not fetch data for "${sym}". Check the ticker and try again.`,
        );
      const res = { ...yahoo, aiAnalysis: null };
      setResult(res);
      ls.set("siq_lastAnalysis", res);
      setActiveStock(sym);
    } catch (e) {
      setErr(
        e.message || `Couldn't load "${sym}". Check the name and try again.`,
      );
    }
    setLoading(false);
    setStep("");
  };

  const doAIAnalysis = async () => {
    if (!result) return;
    setAiLoading(true);
    setAiStep("🧠 Generating AI analysis…");
    try {
      const data = await analyzeStock(result.symbol, risk, advanced, settings);
      const updated = { ...result, aiAnalysis: data, ...data };
      setResult(updated);
      ls.set("siq_lastAnalysis", updated);
    } catch (e) {
      setAiErr(e.message || "AI analysis failed");
    }
    setAiLoading(false);
    setAiStep("");
  };

  // External trigger from ticker tap
  useEffect(() => {
    if (triggerSym) {
      setRawInput(triggerSym);
      doAnalyze(triggerSym);
      onTriggerConsumed?.();
    }
  }, [triggerSym]);

  const goBack = () => {
    setShowCats(true);
    setResult(null);
    setErr("");
    setRawInput("");
    // Clear shared active stock — all tabs revert to general state
    setActiveStock(null);
    ls.set("siq_lastAnalysis", null);
    ls.set("siq_lastSentiment", null);
  };

  const addToPortfolio = () => {
    if (!result || !amount || isNaN(parseFloat(amount))) return;
    const shares = (parseFloat(amount) / result.price).toFixed(4);
    savePortfolio([
      ...getPortfolio(),
      {
        symbol: result.symbol,
        name: result.name,
        price: result.price,
        shares,
        invested: parseFloat(amount),
      },
    ]);
    setAddMsg(`✓ Added ${shares} shares of ${result.symbol}!`);
    setAmount("");
    setTimeout(() => setAddMsg(""), 3000);
  };

  const REC = {
    BUY: { color: M.gain, bg: hexAlpha(M.gain, 0.15) },
    HOLD: { color: M.gold, bg: M.goldCont },
    WAIT: { color: M.txtMid, bg: M.s3 },
  };
  const rs = REC[result?.recommendation] || REC.HOLD;
  const pred = result?.prediction;

  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
      {/* Search bar */}
      <Card style={{ padding: 20 }}>
        <Input
          value={rawInput}
          onChange={(e) => setRawInput(e.target.value)}
          onKeyDown={(e) => e.key === "Enter" && doAnalyze(rawInput)}
          placeholder="Search by name or ticker — e.g. Apple or AAPL"
        />
        <div style={{ marginTop: 12 }}>
          <FilledBtn
            label={loading ? step : "Analyze Stock"}
            onClick={() => doAnalyze(rawInput)}
            disabled={loading}
            full
            icon={loading ? "⏳" : "🔍"}
          />
        </div>
        <div
          style={{
            marginTop: 10,
            fontSize: 12,
            color: M.txtDim,
            lineHeight: 1.5,
          }}
        >
          💡{" "}
          <span style={{ color: M.txtMid }}>
            Search by company name (e.g. "Tesla") or ticker (e.g. "TSLA")
          </span>
        </div>
      </Card>

      {/* ── Beginner Stock Discovery ── */}
      {showCats && !result && !loading && !err && (
        <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
          <div
            style={{
              fontSize: 13,
              fontWeight: 700,
              color: M.txtMid,
              paddingLeft: 4,
            }}
          >
            Browse by category
          </div>
          {/* Category pills */}
          <div
            style={{
              display: "flex",
              gap: 8,
              overflowX: "auto",
              paddingBottom: 2,
            }}
          >
            {STOCK_CATS.map((cat, i) => (
              <button
                key={i}
                onClick={() => setActiveCat(i)}
                style={{
                  ...ST.chip,
                  background:
                    activeCat === i
                      ? hexAlpha(M.pri, 0.18)
                      : hexAlpha(M.txt, 0.05),
                  color: activeCat === i ? M.pri : hexAlpha(M.txt, 0.5),
                  border:
                    activeCat === i
                      ? "1px solid " + hexAlpha(M.pri, 0.45)
                      : "1px solid " + hexAlpha(M.txt, 0.08),
                  borderRadius: M.rFull,
                  padding: "0 16px",
                  height: 40,
                  boxSizing: "border-box",
                  display: "flex",
                  alignItems: "center",
                  fontSize: 12,
                  fontWeight: 700,
                  cursor: "pointer",
                  fontFamily: "inherit",
                  whiteSpace: "nowrap",
                  flexShrink: 0,
                  transition: "all .15s",
                }}
              >
                {cat.label}
              </button>
            ))}
          </div>
          {/* Stock grid for active category */}
          <Card style={{ padding: 16 }}>
            <div
              style={{
                fontSize: 11,
                color: M.pri,
                fontWeight: 700,
                textTransform: "uppercase",
                letterSpacing: 1,
                marginBottom: 12,
              }}
            >
              {STOCK_CATS[activeCat].label} — tap any to analyze
            </div>
            <div style={{ display: "flex", flexWrap: "wrap", gap: 8 }}>
              {STOCK_CATS[activeCat].stocks.map(([sym, name]) => (
                <button
                  key={sym}
                  onClick={() => {
                    setRawInput(sym);
                    doAnalyze(sym);
                  }}
                  style={{
                    background: hexAlpha(M.txt, 0.07),
                    backdropFilter: "blur(36px) saturate(160%)",
                    WebkitBackdropFilter: "blur(36px) saturate(160%)",
                    border: "1px solid " + hexAlpha(M.txt, 0.12),
                    borderRadius: M.r16,
                    padding: advanced ? "8px 14px" : "10px 14px",
                    cursor: "pointer",
                    color: hexAlpha(M.txt, 0.85),
                    fontFamily: "inherit",
                    transition: "all .15s",
                    boxShadow: "inset 0 1px 0 " + hexAlpha(M.txt, 0.1),
                    textAlign: "left",
                    minWidth: advanced ? 0 : 80,
                  }}
                  onTouchStart={(e) => {
                    e.currentTarget.style.background = hexAlpha(M.pri, 0.18);
                    e.currentTarget.style.borderColor = hexAlpha(M.pri, 0.45);
                    e.currentTarget.style.transform = "scale(0.94)";
                  }}
                  onTouchEnd={(e) => {
                    e.currentTarget.style.background = hexAlpha(M.txt, 0.07);
                    e.currentTarget.style.borderColor = hexAlpha(M.txt, 0.12);
                    e.currentTarget.style.transform = "scale(1)";
                  }}
                >
                  {advanced ? (
                    // Advanced: ticker only, monospace
                    <span
                      style={{
                        fontFamily: "'JetBrains Mono',monospace",
                        fontSize: 13,
                        fontWeight: 700,
                      }}
                    >
                      {sym}
                    </span>
                  ) : (
                    // Beginner: company name large, ticker subtext
                    <div>
                      <div style={{ fontSize: 13, fontWeight: 700 }}>
                        {name}
                      </div>
                      <div
                        style={{
                          fontSize: 10,
                          color: hexAlpha(M.txt, 0.4),
                          fontFamily: "'JetBrains Mono',monospace",
                          marginTop: 2,
                        }}
                      >
                        {sym}
                      </div>
                    </div>
                  )}
                </button>
              ))}
            </div>
          </Card>
          {/* Beginner tip */}
          <Card
            style={{
              padding: 16,
              background: hexAlpha(M.pri, 0.15),
              backdropFilter: "blur(36px) saturate(160%)",
              WebkitBackdropFilter: "blur(36px) saturate(160%)",
              boxShadow: "inset 0 1px 0 " + hexAlpha(M.txt, 0.08),
              border: "1px solid " + hexAlpha(M.pri, 0.19),
            }}
          >
            <div
              style={{
                fontSize: 12,
                color: M.pri,
                fontWeight: 700,
                marginBottom: 6,
              }}
            >
              🎓 How to use this
            </div>
            <div style={{ fontSize: 13, color: M.txtMid, lineHeight: 1.65 }}>
              Tap any stock to get a full AI analysis — what the company does,
              whether to buy or hold, the risks, and what prediction markets are
              saying. All explained in plain English.
            </div>
          </Card>
        </div>
      )}

      {/* Loading */}
      {loading && (
        <Card style={{ padding: 24 }}>
          <div
            style={{
              display: "flex",
              alignItems: "center",
              gap: 10,
              marginBottom: 20,
            }}
          >
            <div
              style={{
                backdropFilter: "blur(36px) saturate(160%)",
                WebkitBackdropFilter: "blur(36px) saturate(160%)",
                boxShadow: "inset 0 1px 0 " + hexAlpha(M.txt, 0.1),
                width: 9,
                height: 9,
                borderRadius: "50%",
                background: hexAlpha(M.pri, 0.18),
                animation: "pulse 1s infinite",
              }}
            />
            <span style={{ color: M.pri, fontSize: 14, fontWeight: 600 }}>
              {step}
            </span>
          </div>
          <Skel lines={7} />
        </Card>
      )}

      {/* Error */}
      {err && !loading && (
        <ErrorCard
          error={err}
          onRetry={() => rawInput && doAnalyze(rawInput)}
          onOpenSettings={() => {
            /* bubble to parent via context */
          }}
        />
      )}

      {/* Results */}
      {result && !loading && (
        <>
          {/* Back to browse — glass pill button matching app style */}
          <button
            onClick={goBack}
            style={{
              ...ST.chip,
              height: 40,
              padding: "0 16px",
              display: "flex",
              alignItems: "center",
              gap: 6,
              boxSizing: "border-box",
              fontWeight: 700,
              fontSize: 12,
            }}
          >
            <svg width="16" height="16" viewBox="0 0 24 24" fill="none">
              <path
                d="M19 12H5M12 5l-7 7 7 7"
                stroke={hexAlpha(M.txt, 0.7)}
                strokeWidth="2.2"
                strokeLinecap="round"
                strokeLinejoin="round"
              />
            </svg>
            Browse more stocks
          </button>

          {/* Cross-tab action bar */}
          <CrossTabBar sym={result?.symbol} currentTab="analyze" />

          {/* Hero price card — always shown from Yahoo data */}
          <Card
            style={{ padding: 20, overflow: "hidden", position: "relative" }}
          >
            <div
              style={{
                backdropFilter: "blur(36px) saturate(160%)",
                WebkitBackdropFilter: "blur(36px) saturate(160%)",
                boxShadow: "inset 0 1px 0 " + hexAlpha(M.txt, 0.1),
                position: "absolute",
                top: -40,
                right: -40,
                width: 160,
                height: 160,
                borderRadius: "50%",
                background: `radial-gradient(circle,${(result.changeP || 0) >= 0 ? M.gain : M.loss}14 0%,transparent 70%)`,
                pointerEvents: "none",
              }}
            />
            <div
              style={{
                display: "flex",
                justifyContent: "space-between",
                alignItems: "flex-start",
                position: "relative",
              }}
            >
              <div style={{ flex: 1, minWidth: 0, paddingRight: 12 }}>
                <div
                  style={{
                    fontFamily: "'JetBrains Mono',monospace",
                    fontSize: 26,
                    fontWeight: 900,
                    color: M.txt,
                  }}
                >
                  {result.symbol}
                </div>
                <div style={{ fontSize: 13, color: M.txtMid, marginTop: 3 }}>
                  {result.name}
                </div>
                {result.exchange && (
                  <div
                    style={{
                      display: "inline-block",
                      background: hexAlpha(M.pri, 0.12),
                      backdropFilter: "blur(36px) saturate(160%)",
                      WebkitBackdropFilter: "blur(36px) saturate(160%)",
                      boxShadow: "inset 0 1px 0 " + hexAlpha(M.txt, 0.08),
                      border: "1px solid " + hexAlpha(M.pri, 0.2),
                      borderRadius: M.rFull,
                      padding: "3px 10px",
                      marginTop: 6,
                    }}
                  >
                    <span style={{ fontSize: 10, color: M.pri }}>
                      {result.exchange} · {result.currency || "USD"}
                    </span>
                  </div>
                )}
              </div>
              <div style={{ textAlign: "right", flexShrink: 0 }}>
                <div
                  style={{
                    fontFamily: "'JetBrains Mono',monospace",
                    fontSize: 26,
                    fontWeight: 900,
                    color: M.txt,
                  }}
                >
                  ${result.price?.toFixed(2) || "--"}
                </div>
                <div
                  style={{
                    fontFamily: "monospace",
                    fontSize: 13,
                    fontWeight: 700,
                    color: (result.changeP || 0) >= 0 ? M.gain : M.loss,
                  }}
                >
                  {(result.changeP || 0) >= 0 ? "▲" : "▼"}{" "}
                  {Math.abs(result.changeP || 0).toFixed(2)}%
                </div>
                {result.chartPoints && (
                  <Spark pos={(result.changeP || 0) >= 0} />
                )}
              </div>
            </div>
            <div
              style={{
                display: "grid",
                gridTemplateColumns: "1fr 1fr 1fr",
                gap: 8,
                marginTop: 16,
              }}
            >
              {[
                [
                  "Mkt Cap",
                  result.aiAnalysis?.marketCap ||
                    result.marketCap ||
                    "Loading…",
                  M.pri,
                ],
                [
                  "52W High",
                  result.high52 ? `$${result.high52.toFixed(2)}` : "N/A",
                  M.gain,
                ],
                [
                  "52W Low",
                  result.low52 ? `$${result.low52.toFixed(2)}` : "N/A",
                  M.loss,
                ],
              ].map(([l, v, c]) => (
                <div
                  key={l}
                  style={{
                    ...ST.card,
                    borderRadius: M.r12,
                    padding: "10px 14px",
                  }}
                >
                  <div
                    style={{
                      fontSize: 9,
                      color: M.txtDim,
                      textTransform: "uppercase",
                      letterSpacing: 1,
                    }}
                  >
                    {l}
                  </div>
                  <div
                    style={{
                      fontFamily: "monospace",
                      fontWeight: 800,
                      color: c,
                      fontSize: 13,
                      marginTop: 3,
                    }}
                  >
                    {v}
                  </div>
                </div>
              ))}
            </div>
          </Card>

          {/* AI Analysis expand — shows if no AI analysis yet */}
          {!result.aiAnalysis && !aiLoading && (
            <div style={{ display: "flex", gap: 10, alignItems: "center" }}>
              {hasAIConfigured(settings) ? (
                <button
                  onClick={doAIAnalysis}
                  style={{
                    flex: 1,
                    background: `linear-gradient(135deg,${hexAlpha(M.pri, 0.15)},${hexAlpha(M.pri, 0.08)})`,
                    border: "1px solid " + hexAlpha(M.pri, 0.3),
                    backdropFilter: "blur(16px)",
                    borderRadius: M.r16,
                    padding: "14px 16px",
                    cursor: "pointer",
                    fontFamily: "inherit",
                    textAlign: "left",
                    display: "flex",
                    alignItems: "center",
                    gap: 12,
                  }}
                >
                  <div style={{ fontSize: 24 }}>🧠</div>
                  <div>
                    <div
                      style={{ fontSize: 14, fontWeight: 700, color: M.pri }}
                    >
                      Get AI Analysis
                    </div>
                    <div
                      style={{ fontSize: 12, color: M.txtMid, marginTop: 2 }}
                    >
                      Deep analysis, recommendation, prediction signals
                    </div>
                  </div>
                  <svg
                    width="16"
                    height="16"
                    viewBox="0 0 24 24"
                    fill="none"
                    style={{ marginLeft: "auto", flexShrink: 0 }}
                  >
                    <path
                      d="M9 18l6-6-6-6"
                      stroke={M.pri}
                      strokeWidth="2.2"
                      strokeLinecap="round"
                    />
                  </svg>
                </button>
              ) : (
                <NoAIBanner
                  onSettings={() => {}}
                  label="Set up an AI provider to get deep analysis, recommendations & predictions"
                />
              )}
            </div>
          )}
          {aiLoading && (
            <Card style={{ padding: 20 }}>
              <div
                style={{
                  display: "flex",
                  alignItems: "center",
                  gap: 10,
                  marginBottom: 16,
                }}
              >
                <div
                  style={{
                    backdropFilter: "blur(36px) saturate(160%)",
                    WebkitBackdropFilter: "blur(36px) saturate(160%)",
                    boxShadow: "inset 0 1px 0 " + hexAlpha(M.txt, 0.1),
                    width: 8,
                    height: 8,
                    borderRadius: "50%",
                    background: hexAlpha(M.pri, 0.18),
                    animation: "pulse 1s infinite",
                  }}
                />
                <span style={{ color: M.pri, fontSize: 14, fontWeight: 600 }}>
                  {aiStep}
                </span>
              </div>
              <Skel lines={5} />
            </Card>
          )}
          {aiErr && !aiLoading && (
            <ErrorCard
              error={aiErr}
              onRetry={doAIAnalysis}
              onOpenSettings={() => {}}
            />
          )}

          {/* AI Analysis sections — only shown when AI has run */}
          {result.aiAnalysis && (
            <>
              <Card style={{ padding: 20 }}>
                <div
                  style={{
                    fontSize: 11,
                    color: M.pri,
                    fontWeight: 700,
                    textTransform: "uppercase",
                    letterSpacing: 1,
                    marginBottom: 10,
                  }}
                >
                  What does this company do?
                </div>
                <div style={{ fontSize: 14, color: M.txt, lineHeight: 1.75 }}>
                  {result.summary}
                </div>
                {result.priceMovement && (
                  <div
                    style={{
                      marginTop: 14,
                      paddingTop: 14,
                      borderTop: "1px solid " + M.outlineDim,
                      fontSize: 13,
                      color: M.txtMid,
                      lineHeight: 1.65,
                    }}
                  >
                    📊 {result.priceMovement}
                  </div>
                )}
              </Card>

              <Card
                style={{
                  padding: 20,
                  background: rs.bg,
                  backdropFilter: "blur(36px) saturate(160%)",
                  WebkitBackdropFilter: "blur(36px) saturate(160%)",
                  boxShadow: "inset 0 1px 0 " + hexAlpha(M.txt, 0.08),
                  border: "1.5px solid " + rs.color + "50",
                }}
              >
                <div
                  style={{ display: "flex", gap: 12, alignItems: "flex-start" }}
                >
                  <div
                    style={{
                      backdropFilter: "blur(36px) saturate(160%)",
                      WebkitBackdropFilter: "blur(36px) saturate(160%)",
                      boxShadow: "inset 0 1px 0 " + hexAlpha(M.txt, 0.1),
                      background: rs.color,
                      color: M.bg,
                      borderRadius: M.r12,
                      padding: "6px 16px",
                      fontWeight: 900,
                      fontSize: 14,
                      flexShrink: 0,
                    }}
                  >
                    {result.recommendation}
                  </div>
                  <div style={{ fontSize: 14, color: M.txt, lineHeight: 1.7 }}>
                    {result.recommendationReason}
                  </div>
                </div>
              </Card>

              {/* 🔮 Prediction Market Signals */}
              {pred && (
                <Card
                  style={{
                    padding: 20,
                    background: `${M.secCont}`,
                    backdropFilter: "blur(36px) saturate(160%)",
                    WebkitBackdropFilter: "blur(36px) saturate(160%)",
                    boxShadow: "inset 0 1px 0 " + hexAlpha(M.txt, 0.08),
                    border: "1px solid " + hexAlpha(M.sec, 0.25),
                  }}
                >
                  <div
                    style={{
                      fontSize: 11,
                      color: M.sec,
                      fontWeight: 700,
                      textTransform: "uppercase",
                      letterSpacing: 1,
                      marginBottom: 14,
                    }}
                  >
                    🔮 Prediction Market Signals
                  </div>
                  {/* Bull/Bear bar */}
                  <div style={{ marginBottom: 14 }}>
                    <div
                      style={{
                        display: "flex",
                        justifyContent: "space-between",
                        marginBottom: 6,
                      }}
                    >
                      <span
                        style={{ fontSize: 12, color: M.gain, fontWeight: 700 }}
                      >
                        🐂 Bullish {pred.bullPercent}%
                      </span>
                      <span
                        style={{ fontSize: 12, color: M.loss, fontWeight: 700 }}
                      >
                        {pred.bearPercent}% Bearish 🐻
                      </span>
                    </div>
                    <div
                      style={{
                        backdropFilter: "blur(36px) saturate(160%)",
                        WebkitBackdropFilter: "blur(36px) saturate(160%)",
                        boxShadow: "inset 0 1px 0 " + hexAlpha(M.txt, 0.1),
                        height: 8,
                        background: hexAlpha(M.txt, 0.06),
                        borderRadius: M.rFull,
                        overflow: "hidden",
                      }}
                    >
                      <div
                        style={{
                          backdropFilter: "blur(36px) saturate(160%)",
                          WebkitBackdropFilter: "blur(36px) saturate(160%)",
                          boxShadow: "inset 0 1px 0 " + hexAlpha(M.txt, 0.1),
                          height: "100%",
                          width: `${pred.bullPercent}%`,
                          background: `linear-gradient(90deg,${M.gain},${M.gain}90)`,
                          borderRadius: M.rFull,
                          transition: "width 1s ease",
                        }}
                      />
                    </div>
                    <div style={{ marginTop: 8, textAlign: "center" }}>
                      <span
                        style={{
                          fontSize: 13,
                          fontWeight: 700,
                          color: pred.bullPercent > 50 ? M.gain : M.loss,
                        }}
                      >
                        {pred.signal}
                      </span>
                    </div>
                  </div>
                  <div
                    style={{
                      fontSize: 13,
                      color: M.txtMid,
                      lineHeight: 1.65,
                      marginBottom: 12,
                    }}
                  >
                    {pred.reason}
                  </div>
                  {pred.analystTarget && (
                    <div style={{ display: "flex", gap: 10 }}>
                      <div
                        style={{
                          backdropFilter: "blur(36px) saturate(160%)",
                          WebkitBackdropFilter: "blur(36px) saturate(160%)",
                          boxShadow: "inset 0 1px 0 " + hexAlpha(M.txt, 0.1),
                          flex: 1,
                          background: hexAlpha(M.txt, 0.06),
                          borderRadius: M.r12,
                          padding: "10px 14px",
                        }}
                      >
                        <div style={{ fontSize: 10, color: M.txtDim }}>
                          ANALYST TARGET
                        </div>
                        <div
                          style={{
                            fontFamily: "monospace",
                            fontWeight: 800,
                            color: M.gold,
                            fontSize: 15,
                            marginTop: 3,
                          }}
                        >
                          {pred.analystTarget}
                        </div>
                      </div>
                      {pred.upside && (
                        <div
                          style={{
                            backdropFilter: "blur(36px) saturate(160%)",
                            WebkitBackdropFilter: "blur(36px) saturate(160%)",
                            boxShadow: "inset 0 1px 0 " + hexAlpha(M.txt, 0.1),
                            flex: 1,
                            background: hexAlpha(M.txt, 0.06),
                            borderRadius: M.r12,
                            padding: "10px 14px",
                          }}
                        >
                          <div style={{ fontSize: 10, color: M.txtDim }}>
                            POTENTIAL UPSIDE
                          </div>
                          <div
                            style={{
                              fontFamily: "monospace",
                              fontWeight: 800,
                              color: M.gain,
                              fontSize: 15,
                              marginTop: 3,
                            }}
                          >
                            {pred.upside}
                          </div>
                        </div>
                      )}
                    </div>
                  )}
                </Card>
              )}

              {/* Pros / Cons */}
              <div
                style={{
                  display: "grid",
                  gridTemplateColumns: "1fr 1fr",
                  gap: 12,
                }}
              >
                {[
                  ["✅ Pros", result.pros, M.gain, hexAlpha(M.gain, 0.15)],
                  ["⚠️ Risks", result.cons, M.loss, hexAlpha(M.loss, 0.15)],
                ].map(([title, items, color, bg]) => (
                  <Card
                    key={title}
                    style={{
                      padding: 16,
                      background: bg,
                      backdropFilter: "blur(36px) saturate(160%)",
                      WebkitBackdropFilter: "blur(36px) saturate(160%)",
                      boxShadow: "inset 0 1px 0 " + hexAlpha(M.txt, 0.08),
                      border: "1px solid " + color + "30",
                    }}
                  >
                    <div
                      style={{
                        fontSize: 11,
                        color,
                        fontWeight: 700,
                        textTransform: "uppercase",
                        letterSpacing: 1,
                        marginBottom: 10,
                      }}
                    >
                      {title}
                    </div>
                    {(items || []).map((item, i) => (
                      <div
                        key={i}
                        style={{
                          fontSize: 12,
                          color: M.txt,
                          marginBottom: 7,
                          display: "flex",
                          gap: 7,
                          lineHeight: 1.5,
                        }}
                      >
                        <span style={{ color, flexShrink: 0 }}>•</span>
                        {item}
                      </div>
                    ))}
                  </Card>
                ))}
              </div>

              {/* Advanced note */}
              {advanced && result.advancedNote && (
                <Card
                  style={{
                    padding: 18,
                    background: hexAlpha(M.gold, 0.15),
                    backdropFilter: "blur(36px) saturate(160%)",
                    WebkitBackdropFilter: "blur(36px) saturate(160%)",
                    boxShadow: "inset 0 1px 0 " + hexAlpha(M.txt, 0.08),
                    border: "1px solid " + hexAlpha(M.gold, 0.25),
                  }}
                >
                  <div
                    style={{
                      fontSize: 11,
                      color: M.gold,
                      fontWeight: 700,
                      marginBottom: 8,
                    }}
                  >
                    🔬 ADVANCED METRICS
                  </div>
                  <div style={{ fontSize: 13, color: M.txt, lineHeight: 1.7 }}>
                    {result.advancedNote}
                  </div>
                </Card>
              )}

              {/* Paper trade */}
              <Card style={{ padding: 20 }}>
                <div
                  style={{
                    fontSize: 13,
                    fontWeight: 700,
                    color: M.txtMid,
                    marginBottom: 14,
                  }}
                >
                  📝 Paper Trade — practice without real money
                </div>
                <Input
                  label="Amount ($)"
                  type="number"
                  value={amount}
                  onChange={(e) => setAmount(e.target.value)}
                  placeholder="e.g. 500"
                />
                {amount && result.price && (
                  <div
                    style={{
                      fontSize: 12,
                      color: M.txtDim,
                      margin: "8px 0 4px",
                    }}
                  >
                    ≈ {(parseFloat(amount) / result.price).toFixed(4)} shares of{" "}
                    {result.symbol}
                  </div>
                )}
                <div style={{ marginTop: 12 }}>
                  <TonalBtn
                    label="+ Add to Portfolio"
                    onClick={addToPortfolio}
                    full
                    color={M.gain}
                    bg={hexAlpha(M.gain, 0.15)}
                  />
                </div>
                {addMsg && (
                  <div
                    style={{
                      color: M.gain,
                      fontSize: 13,
                      marginTop: 10,
                      fontWeight: 700,
                    }}
                  >
                    {addMsg}
                  </div>
                )}
              </Card>

              {/* Sources */}
              {result.sources && result.sources.length > 0 && (
                <SourcesCard sources={result.sources} advanced={advanced} />
              )}
            </> /* end aiAnalysis sections */
          )}

          {/* Disclaimer */}
          <div
            style={{
              fontSize: 11,
              color: M.txtDim,
              textAlign: "center",
              lineHeight: 1.6,
              paddingBottom: 4,
            }}
          >
            ⚠️ This is not financial advice. Always do your own research before
            investing real money.
          </div>
        </>
      )}
    </div>
  );
}

// ─── Advisor Screen (pinned input) ────────────────────────────────

export default AnalyzeScreen;
