import { useState, useEffect } from 'react';
import { M, mc } from '../theme/buildM';
import { ST } from '../theme/styles';
import { hexAlpha } from '../theme/colorUtils';
import { fetchLivePrice } from '../api/yahoo';
import { useTickerData, updateTicker } from '../hooks/useTickerData';
import Spark from './ui/Spark';
function TickerToast({ sym, onClose }) {
  useEffect(() => {
    const t = setTimeout(onClose, 1800);
    return () => clearTimeout(t);
  }, []);
  return (
    <div
      style={{
        ...ST.chip,
        padding: "4px 10px",
        display: "flex",
        alignItems: "center",
        gap: 4,
      }}
    >
      <div
        style={{
          backdropFilter: "blur(36px) saturate(160%)",
          WebkitBackdropFilter: "blur(36px) saturate(160%)",
          boxShadow: "inset 0 1px 0 " + hexAlpha(M.txt, 0.1),
          width: 8,
          height: 8,
          borderRadius: "50%",
          background: hexAlpha(M.pri, 0.18),
          animation: "pulse 1s infinite",
        }}
      />
      <span
        style={{
          fontSize: 13,
          color: M.txt,
          fontFamily: "'JetBrains Mono',monospace",
          fontWeight: 700,
        }}
      >
        {sym}
      </span>
      <span style={{ fontSize: 12, color: M.txtMid }}>
        Loading full analysis…
      </span>
    </div>
  );
}

// ─── Ticker Banner — live prices ─────────────────────────────────
function TickerBanner({ onTickerTap }) {
  const tickers = useTickerData();
  // Kick off live fetch on first render
  useEffect(() => {
    fetchAllTickers();
  }, []);
  const doubled = [...tickers, ...tickers];
  return (
    <div
      style={{
        overflow: "hidden",
        height: 28,
        display: "flex",
        alignItems: "center",
        ...ST.tickerBar,
      }}
    >
      <div
        style={{
          display: "flex",
          gap: 0,
          animation: "marquee 48s linear infinite",
          whiteSpace: "nowrap",
        }}
      >
        {doubled.map((item, i) => (
          <button
            key={i}
            onClick={() => onTickerTap(item.sym)}
            style={{
              ...ST.btnGhost,
              background: "transparent",
              border: "none",
              cursor: "pointer",
              padding: "0 14px",
              display: "inline-flex",
              alignItems: "center",
              gap: 5,
              height: 28,
              transition: "background .15s",
            }}
            onMouseEnter={(e) =>
              (e.currentTarget.style.background = hexAlpha(M.txt, 0.06))
            }
            onMouseLeave={(e) =>
              (e.currentTarget.style.background = "transparent")
            }
          >
            <span
              style={{
                fontSize: 11,
                fontFamily: "'JetBrains Mono',monospace",
                color: hexAlpha(M.txt, 0.55),
                fontWeight: 700,
              }}
            >
              {item.sym}
            </span>
            <span
              style={{
                fontSize: 11,
                fontFamily: "monospace",
                color: item.changeP >= 0 ? M.gain : M.loss,
              }}
            >
              {item.live ? (
                <>
                  {item.changeP >= 0 ? "▲" : "▼"}
                  {Math.abs(item.changeP).toFixed(2)}%
                </>
              ) : (
                <span style={{ color: hexAlpha(M.txt, 0.25) }}>—</span>
              )}
            </span>
          </button>
        ))}
      </div>
    </div>
  );
}

// ─── Quiz Screen ──────────────────────────────────────────────────
export { TickerToast };
export default TickerBanner;
