// ─── Guided Progress Card ─────────────────────────────────────────────────────
function GuidedProgressCard({ progress, pinned, onContinue, onSkip }) {
  const { phase, completed } = progress;
  const path = phase === "advanced" ? GUIDED_ADVANCED : GUIDED_BEGINNER;
  const allPath = [...GUIDED_BEGINNER, ...GUIDED_ADVANCED];
  const done = completed.filter((k) => path.includes(k)).length;
  const total = path.length;
  const pct = Math.round((done / total) * 100);
  const next = path.find((k) => !completed.includes(k));
  const nextTopic = next ? LEARN_TOPICS.find((t) => t.key === next) : null;

  // overall pill across both phases
  const totalDone = completed.filter((k) => allPath.includes(k)).length;
  const totalAll = allPath.length;

  return (
    <Card
      style={{
        padding: 18,
        background: hexAlpha(M.pri, 0.07),
        border: "1px solid " + hexAlpha(M.pri, 0.22),
        marginBottom: 4,
      }}
    >
      {/* Header row */}
      <div
        style={{
          display: "flex",
          alignItems: "center",
          justifyContent: "space-between",
          marginBottom: 12,
        }}
      >
        <div style={{ display: "flex", alignItems: "center", gap: 8 }}>
          <span style={{ fontSize: 18 }}>
            {phase === "advanced" ? "🚀" : "🎓"}
          </span>
          <div>
            <div style={{ fontSize: 13, fontWeight: 800, color: M.txt }}>
              {phase === "advanced" ? "Advanced Path" : "Beginner Path"}
            </div>
            <div style={{ fontSize: 11, color: hexAlpha(M.txt, 0.45) }}>
              {done}/{total} topics · {pct}% complete
            </div>
          </div>
        </div>
        {/* overall across both paths pill */}
        <div
          style={{
            ...ST.chip,
            padding: "4px 10px",
            background: hexAlpha(M.pri, 0.12),
            border: "1px solid " + hexAlpha(M.pri, 0.25),
            fontSize: 11,
            fontWeight: 700,
            color: M.pri,
          }}
        >
          {totalDone}/{totalAll} total
        </div>
      </div>

      {/* Progress bar */}
      <div
        style={{
          width: "100%",
          height: 7,
          borderRadius: M.rFull,
          background: hexAlpha(M.txt, 0.08),
          overflow: "hidden",
          marginBottom: 14,
        }}
      >
        <div
          style={{
            height: "100%",
            width: pct + "%",
            borderRadius: M.rFull,
            background: `linear-gradient(90deg,${hexAlpha(M.pri, 0.85)},${M.pri})`,
            transition: "width .4s ease",
          }}
        />
      </div>

      {/* Next topic row */}
      {nextTopic ? (
        <div style={{ display: "flex", gap: 10, alignItems: "center" }}>
          <button
            onClick={() => onContinue(nextTopic)}
            style={{
              ...ST.btnFilled,
              flex: 1,
              background: hexAlpha(M.pri, 0.88),
              color: M.onPri,
              borderRadius: M.r12,
              padding: "11px 16px",
              fontSize: 13,
              fontFamily: "inherit",
              cursor: "pointer",
              display: "flex",
              alignItems: "center",
              gap: 8,
              boxShadow: "0 2px 12px " + hexAlpha(M.pri, 0.28),
            }}
          >
            <span style={{ fontSize: 18 }}>{nextTopic.icon}</span>
            <span style={{ flex: 1, textAlign: "left", fontWeight: 700 }}>
              {nextTopic.title}
            </span>
            <span style={{ fontSize: 12, opacity: 0.75 }}>▶</span>
          </button>
          {pinned && (
            <button
              onClick={onSkip}
              style={{
                background: "transparent",
                border: "1px solid " + hexAlpha(M.txt, 0.12),
                borderRadius: M.r12,
                padding: "11px 14px",
                cursor: "pointer",
                color: hexAlpha(M.txt, 0.4),
                fontSize: 11,
                fontFamily: "inherit",
              }}
            >
              Skip
            </button>
          )}
        </div>
      ) : (
        <div
          style={{
            fontSize: 13,
            color: M.pri,
            fontWeight: 700,
            textAlign: "center",
            padding: "4px 0",
          }}
        >
          ✅ All {phase} topics complete!
        </div>
      )}
    </Card>
  );
}
export { CongratsModal, GuidedProgressCard };
