// ─── Friendly AI error parser ─────────────────────────────────────
function parseAIError(err) {
  const raw = (err?.message || String(err || "")).toLowerCase();
  if (
    raw.includes("529") ||
    raw.includes("overloaded") ||
    raw.includes("rate") ||
    raw.includes("capacity")
  )
    return {
      icon: "⏳",
      title: "AI is busy right now",
      body: "The AI service has too many requests at the moment. Wait 30 seconds and try again — it's usually quick to recover.",
      action: "Try Again",
    };
  if (
    raw.includes("401") ||
    raw.includes("unauthorized") ||
    raw.includes("api key") ||
    raw.includes("authentication")
  )
    return {
      icon: "🔑",
      title: "API key issue",
      body: "Your API key looks incorrect or has expired. Go to ⚙️ Settings to check or update it.",
      action: "Open Settings",
    };
  if (
    raw.includes("402") ||
    raw.includes("billing") ||
    raw.includes("credits") ||
    raw.includes("quota") ||
    raw.includes("limit")
  )
    return {
      icon: "💳",
      title: "Usage limit reached",
      body: "You've run out of AI credits for now. Either wait for your limit to reset, or add a free Groq or Gemini key in ⚙️ Settings — both are free.",
      action: "Open Settings",
    };
  if (
    raw.includes("network") ||
    raw.includes("fetch") ||
    raw.includes("failed to fetch") ||
    raw.includes("cors")
  )
    return {
      icon: "📡",
      title: "No internet connection",
      body: "obol can't reach the AI service. Check your connection and try again.",
      action: "Try Again",
    };
  if (raw.includes("json") || raw.includes("parse") || raw.includes("syntax"))
    return {
      icon: "🔄",
      title: "Unexpected response",
      body: "The AI returned something unexpected. This sometimes happens — just try again.",
      action: "Try Again",
    };
  return {
    icon: "⚠️",
    title: "Something went wrong",
    body: "An unexpected error occurred. Please try again in a moment.",
    action: "Try Again",
  };
}

