// ─── Multi-provider AI ────────────────────────────────────────────
const ANTHROPIC_API = "https://api.anthropic.com/v1/messages";

const OAI_ENDPOINTS = {
  groq: "https://api.groq.com/openai/v1/chat/completions",
  openai: "https://api.openai.com/v1/chat/completions",
  together: "https://api.together.xyz/v1/chat/completions",
  mistral: "https://api.mistral.ai/v1/chat/completions",
  perplexity: "https://api.perplexity.ai/chat/completions",
};
const OAI_MODELS = {
  groq: "llama-3.3-70b-versatile",
  openai: "gpt-4o-mini",
  together: "meta-llama/Llama-3-70b-chat-hf",
  mistral: "mistral-small-latest",
  perplexity: "llama-3.1-sonar-large-128k-online",
};

async function callAI(messages, system = "", settings = {}, useSearch = false) {
  const provider = settings.aiProvider || "anthropic";
  const keys = settings.apiKeys || {};

  // OpenAI-compatible providers
  if (OAI_ENDPOINTS[provider]) {
    const apiKey = keys[provider];
    if (!apiKey)
      throw new Error(`No API key for ${provider}. Add it in Settings.`);
    const res = await fetch(OAI_ENDPOINTS[provider], {
      method: "POST",
      headers: {
        "Content-Type": "application/json",
        Authorization: `Bearer ${apiKey}`,
      },
      body: JSON.stringify({
        model: OAI_MODELS[provider],
        max_tokens: 1000,
        messages: [
          ...(system ? [{ role: "system", content: system }] : []),
          ...messages,
        ],
      }),
    });
    const d = await res.json();
    if (d.error) throw new Error(d.error.message);
    return d.choices?.[0]?.message?.content || "";
  }

  // Google Gemini
  if (provider === "gemini") {
    const apiKey = keys.gemini;
    if (!apiKey) throw new Error("No Gemini API key. Add it in Settings.");
    const res = await fetch(
      `https://generativelanguage.googleapis.com/v1beta/models/gemini-1.5-flash:generateContent?key=${apiKey}`,
      {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          contents: messages.map((m) => ({
            role: m.role === "assistant" ? "model" : "user",
            parts: [{ text: m.content }],
          })),
          ...(system
            ? { systemInstruction: { parts: [{ text: system }] } }
            : {}),
        }),
      },
    );
    const d = await res.json();
    if (d.error) throw new Error(d.error.message);
    return d.candidates?.[0]?.content?.parts?.[0]?.text || "";
  }

  // Anthropic (default — no key needed in artifact)
  const body = {
    model: "claude-sonnet-4-20250514",
    max_tokens: 1000,
    ...(system ? { system } : {}),
    messages,
  };
  if (useSearch)
    body.tools = [{ type: "web_search_20250305", name: "web_search" }];
  const extraHeaders = keys.anthropic
    ? { "x-api-key": keys.anthropic, "anthropic-version": "2023-06-01" }
    : {};
  const res = await fetch(ANTHROPIC_API, {
    method: "POST",
    headers: { "Content-Type": "application/json", ...extraHeaders },
    body: JSON.stringify(body),
  });
  const d = await res.json();
  if (d.error) throw new Error(d.error.message || JSON.stringify(d.error));
  return (d.content || [])
    .map((b) => b.text || "")
    .filter(Boolean)
    .join("\n");
}

// ─── Check if AI is configured ───────────────────────────────────
function hasAIConfigured(settings) {
  if (!settings) return false;
  const provider = settings.aiProvider || "anthropic";
  // Anthropic works by default in claude.ai context
  if (provider === "anthropic" && !settings.apiKeys?.anthropic) return true;
  return !!settings.apiKeys?.[provider];
}
export { parseAIError, callAI, hasAIConfigured };
