const getLevel = (xp) =>
  [...INVESTOR_LEVELS].reverse().find((l) => xp >= l.min) || INVESTOR_LEVELS[0];
const xpToNext = (xp) => {
  const i = INVESTOR_LEVELS.findIndex((l) => l.min > xp);
  return i === -1 ? null : INVESTOR_LEVELS[i];
};

