import { useState, useEffect, useRef } from 'react';
import { M, setM } from './theme/buildM';
import { buildM, readAndroidColors } from './theme/monet';
import { hexToRgb, hexAlpha } from './theme/colorUtils';
import { ST } from './theme/styles';
import { ls } from './utils/storage';
import { AppContext } from './context/AppContext';
import { SettingsContext, DEFAULT_SETTINGS } from './context/SettingsContext';
import useWindowSize from './hooks/useWindowSize';
import ObolLogo from './components/ui/ObolLogo';
import { Card, FilledBtn, TonalBtn } from './components/ui';
import TickerBanner from './components/TickerBanner';
import WelcomeJourney  from './screens/WelcomeJourney';
import QuizScreen      from './screens/QuizScreen';
import AnalyzeScreen   from './screens/AnalyzeScreen';
import AdvisorScreen   from './screens/AdvisorScreen';
import PortfolioScreen from './screens/PortfolioScreen';
import LearnScreen     from './screens/LearnScreen';
import SettingsScreen  from './screens/SettingsScreen';
import PolicySheet     from './screens/PolicySheet';
import { SourcesCard } from './screens/PolicySheet';
import { DEFAULT_XP } from "./data/levels";
import { POLICY_VERSION } from "./screens/WelcomeJourney";



// ─── Nav Tab Config ───────────────────────────────────────────────
const NAV_TABS = [
  { id: "analyze", icon: "📊", label: "Analyze" },
  { id: "advisor", icon: "🤖", label: "Advisor" },
  { id: "markets", icon: "📡", label: "Markets" },
  { id: "portfolio", icon: "💼", label: "Portfolio" },
  { id: "learn", icon: "🎓", label: "Learn" },
];

// ─── Floating Pill Nav — accurate Oura Ring style ────────────────
const NAV_H = 84;

function FloatingNav({ tab, setTab }) {
  return (
    <div
      style={{
        position: "fixed",
        bottom: `calc(16px + env(safe-area-inset-bottom, 0px))`,
        left: "50%",
        transform: "translateX(-50%)",
        width: "calc(100% - 44px)",
        maxWidth: 390,
        zIndex: 100,
        display: "flex",
        alignItems: "center",
        padding: "6px 8px",
        borderRadius: "999px",
        ...ST.navPill,
      }}
    >
      {NAV_TABS.map((t) => {
        const active = tab === t.id;
        return (
          <button
            key={t.id}
            onClick={() => setTab(t.id)}
            style={{
              flex: 1,
              border: "none",
              background: "transparent",
              cursor: "pointer",
              fontFamily: "inherit",
              display: "flex",
              flexDirection: "column",
              alignItems: "center",
              justifyContent: "center",
              gap: 4,
              padding: "2px 4px",
              borderRadius: "999px",
              WebkitTapHighlightColor: "transparent",
              transition: "transform .14s cubic-bezier(0.34,1.56,0.64,1)",
            }}
            onTouchStart={(e) => {
              e.currentTarget.style.transform = "scale(0.87)";
            }}
            onTouchEnd={(e) => {
              e.currentTarget.style.transform = "scale(1)";
            }}
          >
            {/* Active = slightly raised dark capsule, NOT bright */}
            <div
              style={{
                width: active ? 62 : 40,
                height: 38,
                borderRadius: "999px",
                // Oura active: just a touch lighter than the pill itself
                ...(active
                  ? ST.navTabActive
                  : {
                      background: "transparent",
                      border: "1px solid transparent",
                      boxShadow: "none",
                    }),
                display: "flex",
                alignItems: "center",
                justifyContent: "center",
                transition: "all .26s cubic-bezier(0.34,1.56,0.64,1)",
              }}
            >
              <span
                style={{
                  fontSize: 20,
                  lineHeight: 1,
                  // Active stays full color; inactive dims
                  filter: active ? "none" : "grayscale(60%) opacity(0.35)",
                  transition: "all .2s",
                }}
              >
                {t.icon}
              </span>
            </div>

            {/* Label */}
            <span
              style={{
                fontSize: 10,
                fontWeight: active ? 700 : 400,
                color: active ? M.onPri : hexAlpha(M.txt, 0.35),
                letterSpacing: 0.2,
                transition: "all .2s",
                lineHeight: 1,
                paddingBottom: 1,
              }}
            >
              {t.label}
            </span>
          </button>
        );
      })}
    </div>
  );
}

// ─── Paper Plane Send Icon ────────────────────────────────────────
function SendIcon({ size = 22, color = "M.bg" }) {
  return (
    <svg width={size} height={size} viewBox="0 0 24 24" fill="none">
      <path
        d="M22 2L11 13"
        stroke={color}
        strokeWidth="2.2"
        strokeLinecap="round"
        strokeLinejoin="round"
      />
      <path
        d="M22 2L15 22L11 13L2 9L22 2Z"
        stroke={color}
        strokeWidth="2.2"
        strokeLinecap="round"
        strokeLinejoin="round"
      />
    </svg>
  );
}

// ─── Root App ─────────────────────────────────────────────────────
export default function App() {
  // --- 1. THEME STATE (Monet Restoration) ---
  const [themeM, setThemeM] = useState(() => buildM(null));

  // CRITICAL: Update the global M reference so ST getters use the new colors
  setM(themeM);

  // --- 2. REGULAR STATE HOOKS ---
  const [risk, setRisk] = useState(() => ls.get("siq_risk", null));
  const [advanced, setAdvanced] = useState(() => ls.get("siq_advanced", false));
  const [tab, setTab] = useState("analyze");
  const [xpData, setXpData] = useState(() => ls.get("siq_xp", DEFAULT_XP));
  const [xpToast, setXpToast] = useState(null);
  const [onboarded, setOnboarded] = useState(
    () => !!ls.get("siq_onboarded", false),
  );
  const [policiesAccepted, setPoliciesAccepted] = useState(
    () => ls.get("siq_policies_accepted") === POLICY_VERSION,
  );

  const [settings, setSettings] = useState(() =>
    ls.get("siq_settings", DEFAULT_SETTINGS),
  );
  const [showSettings, setShowSettings] = useState(false);
  const [policySheet, setPolicySheet] = useState(null);
  const [triggerSym, setTriggerSym] = useState(null);
  const [marketsInitialSub, setMarketsInitialSub] = useState(null);
  const [toastSym, setToastSym] = useState(null);
  const [activeStock, setActiveStock] = useState(null);
  const [scrolled, setScrolled] = useState(false);
  const [kbOpen, setKbOpen] = useState(false);
  const [isRetakingRisk, setIsRetakingRisk] = useState(false);

  const { w: winW } = useWindowSize();
  const layout = winW > 1024 ? "desktop" : winW >= 600 ? "tablet" : "mobile";

  // --- 3. EFFECTS ---
  // A. Android Monet Integration
  useEffect(() => {
    const androidColors = readAndroidColors();
    if (androidColors) {
      setThemeM(buildM(androidColors));
    }
  }, []);

  // B. Keyboard Awareness
  useEffect(() => {
    const onResize = () => {
      if (window.visualViewport) {
        setKbOpen(window.visualViewport.height < window.innerHeight * 0.85);
      }
    };
    window.visualViewport?.addEventListener("resize", onResize);
    return () => window.visualViewport?.removeEventListener("resize", onResize);
  }, []);

  // --- 4. HANDLERS ---
  const onScroll = (e) => setScrolled(e.target.scrollTop > 10);

  const navigate = (toTab, withSym, sub) => {
    setTab(toTab);
    if (withSym) setTriggerSym(withSym);
    if (sub) setMarketsInitialSub(sub);
    if (toTab === "analyze" && withSym) setToastSym(withSym);
  };

  const handleTickerTap = (sym) => navigate("analyze", sym);

  const earnXp = (amt, label) => {
    const next = { ...xpData, xp: xpData.xp + amt };
    setXpData(next);
    ls.set("siq_xp", next);
    setXpToast({ xp: amt, label });
  };

  const appCtx = { activeStock, setActiveStock, navigate, earnXp };

  // --- 5. CONDITIONALS ---
  const isNewUser = !policiesAccepted || !onboarded;
  const isAdvisor = tab === "advisor";

  // --- 6. GATED ENTRANCE (Welcome / Risk Retake) ---
  if (isNewUser || isRetakingRisk) {
    return (
      <SettingsContext.Provider value={settings}>
        <AppContext.Provider value={appCtx}>
          {/* Note: Dynamic --pri-rgb injected for animations */}
          <style>{`
            @import url('https://fonts.googleapis.com/css2?family=Nunito:wght@400;600;700;800;900&family=JetBrains+Mono:wght@400;600;700&display=swap');
            :root {
              color-scheme: dark;
              --pri-rgb: ${hexToRgb(M.pri).join(",")};
            }
            body { background-color: ${M.bg}; }
            *{box-sizing:border-box;margin:0;padding:0}
            @keyframes fadeIn{from{opacity:0}to{opacity:1}}
            @keyframes sheetUp{from{transform:translateX(-50%) translateY(100%)}to{transform:translateX(-50%) translateY(0)}}
            @keyframes resultReveal { 0% { transform: scale(0.5); opacity: 0; } 60% { transform: scale(1.1); } 100% { transform: scale(1); opacity: 1; } }
            @keyframes glowPulse { 0% { box-shadow: 0 0 10px rgba(var(--pri-rgb), 0.2); } 50% { box-shadow: 0 0 30px rgba(var(--pri-rgb), 0.5); } 100% { box-shadow: 0 0 10px rgba(var(--pri-rgb), 0.2); } }
          `}</style>
          <WelcomeJourney
            startAtRisk={isRetakingRisk}
            onComplete={({ goal, name, risk: finalRisk, advanced: isAdv }) => {
              ls.set("siq_risk", finalRisk);
              ls.set("siq_advanced", isAdv);
              setRisk(finalRisk);
              setAdvanced(isAdv);

              if (!onboarded) {
                ls.set("siq_policies_accepted", POLICY_VERSION);
                ls.set("siq_goal", goal);
                ls.set("siq_name", name);
                ls.set("siq_onboarded", true);
                setPoliciesAccepted(true);
                setOnboarded(true);
              }
              setIsRetakingRisk(false);
            }}
          />
        </AppContext.Provider>
      </SettingsContext.Provider>
    );
  }

  // --- 7. MAIN DASHBOARD ---
  return (
    <SettingsContext.Provider value={settings}>
      <AppContext.Provider value={appCtx}>
        <div
          style={{
            background: hexAlpha(M.bg, 0.55),
            height: "100dvh",
            width: "100%",
            display: "flex",
            flexDirection: "column",
            fontFamily: "'Nunito',system-ui,sans-serif",
            color: M.txt,
            overflow: "hidden",
          }}
        >
          <style>{`
            @import url('https://fonts.googleapis.com/css2?family=Nunito:wght@400;500;600;700;800;900&family=JetBrains+Mono:wght@400;600;700&display=swap');
            :root {
              color-scheme: dark;
              --pri-rgb: ${hexToRgb(M.pri).join(",")};
            }
            body { background-color: ${M.bg}; }
            *{box-sizing:border-box;margin:0;padding:0;-webkit-tap-highlight-color:transparent}
            ::-webkit-scrollbar{display:none}
            @keyframes shimmer{0%{background-position:200% 0}100%{background-position:-200% 0}}
            @keyframes pulse{0%,100%{opacity:.3}50%{opacity:1}}
            @keyframes bounce{0%,80%,100%{transform:scale(0)}40%{transform:scale(1)}}
            @keyframes slideUp{from{opacity:0;transform:translateY(14px)}to{opacity:1;transform:translateY(0)}}
            @keyframes fadeIn{from{opacity:0}to{opacity:1}}
            @keyframes marquee{from{transform:translateX(0)}to{transform:translateX(-50%)}}
            @keyframes sheetUp{from{transform:translateX(-50%) translateY(100%)}to{transform:translateX(-50%) translateY(0)}}
            @keyframes spin{to{transform:rotate(360deg)}}
            input,select,button,textarea{-webkit-appearance:none}
            input::placeholder{color:${M.txtDim}}
          `}</style>

          {/* Top Bar */}
          <div
            style={{
              flexShrink: 0,
              zIndex: 40,
              position: "relative",
              paddingTop: "var(--safe-area-inset-top, 0px)",
              ...(scrolled ? ST.topBarScrolled : ST.topBar),
              transition: "all .25s ease",
            }}
          >
            <div
              style={{
                maxWidth: layout === "mobile" ? 480 : "100%",
                margin: "0 auto",
                padding: "0 16px",
              }}
            >
              <div
                style={{
                  display: "flex",
                  alignItems: "center",
                  justifyContent: "space-between",
                  height: 52,
                }}
              >
                <div style={{ display: "flex", alignItems: "center", gap: 9 }}>
                  <ObolLogo size={34} />
                  <div
                    style={{
                      fontFamily: "'JetBrains Mono',monospace",
                      fontWeight: 700,
                      fontSize: 17,
                      color: hexAlpha(M.txt, 0.92),
                      letterSpacing: "-0.5px",
                    }}
                  >
                    obol
                  </div>
                </div>
                <div style={{ display: "flex", alignItems: "center", gap: 7 }}>
                  {risk && (
                    <div
                      style={{
                        ...ST.chip,
                        height: 40,
                        padding: "0 12px",
                        display: "flex",
                        alignItems: "center",
                        gap: 5,
                      }}
                    >
                      <span style={{ fontSize: 11 }}>{risk.emoji}</span>
                      <span
                        style={{
                          fontSize: 11,
                          color: risk.color,
                          fontWeight: 700,
                        }}
                      >
                        {risk.label}
                      </span>
                    </div>
                  )}
                  <div
                    style={{
                      display: "flex",
                      background: hexAlpha(M.txt, 0.06),
                      borderRadius: M.rFull,
                      padding: 3,
                      border: "1px solid " + hexAlpha(M.txt, 0.1),
                    }}
                  >
                    {[
                      ["🌱", false],
                      ["🔬", true],
                    ].map(([icon, val]) => (
                      <button
                        key={icon}
                        onClick={() => setAdvanced(val)}
                        style={{
                          ...(advanced === val
                            ? ST.navTabActive
                            : {
                                background: "transparent",
                                border: "1px solid transparent",
                              }),
                          borderRadius: M.rFull,
                          width: 32,
                          height: 32,
                          cursor: "pointer",
                          fontSize: 14,
                        }}
                      >
                        {icon}
                      </button>
                    ))}
                  </div>
                  {layout !== "desktop" && (
                    <button
                      onClick={() => setShowSettings(true)}
                      style={{
                        ...ST.iconBtn,
                        width: 40,
                        height: 40,
                        fontSize: 16,
                      }}
                    >
                      ⚙️
                    </button>
                  )}
                </div>
              </div>
              {settings?.tickerEnabled !== false && (
                <TickerBanner onTickerTap={handleTickerTap} />
              )}
            </div>
          </div>

          {/* Body Content */}
          <div
            style={{
              flex: 1,
              display: "flex",
              overflow: "hidden",
              maxWidth: layout === "mobile" ? 480 : "100%",
              width: "100%",
              margin: layout === "mobile" ? "0 auto" : 0,
            }}
          >
            {layout !== "mobile" && (
              <div
                style={{
                  ...ST.navPill,
                  flexShrink: 0,
                  width: layout === "desktop" ? 220 : 72,
                  borderRadius: 0,
                  border: "none",
                  borderRight: "1px solid " + hexAlpha(M.txt, 0.08),
                  display: "flex",
                  flexDirection: "column",
                  paddingTop: 8,
                  paddingBottom: 8,
                  overflowY: "auto",
                }}
              >
                {NAV_TABS.map((t) => {
                  const active = tab === t.id;
                  return (
                    <button
                      key={t.id}
                      onClick={() => setTab(t.id)}
                      style={{
                        ...ST.btnGhost,
                        width: "100%",
                        ...(active
                          ? ST.navTabActive
                          : {
                              background: "transparent",
                              border: "1px solid transparent",
                            }),
                        background: active
                          ? hexAlpha(M.txt, 0.13)
                          : "transparent",
                        borderLeft: active
                          ? "3px solid " + M.pri
                          : "3px solid transparent",
                        borderRadius: layout === "desktop" ? M.r12 : "999px",
                        cursor: "pointer",
                        padding: layout === "desktop" ? "13px 18px" : "11px 0",
                        display: "flex",
                        flexDirection: layout === "desktop" ? "row" : "column",
                        alignItems: "center",
                        justifyContent:
                          layout === "desktop" ? "flex-start" : "center",
                        gap: layout === "desktop" ? 12 : 5,
                        transition: "all .15s",
                        fontFamily: "inherit",
                      }}
                    >
                      <span
                        style={{
                          fontSize: layout === "desktop" ? 17 : 22,
                          filter: active
                            ? "none"
                            : "grayscale(55%) opacity(0.45)",
                        }}
                      >
                        {t.icon}
                      </span>
                      {layout === "desktop" && (
                        <span
                          style={{
                            fontSize: 14,
                            fontWeight: active ? 700 : 400,
                            color: active ? M.pri : hexAlpha(M.txt, 0.5),
                          }}
                        >
                          {t.label}
                        </span>
                      )}
                    </button>
                  );
                })}
              </div>
            )}
            <div
              style={{
                flex: 1,
                overflow: "hidden",
                position: "relative",
                minWidth: 0,
              }}
            >
              {isAdvisor ? (
                <div
                  style={{
                    position: "absolute",
                    inset: 0,
                    bottom: layout === "mobile" ? (kbOpen ? 0 : NAV_H) : 0,
                    transition: "bottom .2s ease",
                  }}
                >
                  <AdvisorScreen
                    risk={risk}
                    advanced={advanced}
                    layout={layout}
                  />
                </div>
              ) : (
                <div
                  id="main-scroll"
                  onScroll={onScroll}
                  style={{
                    height: "100%",
                    overflowY: "auto",
                    padding: "16px 16px 0",
                    paddingBottom: layout === "mobile" ? NAV_H + 16 : 24,
                    animation: "slideUp .25s ease",
                    maxWidth: layout === "desktop" ? 860 : "100%",
                    margin: layout === "desktop" ? "0 auto" : undefined,
                  }}
                >
                  {tab === "analyze" && (
                    <AnalyzeScreen
                      risk={risk}
                      advanced={advanced}
                      triggerSym={triggerSym}
                      onTriggerConsumed={() => setTriggerSym(null)}
                    />
                  )}
                  {tab === "markets" && (
                    <MarketsScreen
                      advanced={advanced}
                      initialSub={marketsInitialSub}
                    />
                  )}
                  {tab === "portfolio" && (
                    <PortfolioScreen
                      risk={risk}
                      advanced={advanced}
                      onXpEarned={earnXp}
                    />
                  )}
                  {tab === "learn" && (
                    <LearnScreen
                      advanced={advanced}
                      onSetAdvanced={setAdvanced}
                      xpData={xpData}
                      onXpEarned={earnXp}
                    />
                  )}
                </div>
              )}
            </div>
          </div>

          {/* Overlays */}
          {xpToast && (
            <XpToast
              xp={xpToast.xp}
              label={xpToast.label}
              onDone={() => setXpToast(null)}
            />
          )}
          {layout === "mobile" && !(tab === "advisor" && kbOpen) && (
            <FloatingNav tab={tab} setTab={setTab} />
          )}
          {toastSym && (
            <TickerToast sym={toastSym} onClose={() => setToastSym(null)} />
          )}
          {showSettings && (
            <SettingsSheet
              settings={settings}
              setSettings={setSettings}
              onClose={() => setShowSettings(false)}
              onRetakeQuiz={() => {
                setIsRetakingRisk(true);
                setShowSettings(false);
              }}
              onViewPolicy={(key, title) => setPolicySheet({ key, title })}
              riskProfile={risk}
              advancedMode={advanced}
              onSetAdvanced={setAdvanced}
            />
          )}
          {policySheet && (
            <PolicySheet
              policyKey={policySheet.key}
              title={policySheet.title}
              onClose={() => setPolicySheet(null)}
            />
          )}
        </div>
      </AppContext.Provider>
    </SettingsContext.Provider>
  );
}
