import { useState, useRef, useEffect } from 'react';
import { M, mc } from '../../theme/buildM';
import { ST } from '../../theme/styles';
import { hexAlpha } from '../../theme/colorUtils';
import { ls } from '../../utils/storage';
import { useApp } from '../../context/AppContext';
import { Card, FilledBtn, TonalBtn, Input, Skel } from '../ui';
const JOURNAL_MOODS = ["😀", "💡", "🤔", "😰", "🚀", "😐"];
function InvestorJournal() {
  const [entries, setEntries] = useState(() => ls.get("siq_journal", []));
  const [form, setForm] = useState({
    ticker: "",
    title: "",
    body: "",
    mood: "💡",
  });
  const [adding, setAdding] = useState(false);
  const save = () => {
    if (!form.title.trim()) return;
    const next = [
      { ...form, id: Date.now(), date: new Date().toLocaleDateString() },
      ...entries,
    ];
    setEntries(next);
    ls.set("siq_journal", next);
    setForm({ ticker: "", title: "", body: "", mood: "💡" });
    setAdding(false);
  };
  const del = (id) => {
    const n = entries.filter((e) => e.id !== id);
    setEntries(n);
    ls.set("siq_journal", n);
  };
  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
      <div
        style={{
          display: "flex",
          alignItems: "center",
          justifyContent: "space-between",
        }}
      >
        <div style={{ fontSize: 13, fontWeight: 800, color: M.txt }}>
          {"📓 Investor Journal"}
        </div>
        <FilledBtn label="+ Entry" onClick={() => setAdding(true)} />
      </div>
      {adding && (
        <Card
          style={{ padding: 18, border: "1px solid " + hexAlpha(M.pri, 0.22) }}
        >
          <div style={{ display: "flex", gap: 6, marginBottom: 12 }}>
            {JOURNAL_MOODS.map((e) => (
              <button
                key={e}
                onClick={() => setForm((f) => ({ ...f, mood: e }))}
                style={{
                  fontSize: 22,
                  background: "transparent",
                  border: "none",
                  cursor: "pointer",
                  opacity: form.mood === e ? 1 : 0.3,
                  transform: form.mood === e ? "scale(1.25)" : "scale(1)",
                  transition: "all .15s",
                }}
              >
                {e}
              </button>
            ))}
          </div>
          {[
            ["Ticker (optional)", "ticker", "AAPL"],
            ["Title *", "title", "Trade idea or observation"],
          ].map(([l, k, ph]) => (
            <input
              key={k}
              value={form[k]}
              onChange={(e) => setForm((f) => ({ ...f, [k]: e.target.value }))}
              placeholder={ph}
              style={{
                ...ST.input,
                width: "100%",
                marginBottom: 8,
                padding: "10px 12px",
                outline: "none",
                fontSize: 13,
                borderRadius: M.r12,
                border: "1px solid " + hexAlpha(M.txt, 0.12),
                boxSizing: "border-box",
              }}
            />
          ))}
          <textarea
            value={form.body}
            onChange={(e) => setForm((f) => ({ ...f, body: e.target.value }))}
            placeholder="Notes, reasoning, emotions, lessons learned..."
            rows={3}
            style={{
              ...ST.input,
              width: "100%",
              marginBottom: 12,
              padding: "10px 12px",
              outline: "none",
              fontSize: 13,
              borderRadius: M.r12,
              border: "1px solid " + hexAlpha(M.txt, 0.12),
              resize: "vertical",
              fontFamily: "inherit",
              boxSizing: "border-box",
            }}
          />
          <div style={{ display: "flex", gap: 8 }}>
            <FilledBtn label={"Save Entry 💾"} onClick={save} full />
            <button
              onClick={() => setAdding(false)}
              style={{
                background: "transparent",
                border: "1px solid " + hexAlpha(M.txt, 0.12),
                borderRadius: M.r12,
                padding: "12px 14px",
                cursor: "pointer",
                fontSize: 13,
                color: hexAlpha(M.txt, 0.4),
                fontFamily: "inherit",
              }}
            >
              Cancel
            </button>
          </div>
        </Card>
      )}
      {entries.length === 0 && !adding && (
        <Card style={{ padding: 36, textAlign: "center" }}>
          <div style={{ fontSize: 36, marginBottom: 10 }}>{"📝"}</div>
          <div
            style={{
              fontSize: 14,
              fontWeight: 700,
              color: M.txt,
              marginBottom: 6,
            }}
          >
            No entries yet
          </div>
          <div style={{ fontSize: 12, color: hexAlpha(M.txt, 0.4) }}>
            Log trade ideas, analysis and lessons learned
          </div>
        </Card>
      )}
      {entries.map((e) => (
        <Card
          key={e.id}
          style={{ padding: 14, border: "1px solid " + hexAlpha(M.txt, 0.08) }}
        >
          <div style={{ display: "flex", alignItems: "flex-start", gap: 10 }}>
            <span style={{ fontSize: 20, flexShrink: 0 }}>{e.mood}</span>
            <div style={{ flex: 1, minWidth: 0 }}>
              <div
                style={{
                  display: "flex",
                  alignItems: "center",
                  gap: 6,
                  marginBottom: 3,
                }}
              >
                {e.ticker && (
                  <span
                    style={{
                      fontSize: 11,
                      fontWeight: 800,
                      color: M.pri,
                      fontFamily: "monospace",
                    }}
                  >
                    {e.ticker}
                  </span>
                )}
                <span style={{ fontSize: 13, fontWeight: 700, color: M.txt }}>
                  {e.title}
                </span>
              </div>
              {e.body && (
                <div
                  style={{
                    fontSize: 12,
                    color: hexAlpha(M.txt, 0.5),
                    lineHeight: 1.5,
                  }}
                >
                  {e.body}
                </div>
              )}
              <div
                style={{
                  fontSize: 10,
                  color: hexAlpha(M.txt, 0.28),
                  marginTop: 6,
                }}
              >
                {e.date}
              </div>
            </div>
            <button
              onClick={() => del(e.id)}
              style={{
                background: "transparent",
                border: "none",
                cursor: "pointer",
                fontSize: 14,
                color: hexAlpha(M.txt, 0.22),
                padding: "2px 4px",
              }}
            >
              {"x"}
            </button>
          </div>
        </Card>
      ))}
    </div>
  );
}

// ─── Daily Market Snapshot ────────────────────────────────────────────────────
export default InvestorJournal;
