import { useState } from 'react';
import { M, mc } from '../../theme/buildM';
import { ST } from '../../theme/styles';
import { hexAlpha } from '../../theme/colorUtils';
function Card({ children, style = {}, color }) {
  return (
    <div
      style={{
        ...ST.card,
        ...style,
      }}
    >
      {children}
    </div>
  );
}
function FilledBtn({ label, onClick, disabled, color, bg, icon, full }) {
  return (
    <button
      onClick={onClick}
      disabled={disabled}
      style={{
        ...ST.btnFilled,
        background: disabled
          ? hexAlpha(M.txt, 0.08)
          : bg
            ? hexAlpha(bg, 0.9)
            : hexAlpha(M.pri, 0.9),
        color: disabled ? M.txtDim : color || M.onPri,
        width: full ? "100%" : "auto",
        opacity: disabled ? 0.5 : 1,
        cursor: disabled ? "not-allowed" : "pointer",
        boxShadow: disabled
          ? "inset 0 1px 0 " + hexAlpha(M.txt, 0.06)
          : ST.btnFilled.boxShadow,
      }}
    >
      {icon && <span>{icon}</span>}
      {label}
    </button>
  );
}
function TonalBtn({ label, onClick, disabled, color, bg, icon, full }) {
  return (
    <button
      onClick={onClick}
      disabled={disabled}
      style={{
        ...ST.btnTonal,
        ...(bg
          ? {
              background: hexAlpha(bg, 0.12),
              border: "1px solid " + hexAlpha(bg, 0.25),
              color: bg,
            }
          : {}),
        color: disabled ? M.txtDim : color || bg || M.txt,
        width: full ? "100%" : "auto",
        opacity: disabled ? 0.5 : 1,
        cursor: disabled ? "not-allowed" : "pointer",
      }}
    >
      {icon && <span>{icon}</span>}
      {label}
    </button>
  );
}
function Input({
  label,
  value,
  onChange,
  onKeyDown,
  placeholder,
  type = "text",
  mono,
}) {
  const [focused, setFocused] = useState(false);
  return (
    <div>
      {label && (
        <div
          style={{
            fontSize: 12,
            color: focused ? M.pri : M.txtDim,
            marginBottom: 6,
            fontWeight: 700,
            letterSpacing: 0.4,
          }}
        >
          {label}
        </div>
      )}
      <input
        type={type}
        value={value}
        onChange={onChange}
        onKeyDown={onKeyDown}
        placeholder={placeholder}
        onFocus={() => setFocused(true)}
        onBlur={() => setFocused(false)}
        style={{
          ...ST.input,
          width: "100%",
          border:
            "1.5px solid " +
            (focused ? hexAlpha(M.pri, 0.6) : hexAlpha(M.txt, 0.1)),
          padding: "13px 16px",
          outline: "none",
          fontFamily: mono ? "'JetBrains Mono',monospace" : "inherit",
          transition: "border-color .2s",
          boxSizing: "border-box",
        }}
      />
    </div>
  );
}
function Skel({ lines = 4 }) {
  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 12 }}>
      {Array.from({ length: lines }, (_, i) => (
        <div
          key={i}
          style={{
            height: 14,
            borderRadius: M.rFull,
            background: `linear-gradient(90deg,${M.s3} 0%,${M.s4} 50%,${M.s3} 100%)`,
            backgroundSize: "200% 100%",
            animation: "shimmer 1.8s infinite",
            width: `${[92, 75, 85, 60][i % 4]}%`,
          }}
        />
      ))}
    </div>
  );
}

// ─── Friendly Error Card ──────────────────────────────────────────
export { Card, FilledBtn, TonalBtn, Input, Skel };
