import { useState, useRef, useEffect } from 'react';
import { M, mc } from '../../theme/buildM';
import { ST } from '../../theme/styles';
import { hexAlpha } from '../../theme/colorUtils';
import { ls } from '../../utils/storage';
import { useApp } from '../../context/AppContext';
import { Card, FilledBtn, TonalBtn, Input, Skel } from '../ui';
import LearnVisual from './LearnVisual';
import { DailyChallenge, TopicQuiz, FlashcardScreen } from './LearnActivities';
function LearnSheet({ topic, onClose, onComplete }) {
  const { w: winW } = useWindowSize();
  const isLarge = winW >= 600;
  const sheetRef = useRef(null);
  const scrollRef = useRef(null);
  const startY = useRef(0);
  const dragY = useRef(0);

  const smoothClose = () => {
    if (onComplete) onComplete(topic.key);
    if (sheetRef.current) {
      if (isLarge) {
        sheetRef.current.style.transition =
          "opacity .2s ease, transform .2s ease";
        sheetRef.current.style.opacity = "0";
        sheetRef.current.style.transform = "translate(-50%,-50%) scale(0.96)";
      } else {
        sheetRef.current.style.transition =
          "transform .32s cubic-bezier(0.4,0,1,1), opacity .28s ease";
        sheetRef.current.style.transform = "translateX(-50%) translateY(100%)";
        sheetRef.current.style.opacity = "0";
      }
    }
    setTimeout(onClose, 280);
  };

  const onTouchStart = (e) => {
    startY.current = e.touches[0].clientY;
    dragY.current = 0;
    if (sheetRef.current) sheetRef.current.style.transition = "none";
  };
  const onTouchMove = (e) => {
    const dy = e.touches[0].clientY - startY.current;
    const atTop = !scrollRef.current || scrollRef.current.scrollTop <= 0;
    if (dy > 0 && atTop && !isLarge) {
      dragY.current = dy;
      if (sheetRef.current)
        sheetRef.current.style.transform = `translateX(-50%) translateY(${dy}px)`;
    }
  };
  const onTouchEnd = () => {
    if (dragY.current > 60) {
      smoothClose();
    } else if (sheetRef.current && !isLarge) {
      sheetRef.current.style.transition =
        "transform .3s cubic-bezier(0.34,1.56,0.64,1)";
      sheetRef.current.style.transform = "translateX(-50%) translateY(0)";
    }
  };

  // Use plain JSX constants (not inner components) to avoid React remount issues
  const headerContent = (
    <div
      style={{
        flexShrink: 0,
        padding: isLarge ? "20px 24px 0" : "14px 20px 0",
      }}
    >
      {!isLarge && (
        <div
          style={{
            display: "flex",
            justifyContent: "center",
            marginBottom: 14,
          }}
        >
          <div style={ST.dragHandle} />
        </div>
      )}
      <div
        style={{
          display: "flex",
          justifyContent: "space-between",
          alignItems: "flex-start",
          marginBottom: 12,
        }}
      >
        <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
          <span style={{ fontSize: 28 }}>{topic.icon}</span>
          <div>
            <div
              style={{
                fontSize: isLarge ? 20 : 18,
                fontWeight: 900,
                color: M.txt,
                lineHeight: 1.2,
              }}
            >
              {topic.title}
            </div>
            <div
              style={{
                fontSize: 11,
                color: mc(topic.colorKey),
                fontWeight: 700,
                marginTop: 3,
                textTransform: "uppercase",
                letterSpacing: 1,
              }}
            >
              {(LEARN_CATS.find((c) => c.key === topic.cat) || {}).label ||
                topic.cat}
            </div>
          </div>
        </div>
        <button onClick={smoothClose} style={{ ...ST.iconBtn }}>
          ✕
        </button>
      </div>
    </div>
  );

  const sectionContent = (
    <div
      ref={scrollRef}
      style={{
        flex: 1,
        overflowY: "auto",
        padding: isLarge ? "4px 24px 48px" : "4px 20px 48px",
        display: "flex",
        flexDirection: "column",
        gap: 14,
      }}
    >
      {topic.visual && <LearnVisual v={topic.visual} />}
      {(topic.sections || []).map((sec, i) => (
        <div
          key={i}
          style={{
            ...ST.card,
            background: sec.highlight
              ? hexAlpha(M.pri, 0.12)
              : hexAlpha(M.bg, 0.55),
            border: sec.highlight
              ? "1px solid " + hexAlpha(M.pri, 0.25)
              : "1px solid " + hexAlpha(M.txt, 0.08),
            borderRadius: M.r20,
            padding: "16px 18px",
          }}
        >
          <div
            style={{
              fontSize: 11,
              fontWeight: 800,
              color: sec.highlight ? mc(topic.colorKey) : hexAlpha(M.txt, 0.38),
              textTransform: "uppercase",
              letterSpacing: 1.2,
              marginBottom: 10,
            }}
          >
            {sec.head}
          </div>
          <div
            style={{
              fontSize: 14,
              color: sec.highlight ? M.txt : hexAlpha(M.txt, 0.78),
              lineHeight: 1.85,
              whiteSpace: "pre-wrap",
            }}
          >
            {sec.body}
          </div>
        </div>
      ))}
    </div>
  );

  return (
    <>
      <div
        onClick={smoothClose}
        style={{
          position: "fixed",
          inset: 0,
          background: hexAlpha(M.bg, 0.58),
          zIndex: 200,
          backdropFilter: "blur(10px)",
          WebkitBackdropFilter: "blur(10px)",
          animation: "fadeIn .2s ease",
        }}
      />
      {isLarge ? (
        <div
          ref={sheetRef}
          style={{
            position: "fixed",
            top: "50%",
            left: "50%",
            transform: "translate(-50%,-50%)",
            width: "min(680px,90vw)",
            maxHeight: "85dvh",
            zIndex: 201,
            ...ST.sheet,
            borderRadius: M.r28,
            display: "flex",
            flexDirection: "column",
            animation: "fadeIn .18s ease",
          }}
        >
          {headerContent}
          {sectionContent}
        </div>
      ) : (
        <div
          ref={sheetRef}
          onTouchStart={onTouchStart}
          onTouchMove={onTouchMove}
          onTouchEnd={onTouchEnd}
          style={{
            position: "fixed",
            bottom: 0,
            left: "50%",
            transform: "translateX(-50%)",
            width: "100%",
            maxWidth: 480,
            zIndex: 201,
            ...ST.sheet,
            borderRadius: "28px 28px 0 0",
            borderBottom: "none",
            maxHeight: "88dvh",
            display: "flex",
            flexDirection: "column",
            animation: "sheetUp .32s cubic-bezier(0.34,1.56,0.64,1)",
          }}
        >
          {headerContent}
          {sectionContent}
        </div>
      )}
    </>
  );
}
export default LearnSheet;
