import { parseAIError } from '../../api/ai';
import { M, mc } from '../../theme/buildM';
import { ST } from '../../theme/styles';
import { hexAlpha } from '../../theme/colorUtils';
function ErrorCard({ error, onRetry, onOpenSettings }) {
  const info = parseAIError(error);
  return (
    <div
      style={{
        background: hexAlpha(M.txt, 0.06),
        backdropFilter: "blur(24px)",
        WebkitBackdropFilter: "blur(24px)",
        border: "1px solid " + hexAlpha(M.txt, 0.1),
        borderRadius: M.r24,
        padding: "22px 20px",
        boxShadow: "inset 0 1px 0 " + hexAlpha(M.txt, 0.08),
      }}
    >
      <div style={{ fontSize: 32, marginBottom: 10 }}>{info.icon}</div>
      <div
        style={{ fontSize: 16, fontWeight: 800, color: M.txt, marginBottom: 8 }}
      >
        {info.title}
      </div>
      <div
        style={{
          fontSize: 14,
          color: M.txtMid,
          lineHeight: 1.7,
          marginBottom: 18,
        }}
      >
        {info.body}
      </div>
      <div style={{ display: "flex", gap: 10, flexWrap: "wrap" }}>
        {info.action === "Open Settings" ? (
          <button
            onClick={onOpenSettings}
            style={{
              background: hexAlpha(M.pri, 0.15),
              backdropFilter: "blur(36px) saturate(160%)",
              WebkitBackdropFilter: "blur(36px) saturate(160%)",
              boxShadow: "inset 0 1px 0 " + hexAlpha(M.txt, 0.08),
              color: M.pri,
              border: "1px solid " + hexAlpha(M.pri, 0.25),
              borderRadius: M.rFull,
              padding: "10px 20px",
              fontSize: 13,
              fontWeight: 700,
              cursor: "pointer",
              fontFamily: "inherit",
            }}
          >
            ⚙️ Open Settings
          </button>
        ) : (
          <button
            onClick={onRetry}
            style={{
              background: hexAlpha(M.txt, 0.1),
              color: M.txt,
              border: "1px solid " + hexAlpha(M.txt, 0.15),
              borderRadius: M.rFull,
              padding: "10px 20px",
              fontSize: 13,
              fontWeight: 700,
              cursor: "pointer",
              fontFamily: "inherit",
              backdropFilter: "blur(12px)",
            }}
          >
            ↺ Try Again
          </button>
        )}
      </div>
    </div>
  );
}

// ─── No AI configured banner ─────────────────────────────────────
function NoAIBanner({ onSettings, label }) {
  return (
    <div
      style={{
        background: hexAlpha(M.gold, 0.08),
        border: "1px solid " + hexAlpha(M.gold, 0.25),
        backdropFilter: "blur(16px)",
        borderRadius: M.r16,
        padding: "14px 16px",
        display: "flex",
        alignItems: "center",
        gap: 12,
      }}
    >
      <span style={{ fontSize: 22, flexShrink: 0 }}>🔑</span>
      <div style={{ flex: 1 }}>
        <div style={{ fontSize: 13, fontWeight: 700, color: M.gold }}>
          AI provider not configured
        </div>
        <div
          style={{
            fontSize: 12,
            color: M.txtMid,
            lineHeight: 1.5,
            marginTop: 2,
          }}
        >
          {label ||
            "Configure an AI provider in Settings to unlock this feature."}
        </div>
      </div>
      <button
        onClick={onSettings}
        style={{
          ...ST.btnFilled,
          background: hexAlpha(M.gold, 0.15),
          backdropFilter: "blur(36px) saturate(160%)",
          WebkitBackdropFilter: "blur(36px) saturate(160%)",
          boxShadow: "inset 0 1px 0 " + hexAlpha(M.txt, 0.08),
          border: "1px solid " + hexAlpha(M.gold, 0.3),
          color: M.gold,
          borderRadius: M.rFull,
          padding: "6px 14px",
          fontSize: 12,
          fontWeight: 700,
          cursor: "pointer",
          fontFamily: "inherit",
          flexShrink: 0,
        }}
      >
        Settings
      </button>
    </div>
  );
}

// ─── Cross-Tab Action Bar ─────────────────────────────────────────
// Appears on any screen that has a stock result — lets user jump to
// other tabs with that stock pre-loaded
export { ErrorCard, NoAIBanner };
