import { useApp } from '../context/AppContext';
import { M, mc } from '../theme/buildM';
import { ST } from '../theme/styles';
import { hexAlpha } from '../theme/colorUtils';
// ─── Cross-Tab Action Bar ─────────────────────────────────────────
// Appears on any screen that has a stock result — lets user jump to
// other tabs with that stock pre-loaded
function CrossTabBar({ sym, label, currentTab }) {
  const { navigate } = useApp();
  if (!sym) return null;
  const actions = [
    currentTab !== "advisor" && {
      icon: "🤖",
      text: "Ask Advisor",
      tab: "advisor",
      sym,
    },
    currentTab !== "sentiment" && {
      icon: "🎯",
      text: "Sentiment",
      tab: "sentiment",
      sym,
    },
    currentTab !== "simulator" && {
      icon: "🔮",
      text: "Simulate",
      tab: "simulator",
      sym,
    },
    currentTab !== "analyze" && {
      icon: "📊",
      text: "Full Analysis",
      tab: "analyze",
      sym,
    },
  ].filter(Boolean);

  return (
    <div style={{ display: "flex", gap: 8, flexWrap: "wrap" }}>
      {actions.map((a) => (
        <button
          key={a.tab}
          onClick={() => navigate(a.tab, a.sym)}
          style={{
            ...ST.chip,
            padding: "4px 10px",
            display: "flex",
            alignItems: "center",
            gap: 4,
          }}
          onTouchStart={(e) =>
            (e.currentTarget.style.background = hexAlpha(M.txt, 0.13))
          }
          onTouchEnd={(e) =>
            (e.currentTarget.style.background = hexAlpha(M.txt, 0.07))
          }
        >
          <span>{a.icon}</span>
          {a.text}
        </button>
      ))}
    </div>
  );
}
export default CrossTabBar;
