import { useState, useRef, useEffect } from 'react';
import { M, mc } from '../../theme/buildM';
import { ST } from '../../theme/styles';
import { hexAlpha } from '../../theme/colorUtils';
import { ls } from '../../utils/storage';
import { useApp } from '../../context/AppContext';
import { Card, FilledBtn, TonalBtn, Input, Skel } from '../ui';
import { callAI, hasAIConfigured } from '../../api/ai';
import { TOPIC_QUIZ, FALLBACK_QUIZ_Q, FLASHCARDS, SNAPSHOT_TIPS } from '../../data/levels';
function DailyChallenge({ xpData, onXpEarned, onUpdateXp }) {
  const today = new Date().toDateString();
  const done = xpData && xpData.lastChallenge === today;
  const [open, setOpen] = useState(false);
  const [picked, setPicked] = useState(null);
  const [result, setResult] = useState(null);
  const idx = new Date().getDate() % 3;
  const q =
    TOPIC_QUIZ.risk_reward && TOPIC_QUIZ.risk_reward[idx]
      ? TOPIC_QUIZ.risk_reward[idx]
      : FALLBACK_QUIZ_Q;
  const submit = () => {
    if (picked === null) return;
    const correct = picked === q.a;
    setResult(correct);
    if (correct && onXpEarned) onXpEarned(XP_PER_QUIZ_PASS, "Daily Challenge");
    if (onUpdateXp) onUpdateXp({ lastChallenge: today });
  };
  if (!open)
    return (
      <Card
        style={{
          padding: 14,
          marginBottom: 16,
          background: done ? hexAlpha(M.gain, 0.07) : hexAlpha(M.gold, 0.07),
          border:
            "1px solid " +
            (done ? hexAlpha(M.gain, 0.22) : hexAlpha(M.gold, 0.25)),
        }}
      >
        <div
          style={{
            display: "flex",
            alignItems: "center",
            justifyContent: "space-between",
          }}
        >
          <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
            <span style={{ fontSize: 22 }}>{done ? "✅" : "🧠"}</span>
            <div>
              <div style={{ fontSize: 13, fontWeight: 800, color: M.txt }}>
                Daily Challenge
              </div>
              <div style={{ fontSize: 11, color: hexAlpha(M.txt, 0.45) }}>
                {done
                  ? "Completed · back tomorrow"
                  : "Streak: " +
                    (xpData ? xpData.streak || 0 : 0) +
                    " days · +" +
                    XP_PER_QUIZ_PASS +
                    " XP"}
              </div>
            </div>
          </div>
          {!done && (
            <FilledBtn
              label="Start"
              onClick={() => {
                setOpen(true);
                setPicked(null);
                setResult(null);
              }}
            />
          )}
        </div>
      </Card>
    );
  return (
    <div
      style={{
        position: "fixed",
        inset: 0,
        zIndex: 310,
        background: hexAlpha(M.bg, 0.82),
        backdropFilter: "blur(18px)",
        WebkitBackdropFilter: "blur(18px)",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        padding: 24,
      }}
    >
      <div
        style={{
          ...ST.card,
          borderRadius: M.r28,
          padding: 28,
          width: "100%",
          maxWidth: 380,
          border: "1px solid " + hexAlpha(M.gold, 0.28),
        }}
      >
        <div
          style={{
            fontSize: 11,
            fontWeight: 800,
            color: M.gold,
            letterSpacing: 1.2,
            marginBottom: 14,
          }}
        >
          {"🧠 DAILY CHALLENGE"}
        </div>
        {result === null ? (
          <>
            <div
              style={{
                fontSize: 15,
                fontWeight: 700,
                color: M.txt,
                lineHeight: 1.55,
                marginBottom: 18,
              }}
            >
              {q.q}
            </div>
            <div
              style={{
                display: "flex",
                flexDirection: "column",
                gap: 8,
                marginBottom: 20,
              }}
            >
              {q.choices.map((c, i) => (
                <button
                  key={i}
                  onClick={() => setPicked(i)}
                  style={{
                    padding: "12px 14px",
                    borderRadius: M.r12,
                    cursor: "pointer",
                    textAlign: "left",
                    fontSize: 13,
                    fontFamily: "inherit",
                    fontWeight: picked === i ? 700 : 400,
                    background:
                      picked === i
                        ? hexAlpha(M.pri, 0.15)
                        : hexAlpha(M.txt, 0.05),
                    border:
                      "1px solid " +
                      (picked === i
                        ? hexAlpha(M.pri, 0.4)
                        : hexAlpha(M.txt, 0.1)),
                    color: picked === i ? M.pri : M.txt,
                    transition: "all .15s",
                  }}
                >
                  {c}
                </button>
              ))}
            </div>
            <div style={{ display: "flex", gap: 10 }}>
              <FilledBtn label="Submit" onClick={submit} full icon="✓" />
              <button
                onClick={() => setOpen(false)}
                style={{
                  background: "transparent",
                  border: "1px solid " + hexAlpha(M.txt, 0.12),
                  borderRadius: M.r12,
                  padding: "12px 14px",
                  cursor: "pointer",
                  fontSize: 13,
                  color: hexAlpha(M.txt, 0.4),
                  fontFamily: "inherit",
                }}
              >
                Skip
              </button>
            </div>
          </>
        ) : (
          <div style={{ textAlign: "center" }}>
            <div style={{ fontSize: 44, marginBottom: 12 }}>
              {result ? "🎉" : "📖"}
            </div>
            <div
              style={{
                fontSize: 18,
                fontWeight: 900,
                color: M.txt,
                marginBottom: 8,
              }}
            >
              {result ? "Correct!" : "Not quite"}
            </div>
            <div
              style={{
                fontSize: 13,
                color: hexAlpha(M.txt, 0.55),
                marginBottom: 20,
              }}
            >
              {result
                ? "+" + XP_PER_QUIZ_PASS + " XP added"
                : "The answer was: " + q.choices[q.a]}
            </div>
            <FilledBtn label="Done" onClick={() => setOpen(false)} full />
          </div>
        )}
      </div>
    </div>
  );
}

// ─── Per-Topic Quiz ───────────────────────────────────────────────────────────
function TopicQuiz({ topicKey, onPass, onDismiss }) {
  const qs =
    TOPIC_QUIZ[topicKey] && TOPIC_QUIZ[topicKey].length
      ? TOPIC_QUIZ[topicKey]
      : [FALLBACK_QUIZ_Q];
  const [idx, setIdx] = useState(0);
  const [picked, setPicked] = useState(null);
  const [log, setLog] = useState([]);
  const [done, setDone] = useState(false);
  const submit = () => {
    if (picked === null) return;
    const correct = picked === qs[idx].a;
    const next = [...log, correct];
    if (idx < qs.length - 1) {
      setLog(next);
      setIdx((i) => i + 1);
      setPicked(null);
    } else {
      setLog(next);
      setDone(true);
      if (next.filter(Boolean).length >= Math.ceil(qs.length * 0.67) && onPass)
        onPass();
    }
  };
  const score = log.filter(Boolean).length;
  if (done) {
    const passed = score >= Math.ceil(qs.length * 0.67);
    return (
      <div
        style={{
          position: "fixed",
          inset: 0,
          zIndex: 315,
          background: hexAlpha(M.bg, 0.82),
          backdropFilter: "blur(16px)",
          WebkitBackdropFilter: "blur(16px)",
          display: "flex",
          alignItems: "center",
          justifyContent: "center",
          padding: 24,
        }}
      >
        <div
          style={{
            ...ST.card,
            borderRadius: M.r28,
            padding: 28,
            width: "100%",
            maxWidth: 360,
            textAlign: "center",
            border: "1px solid " + hexAlpha(passed ? M.gain : M.loss, 0.3),
          }}
        >
          <div style={{ fontSize: 44, marginBottom: 12 }}>
            {passed ? "🎉" : "📖"}
          </div>
          <div
            style={{
              fontSize: 18,
              fontWeight: 900,
              color: M.txt,
              marginBottom: 8,
            }}
          >
            {passed ? "Quiz Passed!" : "Keep Studying"}
          </div>
          <div
            style={{
              fontSize: 13,
              color: hexAlpha(M.txt, 0.55),
              marginBottom: 20,
            }}
          >
            {score +
              "/" +
              qs.length +
              " correct · " +
              (passed
                ? "+" + XP_PER_QUIZ_PASS + " XP earned"
                : "Read again and retry for XP")}
          </div>
          <FilledBtn
            label={passed ? "Continue" : "Try Again"}
            onClick={onDismiss}
            full
          />
        </div>
      </div>
    );
  }
  const q = qs[idx];
  return (
    <div
      style={{
        position: "fixed",
        inset: 0,
        zIndex: 315,
        background: hexAlpha(M.bg, 0.82),
        backdropFilter: "blur(16px)",
        WebkitBackdropFilter: "blur(16px)",
        display: "flex",
        alignItems: "center",
        justifyContent: "center",
        padding: 24,
      }}
    >
      <div
        style={{
          ...ST.card,
          borderRadius: M.r28,
          padding: 28,
          width: "100%",
          maxWidth: 380,
          border: "1px solid " + hexAlpha(M.pri, 0.25),
        }}
      >
        <div
          style={{
            display: "flex",
            justifyContent: "space-between",
            marginBottom: 14,
          }}
        >
          <div
            style={{
              fontSize: 11,
              fontWeight: 800,
              color: M.pri,
              letterSpacing: 1.2,
            }}
          >
            QUICK QUIZ
          </div>
          <div style={{ fontSize: 11, color: hexAlpha(M.txt, 0.4) }}>
            {idx + 1 + "/" + qs.length}
          </div>
        </div>
        <div
          style={{
            width: "100%",
            height: 4,
            borderRadius: M.rFull,
            background: hexAlpha(M.txt, 0.08),
            overflow: "hidden",
            marginBottom: 16,
          }}
        >
          <div
            style={{
              height: "100%",
              width: (idx / qs.length) * 100 + "%",
              background: M.pri,
              borderRadius: M.rFull,
              transition: "width .3s",
            }}
          />
        </div>
        <div
          style={{
            fontSize: 15,
            fontWeight: 700,
            color: M.txt,
            lineHeight: 1.55,
            marginBottom: 18,
          }}
        >
          {q.q}
        </div>
        <div
          style={{
            display: "flex",
            flexDirection: "column",
            gap: 8,
            marginBottom: 20,
          }}
        >
          {q.choices.map((c, i) => (
            <button
              key={i}
              onClick={() => setPicked(i)}
              style={{
                padding: "11px 14px",
                borderRadius: M.r12,
                cursor: "pointer",
                textAlign: "left",
                fontSize: 13,
                fontFamily: "inherit",
                fontWeight: picked === i ? 700 : 400,
                background:
                  picked === i ? hexAlpha(M.pri, 0.15) : hexAlpha(M.txt, 0.05),
                border:
                  "1px solid " +
                  (picked === i ? hexAlpha(M.pri, 0.4) : hexAlpha(M.txt, 0.1)),
                color: picked === i ? M.pri : M.txt,
                transition: "all .15s",
              }}
            >
              {c}
            </button>
          ))}
        </div>
        <div style={{ display: "flex", gap: 10 }}>
          <FilledBtn label={"Next \u2192"} onClick={submit} full />
          <button
            onClick={onDismiss}
            style={{
              background: "transparent",
              border: "1px solid " + hexAlpha(M.txt, 0.12),
              borderRadius: M.r12,
              padding: "12px 14px",
              cursor: "pointer",
              fontSize: 12,
              color: hexAlpha(M.txt, 0.4),
              fontFamily: "inherit",
            }}
          >
            Skip
          </button>
        </div>
      </div>
    </div>
  );
}

// ─── Flashcard Screen ─────────────────────────────────────────────────────────
function FlashcardScreen({ onXpEarned }) {
  const [deck] = useState(() =>
    [...FLASHCARDS].sort(() => Math.random() - 0.5),
  );
  const [idx, setIdx] = useState(0);
  const [flipped, setFlipped] = useState(false);
  const [known, setKnown] = useState([]);
  const [review, setReview] = useState([]);
  const done = idx >= deck.length;
  const answer = (correct) => {
    if (correct) {
      const nk = [...known, idx];
      setKnown(nk);
      if (nk.length % 5 === 0 && onXpEarned)
        onXpEarned(XP_STREAK_BONUS, "Flashcard Streak");
    } else setReview((r) => [...r, idx]);
    setFlipped(false);
    setIdx((i) => i + 1);
  };
  if (done)
    return (
      <Card style={{ padding: 28, textAlign: "center" }}>
        <div style={{ fontSize: 44, marginBottom: 12 }}>{"🃏"}</div>
        <div
          style={{
            fontSize: 18,
            fontWeight: 900,
            color: M.txt,
            marginBottom: 8,
          }}
        >
          Deck Complete!
        </div>
        <div
          style={{
            fontSize: 13,
            color: hexAlpha(M.txt, 0.55),
            marginBottom: 20,
          }}
        >
          {"✅ " + known.length + " known · 📖 " + review.length + " to review"}
        </div>
        <FilledBtn
          label={"Shuffle & Restart 🔀"}
          onClick={() => {
            setIdx(0);
            setFlipped(false);
            setKnown([]);
            setReview([]);
          }}
          full
        />
      </Card>
    );
  const card = deck[idx];
  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 14 }}>
      <div
        style={{
          display: "flex",
          justifyContent: "space-between",
          alignItems: "center",
        }}
      >
        <div style={{ fontSize: 13, fontWeight: 700, color: M.txt }}>
          {idx + 1 + " / " + deck.length}
        </div>
        <div style={{ display: "flex", gap: 10 }}>
          <span style={{ fontSize: 11, color: M.gain }}>
            {"✅ " + known.length}
          </span>
          <span style={{ fontSize: 11, color: M.loss }}>
            {"📖 " + review.length}
          </span>
        </div>
      </div>
      <div
        style={{
          height: 5,
          borderRadius: M.rFull,
          background: hexAlpha(M.txt, 0.08),
          overflow: "hidden",
        }}
      >
        <div
          style={{
            height: "100%",
            width: (idx / deck.length) * 100 + "%",
            background: M.pri,
            borderRadius: M.rFull,
            transition: "width .3s",
          }}
        />
      </div>
      <button
        onClick={() => setFlipped((f) => !f)}
        style={{
          ...ST.card,
          padding: 44,
          borderRadius: M.r20,
          cursor: "pointer",
          fontFamily: "inherit",
          minHeight: 190,
          display: "flex",
          flexDirection: "column",
          alignItems: "center",
          justifyContent: "center",
          gap: 12,
          textAlign: "center",
          border: "1px solid " + hexAlpha(M.pri, flipped ? 0.3 : 0.14),
          background: flipped ? hexAlpha(M.pri, 0.07) : hexAlpha(M.txt, 0.03),
          transition: "all .25s",
        }}
      >
        <div
          style={{
            fontSize: 10,
            fontWeight: 800,
            color: hexAlpha(M.txt, 0.3),
            letterSpacing: 1.5,
            textTransform: "uppercase",
          }}
        >
          {flipped ? "Definition — tap to flip back" : "Term — tap to reveal"}
        </div>
        <div
          style={{
            fontSize: flipped ? 14 : 22,
            fontWeight: flipped ? 400 : 800,
            color: M.txt,
            lineHeight: 1.6,
          }}
        >
          {flipped ? card.back : card.front}
        </div>
      </button>
      {flipped && (
        <div
          style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 10 }}
        >
          <button
            onClick={() => answer(false)}
            style={{
              padding: "14px 0",
              borderRadius: M.r16,
              cursor: "pointer",
              fontFamily: "inherit",
              fontSize: 14,
              fontWeight: 700,
              background: hexAlpha(M.loss, 0.1),
              border: "1px solid " + hexAlpha(M.loss, 0.25),
              color: M.loss,
            }}
          >
            {"😕 Still Learning"}
          </button>
          <button
            onClick={() => answer(true)}
            style={{
              padding: "14px 0",
              borderRadius: M.r16,
              cursor: "pointer",
              fontFamily: "inherit",
              fontSize: 14,
              fontWeight: 700,
              background: hexAlpha(M.gain, 0.1),
              border: "1px solid " + hexAlpha(M.gain, 0.25),
              color: M.gain,
            }}
          >
            {"✅ Got It"}
          </button>
        </div>
      )}
    </div>
  );
}

// ─── Stock Screener ───────────────────────────────────────────────────────────
export { DailyChallenge, TopicQuiz, FlashcardScreen };
