import { M } from './buildM';
import { hexAlpha } from './colorUtils';
// ─── UNIVERSAL GLASS STYLE SYSTEM ──────────────────────────────────
// ONE source of truth — the nav pill glass — applied to EVERY surface.
// All getters read M.* live so Monet colors are always current.
const ST = {
  // ═══ CORE GLASS RECIPE (Nav Pill reference) ═══════════════════════
  get glass() {
    return {
      background: hexAlpha(M.bg, 0.55),
      backdropFilter: "blur(36px) saturate(160%)",
      WebkitBackdropFilter: "blur(36px) saturate(160%)",
      border: "1px solid " + hexAlpha(M.txt, 0.08),
      boxShadow:
        "0 8px 32px " +
        hexAlpha(M.bg, 0.6) +
        ", " +
        "inset 0 1px 0 " +
        hexAlpha(M.txt, 0.1) +
        ", " +
        "inset 0 -1px 0 " +
        hexAlpha(M.bg, 0.3),
    };
  },

  // ═══ NAV PILL (exact reference) ═══════════════════════════════════
  get navPill() {
    return {
      background: hexAlpha(M.bg, 0.55),
      backdropFilter: "blur(36px) saturate(160%)",
      WebkitBackdropFilter: "blur(36px) saturate(160%)",
      border: "1px solid " + hexAlpha(M.txt, 0.08),
      boxShadow:
        "0 18px 50px " +
        hexAlpha(M.bg, 0.7) +
        ", " +
        "0 4px 16px " +
        hexAlpha(M.bg, 0.5) +
        ", " +
        "inset 0 1px 0 " +
        hexAlpha(M.txt, 0.1) +
        ", " +
        "inset 0 -1px 0 " +
        hexAlpha(M.bg, 0.35),
    };
  },

  // ═══ ACTIVE TAB CAPSULE ════════════════════════════════════════════
  get navTabActive() {
    return {
      background: hexAlpha(M.txt, 0.13),
      border: "1px solid " + hexAlpha(M.txt, 0.12),
      boxShadow:
        "inset 0 1px 0 " +
        hexAlpha(M.txt, 0.18) +
        ", inset 0 -1px 0 " +
        hexAlpha(M.bg, 0.2),
    };
  },

  // ═══ PANELS & SHEETS (stronger bg for readability) ════════════════
  get sheet() {
    return {
      background: hexAlpha(M.bg, 0.82),
      backdropFilter: "blur(36px) saturate(160%)",
      WebkitBackdropFilter: "blur(36px) saturate(160%)",
      border: "1px solid " + hexAlpha(M.txt, 0.08),
      boxShadow:
        "0 18px 50px " +
        hexAlpha(M.bg, 0.7) +
        ", " +
        "0 4px 16px " +
        hexAlpha(M.bg, 0.5) +
        ", " +
        "inset 0 1px 0 " +
        hexAlpha(M.txt, 0.1) +
        ", " +
        "inset 0 -1px 0 " +
        hexAlpha(M.bg, 0.35),
    };
  },

  // ═══ CARDS & SURFACES ══════════════════════════════════════════════
  get card() {
    return {
      background: hexAlpha(M.bg, 0.55),
      backdropFilter: "blur(36px) saturate(160%)",
      WebkitBackdropFilter: "blur(36px) saturate(160%)",
      border: "1px solid " + hexAlpha(M.txt, 0.08),
      borderRadius: M.r20,
      boxShadow:
        "0 4px 24px " +
        hexAlpha(M.bg, 0.4) +
        ", " +
        "inset 0 1px 0 " +
        hexAlpha(M.txt, 0.1),
    };
  },

  // ═══ BUTTONS — nav pill derived ═══════════════════════════════════
  get btnFilled() {
    return {
      background: hexAlpha(M.pri, 0.9),
      backdropFilter: "blur(36px) saturate(160%)",
      WebkitBackdropFilter: "blur(36px) saturate(160%)",
      border: "1px solid " + hexAlpha(M.txt, 0.12),
      borderRadius: M.rFull,
      boxShadow:
        "0 4px 20px " +
        hexAlpha(M.pri, 0.45) +
        ", " +
        "inset 0 1px 0 " +
        hexAlpha(M.txt, 0.22),
      color: M.onPri,
      fontWeight: 800,
      fontSize: 15,
      cursor: "pointer",
      fontFamily: "inherit",
      padding: "14px 28px",
      display: "flex",
      alignItems: "center",
      justifyContent: "center",
      gap: 8,
    };
  },
  get btnTonal() {
    return {
      background: hexAlpha(M.txt, 0.08),
      backdropFilter: "blur(36px) saturate(160%)",
      WebkitBackdropFilter: "blur(36px) saturate(160%)",
      border: "1px solid " + hexAlpha(M.txt, 0.12),
      borderRadius: M.rFull,
      boxShadow: "inset 0 1px 0 " + hexAlpha(M.txt, 0.1),
      color: M.txt,
      fontWeight: 700,
      fontSize: 14,
      cursor: "pointer",
      fontFamily: "inherit",
      padding: "13px 24px",
      display: "flex",
      alignItems: "center",
      justifyContent: "center",
      gap: 8,
    };
  },
  get btnOutline() {
    return {
      background: "transparent",
      backdropFilter: "blur(36px) saturate(160%)",
      WebkitBackdropFilter: "blur(36px) saturate(160%)",
      border: "1px solid " + hexAlpha(M.txt, 0.2),
      borderRadius: M.rFull,
      boxShadow: "inset 0 1px 0 " + hexAlpha(M.txt, 0.06),
      color: M.txt,
      fontWeight: 600,
      fontSize: 14,
      cursor: "pointer",
      fontFamily: "inherit",
      padding: "12px 22px",
      display: "flex",
      alignItems: "center",
      justifyContent: "center",
      gap: 8,
    };
  },

  // ═══ ICON BUTTON ══════════════════════════════════════════════════
  get iconBtn() {
    return {
      width: 34,
      height: 34,
      borderRadius: "50%",
      background: hexAlpha(M.txt, 0.08),
      backdropFilter: "blur(36px) saturate(160%)",
      WebkitBackdropFilter: "blur(36px) saturate(160%)",
      border: "1px solid " + hexAlpha(M.txt, 0.12),
      boxShadow: "inset 0 1px 0 " + hexAlpha(M.txt, 0.12),
      color: hexAlpha(M.txt, 0.75),
      cursor: "pointer",
      fontSize: 14,
      display: "flex",
      alignItems: "center",
      justifyContent: "center",
    };
  },

  // ═══ CHIPS / PILLS / BADGES ═══════════════════════════════════════
  get chip() {
    return {
      background: hexAlpha(M.txt, 0.08),
      backdropFilter: "blur(36px) saturate(160%)",
      WebkitBackdropFilter: "blur(36px) saturate(160%)",
      border: "1px solid " + hexAlpha(M.txt, 0.12),
      borderRadius: M.rFull,
      boxShadow: "inset 0 1px 0 " + hexAlpha(M.txt, 0.1),
    };
  },

  // ═══ INPUT FIELDS ═════════════════════════════════════════════════
  get input() {
    return {
      background: hexAlpha(M.txt, 0.05),
      backdropFilter: "blur(36px) saturate(160%)",
      WebkitBackdropFilter: "blur(36px) saturate(160%)",
      border: "1px solid " + hexAlpha(M.txt, 0.1),
      borderRadius: M.r16,
      boxShadow: "inset 0 1px 0 " + hexAlpha(M.txt, 0.06),
      color: M.txt,
      fontSize: 14,
      fontFamily: "inherit",
    };
  },

  // ═══ TOP BAR ══════════════════════════════════════════════════════
  get topBar() {
    return {
      background: hexAlpha(M.bg, 0.55),
      backdropFilter: "blur(48px) saturate(180%)",
      WebkitBackdropFilter: "blur(48px) saturate(180%)",
      borderBottom: "1px solid " + hexAlpha(M.txt, 0.1),
      boxShadow:
        "0 8px 32px " +
        hexAlpha(M.bg, 0.55) +
        ", " +
        "0 2px 8px " +
        hexAlpha(M.bg, 0.3) +
        ", " +
        "inset 0 -1px 0 " +
        hexAlpha(M.txt, 0.08),
    };
  },
  get topBarScrolled() {
    return {
      background: hexAlpha(M.bg, 0.72),
      backdropFilter: "blur(48px) saturate(200%)",
      WebkitBackdropFilter: "blur(48px) saturate(200%)",
      borderBottom: "1px solid " + hexAlpha(M.pri, 0.22),
      boxShadow:
        "0 8px 36px " +
        hexAlpha(M.bg, 0.65) +
        ", " +
        "0 2px 8px " +
        hexAlpha(M.bg, 0.35) +
        ", " +
        "inset 0 -1px 0 " +
        hexAlpha(M.pri, 0.12),
    };
  },

  // ═══ TICKER BAR ═══════════════════════════════════════════════════
  get tickerBar() {
    return {
      background: hexAlpha(M.bg, 0.65),
      backdropFilter: "blur(36px) saturate(160%)",
      WebkitBackdropFilter: "blur(36px) saturate(160%)",
      borderTop: "1px solid " + hexAlpha(M.txt, 0.06),
      borderBottom: "1px solid " + hexAlpha(M.txt, 0.06),
      boxShadow: "inset 0 1px 0 " + hexAlpha(M.txt, 0.05),
    };
  },

  // ═══ SCRIM / MODAL BACKDROP ═══════════════════════════════════════
  get scrim() {
    return {
      position: "fixed",
      inset: 0,
      background: hexAlpha(M.bg, 0.55),
      backdropFilter: "blur(10px)",
      WebkitBackdropFilter: "blur(10px)",
      zIndex: 200,
      animation: "fadeIn .2s ease",
    };
  },

  // ═══ DRAG HANDLE ══════════════════════════════════════════════════
  get dragHandle() {
    return {
      width: 38,
      height: 4,
      borderRadius: M.rFull,
      background: hexAlpha(M.txt, 0.2),
      boxShadow: "inset 0 1px 0 " + hexAlpha(M.txt, 0.1),
    };
  },

  // ═══ GLITCH: old aliases kept for compatibility ═══════════════════
  get navGlass() {
    return this.navPill;
  },
  get glassChip() {
    return this.chip;
  },

  // ═══ SUB-NAVIGATION TABS (Markets & Learn) ════════════════════════
  subTabBtn(active) {
    return {
      flex: 1,
      background: active ? hexAlpha(M.txt, 0.1) : hexAlpha(M.txt, 0.05),
      backdropFilter: "blur(16px)",
      WebkitBackdropFilter: "blur(16px)",
      color: active ? hexAlpha(M.txt, 0.9) : hexAlpha(M.txt, 0.4),
      border: active
        ? "1px solid " + hexAlpha(M.txt, 0.18)
        : "1px solid " + hexAlpha(M.txt, 0.08),
      borderRadius: M.r20,
      padding: "12px 0",
      fontSize: 14,
      fontWeight: 700,
      cursor: "pointer",
      fontFamily: "inherit",
      display: "flex",
      alignItems: "center",
      justifyContent: "center",
      gap: 7,
      boxShadow: active ? "inset 0 1px 0 " + hexAlpha(M.txt, 0.15) : "none",
      transition: "all .2s",
    };
  },

  // ═══ TYPOGRAPHY ═══════════════════════════════════════════════════
  get label() {
    return {
      fontSize: 11,
      color: M.pri,
      fontWeight: 700,
      textTransform: "uppercase",
      letterSpacing: 1,
    };
  },
  get body() {
    return { fontSize: 14, color: M.txt, lineHeight: 1.75 };
  },
  get bodyMid() {
    return { fontSize: 13, color: M.txtMid, lineHeight: 1.65 };
  },
  get caption() {
    return { fontSize: 12, color: M.txtDim };
  },
  get col16() {
    return { display: "flex", flexDirection: "column", gap: 16 };
  },
  get col12() {
    return { display: "flex", flexDirection: "column", gap: 12 };
  },
  get row() {
    return { display: "flex", alignItems: "center" };
  },
};
export { ST };
