import { useState, useRef, useEffect } from 'react';
import { M, mc } from '../theme/buildM';
import { ST } from '../theme/styles';
import { hexAlpha } from '../theme/colorUtils';
import { ls } from '../utils/storage';
import { useApp } from '../context/AppContext';
import { useSettings } from '../context/SettingsContext';
import { Card, FilledBtn, TonalBtn, Input, Skel } from '../components/ui';
import { ErrorCard, NoAIBanner } from '../components/ui';
import ObolLogo from '../components/ui/ObolLogo';
import { getRisk } from '../data/quiz';
import { INVEST_GOALS } from '../data/levels';

// ─── Terms Gate — shown on first launch ──────────────────────────
export const POLICY_VERSION = "2025-01-01"; // bump to force re-acceptance

function WelcomeJourney({ onComplete, startAtRisk = false }) {
  // Steps: 0-2: Legal | 3: Intro | 4: Name | 5-9: Risk Quiz | 10: Result | 11: Experience
  const [step, setStep] = useState(startAtRisk ? 5 : 0);
  const [name, setName] = useState(() => ls.get("siq_name", ""));
  const [quizScores, setQuizScores] = useState({});
  const [experience, setExperience] = useState(null);
  const [agreements, setAgreements] = useState({
    terms: false,
    privacy: false,
    disclaimer: false,
  });

  // RESTORED: Track which policies have been scrolled to the bottom
  const [unlocked, setUnlocked] = useState({
    terms: false,
    privacy: false,
    disclaimer: false,
  });
  const scrollRef = useRef(null);

  const { w: winW } = useWindowSize();
  const isLarge = winW >= 600;

  const MERGED_GOALS = [
    {
      id: 1,
      s: 1,
      icon: "🛡️",
      label: "Protect Savings",
      desc: "Low-risk, capital preservation focus.",
    },
    {
      id: 2,
      s: 2,
      icon: "⚖️",
      label: "Slow & Steady",
      desc: "Conservative growth with low volatility.",
    },
    {
      id: 3,
      s: 3,
      icon: "🚀",
      label: "Strong Growth",
      desc: "Balanced aggressive growth strategy.",
    },
    {
      id: 4,
      s: 4,
      icon: "⚡",
      label: "Max Gains",
      desc: "High-conviction, aggressive market plays.",
    },
  ];

  const journeySteps = [
    { type: "policy", key: "terms", title: "Terms of Service", icon: "📋" },
    { type: "policy", key: "privacy", title: "Privacy Policy", icon: "🔒" },
    { type: "policy", key: "disclaimer", title: "Risk Disclaimer", icon: "⚠️" },
    {
      type: "onboarding",
      id: "intro",
      title: "Welcome to obol",
      desc: "Your AI-powered companion",
    },
    {
      type: "onboarding",
      id: "name",
      title: "Let's get started",
      desc: "What should we call you?",
    },
    {
      type: "quiz",
      id: "q0",
      title: "Risk Profile",
      sub: "Question 1 of 5",
      question: "How old are you?",
      opts: ["Under 25", "25–35", "36–50", "Over 50"],
      s: [4, 3, 2, 1],
    },
    {
      type: "quiz",
      id: "q1",
      title: "Risk Profile",
      sub: "Question 2 of 5",
      question: "Investment drops 30%. You:",
      opts: ["Sell now", "Worry but hold", "Stay calm", "Buy more"],
      s: [1, 2, 3, 4],
    },
    {
      type: "quiz",
      id: "q2",
      title: "Risk Profile",
      sub: "Question 3 of 5",
      question: "How long can you invest?",
      opts: ["< 1 year", "1–3 years", "3–10 years", "10+ years"],
      s: [1, 2, 3, 4],
    },
    {
      type: "quiz",
      id: "q3",
      title: "Risk Profile",
      sub: "Question 4 of 5",
      question: "What is your primary goal?",
      isGoal: true,
    },
    {
      type: "quiz",
      id: "q4",
      title: "Risk Profile",
      sub: "Question 5 of 5",
      question: "% of savings to invest?",
      opts: ["< 5%", "5–15%", "15–30%", "> 30%"],
      s: [1, 2, 3, 4],
    },
    {
      type: "result",
      title: "Profile Calculated",
      desc: "Here is your investor identity",
    },
    {
      type: "experience",
      title: "One last thing",
      desc: "How would you describe your knowledge?",
    },
  ];

  const cur = journeySteps[step];
  const currentSelection = quizScores[cur.id];

  const handleNext = () => {
    if (step < journeySteps.length - 1) {
      setStep(step + 1);
    } else {
      const totalScore = Object.values(quizScores).reduce((a, b) => a + b, 0);
      onComplete({ name, risk: getRisk(totalScore), advanced: experience });
    }
  };

  const handleBack = () => {
    if (step > (startAtRisk ? 5 : 0)) setStep(step - 1);
  };

  // --- RESTORED SMART SCROLL LOGIC ---
  useEffect(() => {
    if (cur.type === "policy" && scrollRef.current) {
      const el = scrollRef.current;
      el.scrollTop = 0; // Reset scroll on step change

      // If already unlocked, do nothing
      if (unlocked[cur.key]) return;

      // Allow DOM to paint, then check if content is short enough to auto-unlock
      const timer = setTimeout(() => {
        if (el.scrollHeight <= el.clientHeight + 80) {
          setUnlocked((p) => ({ ...p, [cur.key]: true }));
        }
      }, 150);

      return () => clearTimeout(timer);
    } else if (scrollRef.current) {
      scrollRef.current.scrollTop = 0;
    }
  }, [step, cur.key]);

  // Handle the actual scrolling event
  const handleScroll = (e) => {
    if (cur.type !== "policy" || unlocked[cur.key]) return;
    const el = e.currentTarget;
    // Generous 100px tolerance for mobile browser bounce
    const isAtBottom = el.scrollHeight - el.scrollTop - el.clientHeight < 100;
    if (isAtBottom) {
      setUnlocked((p) => ({ ...p, [cur.key]: true }));
    }
  };

  const renderMd = (text) =>
    (text || "").split("\n").map((line, i) => {
      if (line.startsWith("# "))
        return (
          <div
            key={i}
            style={{
              fontSize: 22,
              fontWeight: 900,
              color: M.txt,
              marginBottom: 12,
            }}
          >
            {line.slice(2)}
          </div>
        );
      if (line.startsWith("## "))
        return (
          <div
            key={i}
            style={{
              fontSize: 16,
              fontWeight: 800,
              color: M.pri,
              marginTop: 16,
              marginBottom: 8,
            }}
          >
            {line.slice(3)}
          </div>
        );
      return (
        <div key={i} style={{ ...ST.body, marginBottom: 10, opacity: 0.85 }}>
          {line}
        </div>
      );
    });

  return (
    <div
      style={{
        ...ST.scrim,
        background: hexAlpha(M.bg, 0.25),
        zIndex: 3000,
        display: "flex",
        flexDirection: "column",
        alignItems: "center",
        justifyContent: isLarge ? "center" : "flex-end",
      }}
    >
      <style>{`
        @keyframes resultReveal { 0% { transform: scale(0.5); opacity: 0; } 60% { transform: scale(1.1); } 100% { transform: scale(1); opacity: 1; } }
        @keyframes glowPulse { 0% { box-shadow: 0 0 10px rgba(167, 139, 250, 0.2); } 50% { box-shadow: 0 0 30px rgba(167, 139, 250, 0.5); } 100% { box-shadow: 0 0 10px rgba(167, 139, 250, 0.2); } }
      `}</style>

      <div
        style={{
          ...ST.sheet,
          width: isLarge ? "min(680px, 95vw)" : "100%",
          height: isLarge ? "85dvh" : "100dvh",
          borderRadius: isLarge ? M.r28 : 0,
          display: "flex",
          flexDirection: "column",
          overflow: "hidden",
          animation: isLarge
            ? "fadeIn .3s ease"
            : "sheetUp .4s cubic-bezier(0.34, 1.56, 0.64, 1)",
        }}
      >
        {/* Header */}
        <div style={{ padding: "24px 24px 12px", flexShrink: 0 }}>
          <div
            style={{
              display: "flex",
              alignItems: "center",
              justifyContent: "space-between",
              marginBottom: 20,
            }}
          >
            <button
              onClick={handleBack}
              style={{
                ...ST.iconBtn,
                opacity: step === (startAtRisk ? 5 : 0) ? 0 : 1,
                pointerEvents: step === (startAtRisk ? 5 : 0) ? "none" : "auto",
              }}
            >
              <span>←</span>
            </button>
            <div style={{ display: "flex", gap: 4, flex: 1, margin: "0 16px" }}>
              {journeySteps.map((_, i) => (
                <div
                  key={i}
                  style={{
                    height: 4,
                    flex: 1,
                    borderRadius: M.rFull,
                    background: i <= step ? M.pri : hexAlpha(M.txt, 0.1),
                  }}
                />
              ))}
            </div>
            <div style={{ width: 34 }} />
          </div>
          <div style={{ textAlign: "center" }}>
            <div style={{ fontSize: 22, fontWeight: 900, color: M.txt }}>
              {cur.title}
            </div>
            {cur.sub && (
              <div style={{ ...ST.label, marginTop: 4 }}>{cur.sub}</div>
            )}
            {cur.desc && (
              <div style={{ ...ST.bodyMid, marginTop: 4, padding: "0 20px" }}>
                {cur.desc}
              </div>
            )}
          </div>
        </div>

        {/* Content Area - Added onScroll handler */}
        <div
          ref={scrollRef}
          onScroll={handleScroll}
          style={{ flex: 1, overflowY: "auto", padding: "10px 24px 30px" }}
        >
          {cur.type === "policy" && renderMd(POLICY_FALLBACK[cur.key])}

          {cur.type === "onboarding" && (
            <div style={{ animation: "fadeIn .3s ease" }}>
              {cur.id === "intro" && (
                <div
                  style={{
                    display: "flex",
                    flexDirection: "column",
                    alignItems: "center",
                    gap: 24,
                    paddingTop: 40,
                  }}
                >
                  <ObolLogo size={120} />
                  <div
                    style={{ ...ST.body, textAlign: "center", maxWidth: 280 }}
                  >
                    Your AI-powered companion for mastering the stock market.
                  </div>
                </div>
              )}
              {cur.id === "name" && (
                <div style={ST.col16}>
                  <Input
                    label="What should we call you?"
                    value={name}
                    onChange={(e) => setName(e.target.value)}
                    placeholder="Your name"
                  />
                  <div
                    style={{
                      ...ST.card,
                      padding: 16,
                      border: `1px dashed ${hexAlpha(M.pri, 0.3)}`,
                      background: hexAlpha(M.pri, 0.05),
                    }}
                  >
                    <div style={ST.bodyMid}>
                      👋 <b>{name || "Friend"}</b>, obol uses this to
                      personalize insights.
                    </div>
                  </div>
                </div>
              )}
            </div>
          )}

          {cur.type === "quiz" && (
            <div style={ST.col12}>
              <div
                style={{
                  fontSize: 19,
                  fontWeight: 800,
                  color: M.txt,
                  marginBottom: 20,
                  textAlign: "center",
                  lineHeight: 1.4,
                }}
              >
                {cur.question}
              </div>
              {cur.isGoal
                ? MERGED_GOALS.map((g) => (
                    <button
                      key={g.id}
                      onClick={() =>
                        setQuizScores((p) => ({ ...p, [cur.id]: g.s }))
                      }
                      style={{
                        ...ST.card,
                        padding: "16px 20px",
                        display: "flex",
                        alignItems: "center",
                        justifyContent: "space-between",
                        background:
                          currentSelection === g.s
                            ? hexAlpha(M.pri, 0.12)
                            : hexAlpha(M.txt, 0.05),
                        borderColor:
                          currentSelection === g.s
                            ? hexAlpha(M.pri, 0.4)
                            : hexAlpha(M.txt, 0.1),
                        width: "100%",
                        textAlign: "left",
                      }}
                    >
                      <div
                        style={{
                          display: "flex",
                          alignItems: "center",
                          gap: 14,
                        }}
                      >
                        <span style={{ fontSize: 24 }}>{g.icon}</span>
                        <div>
                          <div
                            style={{
                              fontSize: 15,
                              fontWeight: 800,
                              color: currentSelection === g.s ? M.pri : M.txt,
                            }}
                          >
                            {g.label}
                          </div>
                          <div style={ST.caption}>{g.desc}</div>
                        </div>
                      </div>
                      <div
                        style={{
                          width: 44,
                          height: 24,
                          borderRadius: M.rFull,
                          background:
                            currentSelection === g.s
                              ? M.pri
                              : hexAlpha(M.txt, 0.1),
                          position: "relative",
                          border: "1px solid " + hexAlpha(M.txt, 0.1),
                        }}
                      >
                        <div
                          style={{
                            position: "absolute",
                            top: 2,
                            left: currentSelection === g.s ? 22 : 2,
                            width: 18,
                            height: 18,
                            borderRadius: "50%",
                            background: M.onPri,
                            transition: "all 0.2s",
                          }}
                        />
                      </div>
                    </button>
                  ))
                : cur.opts.map((opt, i) => (
                    <button
                      key={opt}
                      onClick={() =>
                        setQuizScores((p) => ({ ...p, [cur.id]: cur.s[i] }))
                      }
                      style={{
                        ...ST.card,
                        padding: "18px 20px",
                        textAlign: "left",
                        background:
                          currentSelection === cur.s[i]
                            ? hexAlpha(M.pri, 0.12)
                            : hexAlpha(M.txt, 0.05),
                        borderColor:
                          currentSelection === cur.s[i]
                            ? M.pri
                            : hexAlpha(M.txt, 0.1),
                        display: "flex",
                        alignItems: "center",
                        justifyContent: "space-between",
                        gap: 14,
                      }}
                    >
                      <div
                        style={{
                          display: "flex",
                          alignItems: "center",
                          gap: 14,
                        }}
                      >
                        <div
                          style={{
                            ...ST.card,
                            borderRadius: M.r8,
                            width: 32,
                            height: 32,
                            display: "flex",
                            alignItems: "center",
                            justifyContent: "center",
                            fontWeight: 900,
                            fontSize: 12,
                            background:
                              currentSelection === cur.s[i]
                                ? hexAlpha(M.pri, 0.2)
                                : hexAlpha(M.txt, 0.05),
                            color:
                              currentSelection === cur.s[i] ? M.pri : M.txtMid,
                          }}
                        >
                          {String.fromCharCode(65 + i)}
                        </div>
                        <span
                          style={{
                            fontWeight: 700,
                            fontSize: 15,
                            color:
                              currentSelection === cur.s[i] ? M.pri : M.txt,
                          }}
                        >
                          {opt}
                        </span>
                      </div>
                      <div
                        style={{
                          width: 44,
                          height: 24,
                          borderRadius: M.rFull,
                          background:
                            currentSelection === cur.s[i]
                              ? M.pri
                              : hexAlpha(M.txt, 0.1),
                          position: "relative",
                          border: "1px solid " + hexAlpha(M.txt, 0.1),
                        }}
                      >
                        <div
                          style={{
                            position: "absolute",
                            top: 2,
                            left: currentSelection === cur.s[i] ? 22 : 2,
                            width: 18,
                            height: 18,
                            borderRadius: "50%",
                            background: M.onPri,
                            transition: "all 0.2s",
                          }}
                        />
                      </div>
                    </button>
                  ))}
            </div>
          )}

          {cur.type === "result" &&
            (() => {
              const res = getRisk(
                Object.values(quizScores).reduce((a, b) => a + b, 0),
              );
              return (
                <div
                  style={{
                    display: "flex",
                    flexDirection: "column",
                    alignItems: "center",
                    gap: 24,
                    paddingTop: 40,
                    animation: "fadeIn .5s ease",
                  }}
                >
                  <div
                    style={{
                      width: 100,
                      height: 100,
                      borderRadius: "50%",
                      background: res.cont,
                      display: "flex",
                      alignItems: "center",
                      justifyContent: "center",
                      fontSize: 48,
                      border: `3px solid ${res.color}`,
                      animation:
                        "resultReveal 0.6s cubic-bezier(0.34, 1.56, 0.64, 1), glowPulse 2s infinite ease-in-out",
                      "--pri-rgb": hexToRgb(res.color).join(","),
                    }}
                  >
                    {res.emoji}
                  </div>
                  <div style={{ textAlign: "center" }}>
                    <div
                      style={{
                        fontSize: 28,
                        fontWeight: 900,
                        color: res.color,
                      }}
                    >
                      {res.label} Investor
                    </div>
                    <div
                      style={{
                        ...ST.body,
                        marginTop: 16,
                        maxWidth: 300,
                        fontSize: 16,
                        opacity: 0.9,
                      }}
                    >
                      {res.desc}
                    </div>
                  </div>
                </div>
              );
            })()}

          {cur.type === "experience" && (
            <div style={ST.col12}>
              {[
                {
                  val: false,
                  icon: "🌱",
                  label: "Beginner",
                  color: M.ter,
                  points: [
                    "Plain-English explanations, no jargon",
                    "Step-by-step guidance with real examples",
                    "Analogies that make complex ideas click",
                    "Perfect if you're just getting started",
                  ],
                },
                {
                  val: true,
                  icon: "🔬",
                  label: "Advanced",
                  color: M.gold,
                  points: [
                    "Technical analysis, ratios & formulas",
                    "Market mechanics and macro context",
                    "Data-dense breakdowns for experienced investors",
                    "Best if you already know the basics",
                  ],
                },
              ].map((opt) => (
                <button
                  key={opt.label}
                  onClick={() => setExperience(opt.val)}
                  style={{
                    ...ST.card,
                    padding: "20px",
                    textAlign: "left",
                    background:
                      experience === opt.val
                        ? hexAlpha(opt.color, 0.12)
                        : hexAlpha(M.txt, 0.05),
                    borderColor:
                      experience === opt.val ? opt.color : hexAlpha(M.txt, 0.1),
                    transition: "all .2s",
                  }}
                >
                  <div
                    style={{
                      display: "flex",
                      alignItems: "center",
                      justifyContent: "space-between",
                      marginBottom: 12,
                    }}
                  >
                    <div
                      style={{ display: "flex", alignItems: "center", gap: 12 }}
                    >
                      <span style={{ fontSize: 28 }}>{opt.icon}</span>
                      <div
                        style={{
                          fontSize: 18,
                          fontWeight: 900,
                          color: experience === opt.val ? opt.color : M.txt,
                        }}
                      >
                        {opt.label}
                      </div>
                    </div>
                    <div
                      style={{
                        width: 44,
                        height: 24,
                        borderRadius: M.rFull,
                        background:
                          experience === opt.val
                            ? opt.color
                            : hexAlpha(M.txt, 0.1),
                        position: "relative",
                        border: "1px solid " + hexAlpha(M.txt, 0.1),
                      }}
                    >
                      <div
                        style={{
                          position: "absolute",
                          top: 2,
                          left: experience === opt.val ? 22 : 2,
                          width: 18,
                          height: 18,
                          borderRadius: "50%",
                          background: M.onPri,
                          transition: "all 0.2s",
                        }}
                      />
                    </div>
                  </div>
                  <div
                    style={{
                      display: "flex",
                      flexDirection: "column",
                      gap: 6,
                      marginBottom: 12,
                    }}
                  >
                    {opt.points.map((pt, i) => (
                      <div
                        key={i}
                        style={{
                          display: "flex",
                          alignItems: "flex-start",
                          gap: 8,
                          fontSize: 13,
                          color: hexAlpha(M.txt, 0.72),
                          lineHeight: 1.45,
                        }}
                      >
                        <span style={{ color: opt.color, flexShrink: 0 }}>
                          •
                        </span>
                        {pt}
                      </div>
                    ))}
                  </div>
                  <div
                    style={{
                      fontSize: 11,
                      color: hexAlpha(opt.color, 0.7),
                      fontWeight: 700,
                    }}
                  >
                    Switch anytime via the header or ⚙️ Settings
                  </div>
                </button>
              ))}
            </div>
          )}
        </div>

        {/* Action Footer */}
        <div
          style={{
            padding: "20px 24px 40px",
            borderTop: `1px solid ${hexAlpha(M.txt, 0.1)}`,
            ...ST.col12,
            background: hexAlpha(M.bg, 0.5),
          }}
        >
          {cur.type === "policy" && (
            <button
              onClick={() =>
                unlocked[cur.key] &&
                setAgreements((p) => ({ ...p, [cur.key]: !p[cur.key] }))
              }
              style={{
                ...ST.card,
                padding: "16px 20px",
                display: "flex",
                alignItems: "center",
                justifyContent: "space-between",
                background: agreements[cur.key]
                  ? hexAlpha(M.pri, 0.12)
                  : hexAlpha(M.txt, 0.05),
                width: "100%",
                textAlign: "left",
                cursor: unlocked[cur.key] ? "pointer" : "not-allowed",
                opacity: unlocked[cur.key] ? 1 : 0.6,
              }}
            >
              <div>
                <div
                  style={{
                    fontSize: 15,
                    fontWeight: 800,
                    color: agreements[cur.key] ? M.pri : M.txt,
                  }}
                >
                  I agree to these terms
                </div>
                {!unlocked[cur.key] && (
                  <div
                    style={{
                      ...ST.label,
                      color: M.gold,
                      textTransform: "none",
                      letterSpacing: 0,
                      marginTop: 4,
                    }}
                  >
                    Scroll to the bottom to unlock ↓
                  </div>
                )}
              </div>
              <div
                style={{
                  width: 44,
                  height: 24,
                  borderRadius: M.rFull,
                  background: agreements[cur.key]
                    ? M.pri
                    : hexAlpha(M.txt, 0.1),
                  position: "relative",
                  border: "1px solid " + hexAlpha(M.txt, 0.1),
                }}
              >
                <div
                  style={{
                    position: "absolute",
                    top: 2,
                    left: agreements[cur.key] ? 22 : 2,
                    width: 18,
                    height: 18,
                    borderRadius: "50%",
                    background: M.onPri,
                    transition: "all 0.2s",
                  }}
                />
              </div>
            </button>
          )}

          <button
            onClick={handleNext}
            disabled={
              (cur.type === "policy" && !agreements[cur.key]) ||
              (cur.id === "name" && !name.trim()) ||
              (cur.type === "quiz" && !currentSelection) ||
              (cur.type === "experience" && experience === null)
            }
            style={{
              ...ST.btnFilled,
              width: "100%",
              opacity:
                (cur.type === "policy" && !agreements[cur.key]) ||
                (cur.id === "name" && !name.trim()) ||
                (cur.type === "quiz" && !currentSelection) ||
                (cur.type === "experience" && experience === null)
                  ? 0.5
                  : 1,
            }}
          >
            {step === journeySteps.length - 1 ? "Launch obol 🚀" : "Continue →"}
          </button>
        </div>
      </div>
    </div>
  );
}

// ─── Congrats Modal ───────────────────────────────────────────────────────────

export default WelcomeJourney;
