import { useState, useRef, useEffect } from 'react';
import { M, mc } from '../theme/buildM';
import { ST } from '../theme/styles';
import { hexAlpha } from '../theme/colorUtils';
import { ls } from '../utils/storage';
import { useApp } from '../context/AppContext';
import { useSettings } from '../context/SettingsContext';
import { Card, FilledBtn, TonalBtn, Input, Skel } from '../components/ui';
import { ErrorCard, NoAIBanner } from '../components/ui';
import ObolLogo from '../components/ui/ObolLogo';
import { callAI, hasAIConfigured } from '../api/ai';
import { QUIZ, getRisk } from '../data/quiz';
import CrossTabBar from '../components/CrossTabBar';
import StockScreener from './StockScreener';
import SentimentScreen from './SentimentScreen';
import SimulatorScreen from './SimulatorScreen';
import DailySnapshot from '../components/portfolio/DailySnapshot';
import ManualPortfolioEntry from '../components/portfolio/ManualPortfolioEntry';
import WhatIfAnalyzer from '../components/portfolio/WhatIfAnalyzer';
import PortfolioHealthScore from '../components/portfolio/PortfolioHealthScore';
import PaperTradingScreen from '../components/portfolio/PaperTradingScreen';
import InvestorJournal from '../components/portfolio/InvestorJournal';

function PortfolioScreen({ risk, advanced, onXpEarned }) {
  const settings = useSettings();
  const { navigate } = useApp();
  const [portfolio, setPortfolio] = useState(() => ls.get("siq_portfolio", []));
  const [review, setReview] = useState("");
  const [loadingReview, setLoadingReview] = useState(false);

  const save = (p) => {
    setPortfolio(p);
    ls.set("siq_portfolio", p);
  };
  const total = portfolio.reduce((s, p) => s + p.invested, 0);
  const PIE = [M.pri, M.ter, M.sec, M.gold, M.loss, M.pri, "M.sec"];

  const getReview = async () => {
    if (!portfolio.length) return;
    setLoadingReview(true);
    const holdings = portfolio
      .map((p) => `${p.symbol}: $${p.invested}`)
      .join(", ");
    const prompt = advanced
      ? `Analyse: ${holdings}. ${risk ? `Investor: ${risk.label}.` : ""} Comment on sector concentration, diversification, risk alignment, 2 improvements.`
      : `My portfolio: ${holdings}. ${risk ? `I'm ${risk.label}.` : ""} Simple English: diversified? Matches my profile? 2 easy tips.`;
    try {
      const resp = await callAI(
        [{ role: "user", content: prompt }],
        "You are a helpful portfolio advisor.",
        settings,
      );
      setReview(resp);
    } catch (e) {
      setReview(`⚠️ ${e.message}`);
    }
    setLoadingReview(false);
  };

  const [portSub, setPortSub] = useState("holdings");

  return (
    <div style={{ display: "flex", flexDirection: "column", gap: 16 }}>
      {/* ── Tabs Row ── */}
      <div
        style={{ display: "flex", gap: 8, overflowX: "auto", paddingBottom: 2 }}
      >
        {[
          ["holdings", "💼 Holdings"],
          ["paper", "📝 Paper Trade"],
          ["journal", "📓 Journal"],
          ["health", "🏥 Health"],
        ].map(([id, lbl]) => (
          <button
            key={id}
            onClick={() => setPortSub(id)}
            style={{
              ...ST.subTabBtn(portSub === id),
              whiteSpace: "nowrap",
              flexShrink: 0,
              padding: "12px 16px",
            }}
          >
            {lbl}
          </button>
        ))}
      </div>

      {/* ── Tab Content Rendering ── */}
      {portSub === "paper" && (
        <PaperTradingScreen onXpEarned={onXpEarned || (() => {})} />
      )}
      {portSub === "journal" && <InvestorJournal />}
      {portSub === "health" &&
        (portfolio.length < 2 ? (
          <Card style={{ padding: 36, textAlign: "center" }}>
            <div style={{ fontSize: 36, marginBottom: 10 }}>📊</div>
            <div
              style={{
                fontSize: 14,
                fontWeight: 700,
                color: M.txt,
                marginBottom: 6,
              }}
            >
              Add 2+ positions
            </div>
            <div style={{ fontSize: 12, color: hexAlpha(M.txt, 0.45) }}>
              Switch to Holdings tab and add positions first
            </div>
          </Card>
        ) : (
          <PortfolioHealthScore portfolio={portfolio} />
        ))}
      {portSub === "holdings" && (
        <>
          <div
            style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 12 }}
          >
            {[
              {
                label: "Total Invested",
                value: `$${total.toFixed(2)}`,
                color: M.txt,
              },
              { label: "Positions", value: portfolio.length, color: M.pri },
            ].map(({ label, value, color }) => (
              <Card key={label} style={{ padding: "18px 20px" }}>
                <div style={{ fontSize: 12, color: M.txtDim, marginBottom: 4 }}>
                  {label}
                </div>
                <div
                  style={{
                    fontFamily: "monospace",
                    fontSize: 22,
                    fontWeight: 900,
                    color,
                  }}
                >
                  {value}
                </div>
              </Card>
            ))}
          </div>
          {risk && (
            <Card
              style={{
                padding: 16,
                background: risk.cont,
                backdropFilter: "blur(36px) saturate(160%)",
                WebkitBackdropFilter: "blur(36px) saturate(160%)",
                boxShadow: "inset 0 1px 0 " + hexAlpha(M.txt, 0.08),
                border: "1px solid " + risk.color + "40",
              }}
            >
              <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
                <span style={{ fontSize: 22 }}>{risk.emoji}</span>
                <div>
                  <div
                    style={{ fontSize: 14, fontWeight: 700, color: risk.color }}
                  >
                    {risk.label} Investor
                  </div>
                  <div style={{ fontSize: 12, color: M.txtMid, marginTop: 2 }}>
                    {risk.desc}
                  </div>
                </div>
              </div>
            </Card>
          )}
          {portfolio.length === 0 ? (
            <Card style={{ padding: 56, textAlign: "center" }}>
              <div style={{ fontSize: 44, marginBottom: 14 }}>📭</div>
              <div
                style={{
                  fontSize: 17,
                  fontWeight: 700,
                  color: M.txt,
                  marginBottom: 6,
                }}
              >
                No positions yet
              </div>
              <div style={{ fontSize: 14, color: M.txtMid }}>
                Analyze a stock → tap "+ Add to Portfolio"
              </div>
            </Card>
          ) : (
            <>
              {/* Donut allocation chart */}
              <Card style={{ padding: 22 }}>
                <div
                  style={{
                    fontSize: 11,
                    color: M.txtDim,
                    fontWeight: 700,
                    textTransform: "uppercase",
                    letterSpacing: 1,
                    marginBottom: 16,
                  }}
                >
                  Allocation
                </div>
                <div style={{ display: "flex", alignItems: "center", gap: 20 }}>
                  <svg
                    width="100"
                    height="100"
                    viewBox="0 0 100 100"
                    style={{ flexShrink: 0 }}
                  >
                    {(() => {
                      let cur = -Math.PI / 2;
                      return portfolio.map((p, i) => {
                        const frac = p.invested / total,
                          angle = frac * Math.PI * 2;
                        const x1 = 50 + 42 * Math.cos(cur),
                          y1 = 50 + 42 * Math.sin(cur);
                        cur += angle;
                        const x2 = 50 + 42 * Math.cos(cur),
                          y2 = 50 + 42 * Math.sin(cur);
                        return (
                          <path
                            key={p.symbol}
                            d={`M50 50 L${x1} ${y1} A42 42 0 ${angle > Math.PI ? 1 : 0} 1 ${x2} ${y2}Z`}
                            fill={PIE[i % PIE.length]}
                            opacity=".9"
                          />
                        );
                      });
                    })()}
                    <circle cx="50" cy="50" r="22" fill={M.s2} />
                    <text
                      x="50"
                      y="47"
                      textAnchor="middle"
                      fill={M.txt}
                      fontSize="9"
                      fontWeight="900"
                      fontFamily="monospace"
                    >
                      {portfolio.length}
                    </text>
                    <text
                      x="50"
                      y="59"
                      textAnchor="middle"
                      fill={M.txtDim}
                      fontSize="7"
                    >
                      pos
                    </text>
                  </svg>
                  <div
                    style={{
                      flex: 1,
                      display: "flex",
                      flexDirection: "column",
                      gap: 7,
                    }}
                  >
                    {portfolio.map((p, i) => (
                      <div
                        key={p.symbol}
                        style={{
                          display: "flex",
                          alignItems: "center",
                          gap: 8,
                          fontSize: 13,
                        }}
                      >
                        <div
                          style={{
                            backdropFilter: "blur(36px) saturate(160%)",
                            WebkitBackdropFilter: "blur(36px) saturate(160%)",
                            boxShadow: "inset 0 1px 0 " + hexAlpha(M.txt, 0.1),
                            width: 8,
                            height: 8,
                            borderRadius: "50%",
                            background: PIE[i % PIE.length],
                            flexShrink: 0,
                          }}
                        />
                        <span
                          style={{
                            fontFamily: "monospace",
                            color: M.txt,
                            fontWeight: 700,
                            flex: 1,
                          }}
                        >
                          {p.symbol}
                        </span>
                        <span
                          style={{
                            color: M.gold,
                            fontWeight: 700,
                            fontFamily: "monospace",
                          }}
                        >
                          {((p.invested / total) * 100).toFixed(0)}%
                        </span>
                      </div>
                    ))}
                  </div>
                </div>
              </Card>

              {/* Holdings list — each has cross-tab actions */}
              {portfolio.map((p, i) => (
                <Card key={i} style={{ padding: 16 }}>
                  <div
                    style={{
                      display: "flex",
                      alignItems: "center",
                      gap: 12,
                      marginBottom: 12,
                    }}
                  >
                    <div
                      style={{
                        backdropFilter: "blur(36px) saturate(160%)",
                        WebkitBackdropFilter: "blur(36px) saturate(160%)",
                        boxShadow: "inset 0 1px 0 " + hexAlpha(M.txt, 0.1),
                        width: 10,
                        height: 10,
                        borderRadius: "50%",
                        background: PIE[i % PIE.length],
                        flexShrink: 0,
                      }}
                    />
                    <div style={{ flex: 1, minWidth: 0 }}>
                      <div
                        style={{
                          fontFamily: "monospace",
                          fontWeight: 800,
                          fontSize: 15,
                          color: M.txt,
                        }}
                      >
                        {p.symbol}
                      </div>
                      <div style={{ fontSize: 12, color: M.txtDim }}>
                        {p.shares} shares · avg ${p.price?.toFixed(2)}
                      </div>
                    </div>
                    <div style={{ textAlign: "right" }}>
                      <div
                        style={{
                          fontFamily: "monospace",
                          fontWeight: 700,
                          color: M.txt,
                        }}
                      >
                        ${p.invested.toFixed(2)}
                      </div>
                      <div
                        style={{
                          fontSize: 11,
                          color: M.gold,
                          fontFamily: "monospace",
                        }}
                      >
                        {((p.invested / total) * 100).toFixed(1)}%
                      </div>
                    </div>
                    <button
                      onClick={() =>
                        save(portfolio.filter((_, idx) => idx !== i))
                      }
                      style={{
                        ...ST.btnFilled,
                        width: 32,
                        height: 32,
                        borderRadius: "50%",
                        background: hexAlpha(M.txt, 0.07),
                        backdropFilter: "blur(36px) saturate(160%)",
                        WebkitBackdropFilter: "blur(36px) saturate(160%)",
                        boxShadow: "inset 0 1px 0 " + hexAlpha(M.txt, 0.08),
                        border: "1px solid " + hexAlpha(M.txt, 0.12),
                        color: M.txtMid,
                        cursor: "pointer",
                        fontSize: 13,
                        display: "flex",
                        alignItems: "center",
                        justifyContent: "center",
                        flexShrink: 0,
                      }}
                      onTouchStart={(e) => {
                        e.currentTarget.style.background = hexAlpha(
                          M.loss,
                          0.15,
                        );
                        e.currentTarget.style.color = M.err;
                      }}
                      onTouchEnd={(e) => {
                        e.currentTarget.style.background = hexAlpha(
                          M.txt,
                          0.07,
                        );
                        e.currentTarget.style.color = M.txtMid;
                      }}
                    >
                      ✕
                    </button>
                  </div>
                  {/* Per-holding cross-tab actions */}
                  <div style={{ display: "flex", gap: 7, flexWrap: "wrap" }}>
                    {[
                      ["📊", "Analyze", "analyze"],
                      ["🔮", "Simulate", "simulator"],
                      ["🎯", "Sentiment", "sentiment"],
                      ["🤖", "Ask Advisor", "advisor"],
                    ].map(([icon, label, tab]) => (
                      <button
                        key={tab}
                        onClick={() => navigate(tab, p.symbol)}
                        style={{
                          ...ST.chip,
                          padding: "4px 10px",
                          display: "flex",
                          alignItems: "center",
                          gap: 4,
                        }}
                      >
                        {icon} {label}
                      </button>
                    ))}
                  </div>
                </Card>
              ))}

              <TonalBtn
                label={loadingReview ? "Analysing…" : "🤖 AI Portfolio Review"}
                onClick={getReview}
                disabled={loadingReview}
                full
              />
              {loadingReview && (
                <Card style={{ padding: 20 }}>
                  <Skel lines={4} />
                </Card>
              )}
              {review && !loadingReview && (
                <Card
                  style={{
                    padding: 20,
                    border: "1px solid " + hexAlpha(M.pri, 0.19),
                  }}
                >
                  <div
                    style={{
                      fontSize: 11,
                      color: M.pri,
                      fontWeight: 700,
                      marginBottom: 10,
                    }}
                  >
                    🤖 AI REVIEW
                  </div>
                  <div
                    style={{
                      fontSize: 14,
                      color: M.txt,
                      lineHeight: 1.75,
                      whiteSpace: "pre-wrap",
                    }}
                  >
                    {review}
                  </div>
                </Card>
              )}

              {/* Advanced: manual stock entry directly in portfolio */}
              {advanced && (
                <ManualPortfolioEntry
                  onAdd={(entry) => save([...portfolio, entry])}
                />
              )}
            </>
          )}
        </>
      )}
    </div>
  );
}

// ─── Settings Screen ──────────────────────────────────────────────

export default PortfolioScreen;
