// Live prices — try multiple CORS proxies for reliability
async function fetchLivePrice(sym) {
  const url = `https://query1.finance.yahoo.com/v8/finance/chart/${encodeURIComponent(sym)}?interval=1d&range=1d`;
  const proxies = [
    `https://corsproxy.io/?${encodeURIComponent(url)}`,
    `https://api.allorigins.win/get?url=${encodeURIComponent(url)}`,
  ];
  for (const proxy of proxies) {
    try {
      const ctrl2 = new AbortController();
      const t2 = setTimeout(() => ctrl2.abort(), 6000);
      const r = await fetch(proxy, { signal: ctrl2.signal });
      clearTimeout(t2);
      if (!r.ok) continue;
      const raw = await r.json();
      // allorigins wraps in .contents; corsproxy.io returns direct
      const d =
        typeof raw.contents === "string" ? JSON.parse(raw.contents) : raw;
      const meta = d?.chart?.result?.[0]?.meta;
      if (!meta) continue;
      const prev =
        meta.chartPreviousClose ||
        meta.previousClose ||
        meta.regularMarketPreviousClose;
      const price = meta.regularMarketPrice ?? meta.price;
      if (!price) continue;
      const changeP = prev && price ? ((price - prev) / prev) * 100 : 0;
      return { sym, price, changeP };
    } catch {
      continue;
    }
  }
  return null;
}

